let wirdState; try { wirdState = JSON.parse(safeGetItem('niyyah_wird_' + (todayKey()))); } catch(e) { if (typeof Sentry !== 'undefined') Sentry.captureException(new Error('Parse error: niyyah_wird_today')); } wirdState = wirdState || {};
const ITEM_WEIGHTS = {
  fajr: 3, dhuhr: 3, asr: 3, maghrib: 3, isha: 3, jumua: 3,
  wird_matin: 2, wird_soir: 2,
  ayat_kursi: 2,
  sunnah_fajr: 2, witr: 2, tahajjud: 2,
  istighfar: 2, tasbih: 2,
  silaturahm: 2,
  doua1: 2, doua2: 2, doua_soi: 2, doua_morts: 2, doua_oumma: 2, ziyara: 2, pardon: 2,
  fri_kahf: 2, fri_salawat: 2, fri_doua: 2,
};
function getWeight(id) { return ITEM_WEIGHTS[id] || 1; }
function isItemDone(item, s) {
  if (item.type === 'wird') {
    const session = WIRD_DATA[item.session];
    return session && session.items.every(wi => !!wirdState[wi.id]);
  }
  return item.type === 'counter' ? (s[item.id]||0) >= item.target : !!s[item.id];
}
function getWeightedScore(items, s) {
  const totalPts = items.reduce((sum, i) => sum + getWeight(i.id), 0);
  const donePts  = items.filter(i => isItemDone(i, s)).reduce((sum, i) => sum + getWeight(i.id), 0);
  return totalPts > 0 ? (donePts / totalPts) * 100 : 0;
}
function openScoreInfo() {
  var overlay = document.createElement('div');
  overlay.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;z-index:9999;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;padding:24px;';
  overlay.onclick = function(e) { if (e.target === overlay) overlay.remove(); };
  overlay.innerHTML = '<div style="background:#2C2E32;border:1px solid rgba(200,168,74,0.2);border-radius:16px;padding:24px;max-width:320px;width:100%;text-align:center;">'
    + '<div style="font-family:\'Cormorant Garamond\',serif;font-size:18px;font-weight:700;color:#C8A84A;margin-bottom:12px;">Score du jour</div>'
    + '<div style="font-size:13px;color:rgba(255,255,255,0.7);line-height:1.7;text-align:left;margin-bottom:16px;">'
    + 'Le score est pond\u00e9r\u00e9 par importance spirituelle :<br><br>'
    + '<span style="color:#C8A84A;">\u2022</span> Pri\u00e8res fard (5 salawat) \u2014 <b>\u00d73</b><br>'
    + '<span style="color:#C8A84A;">\u2022</span> Wirds, sunnahs, dou\u2019as \u2014 <b>\u00d72</b><br>'
    + '<span style="color:#C8A84A;">\u2022</span> Autres actes (science, bienfaisance) \u2014 <b>\u00d71</b><br><br>'
    + 'Le score va de 0 \u00e0 <b>100%</b>. Ta journ\u00e9e est valid\u00e9e bien avant le sommet \u2014 chaque pas vaut.</div>'
    + '<button onclick="this.closest(\'div[style]\').parentNode.remove()" style="padding:8px 20px;border-radius:10px;border:1px solid rgba(200,168,74,0.3);background:transparent;color:#C8A84A;font-size:13px;cursor:pointer;">Compris</button>'
    + '</div>';
  document.body.appendChild(overlay);
}
window.openScoreInfo = openScoreInfo;
function saveWirdState() {
  safeSetItem('niyyah_wird_' + (todayKey()), JSON.stringify(wirdState));
}
function toggleWirdItem(id, event) {
  if (event && event.target && (
    event.target.classList.contains('btn-wird-audio') ||
    event.target.classList.contains('btn-wird-info') ||
    event.target.closest('.btn-wird-audio') ||
    event.target.closest('.btn-wird-info')
  )) return;
  wirdState[id] = !wirdState[id];
  saveWirdState();
  if (wirdState[id]) {
    if (typeof playCheckSound === 'function') playCheckSound();
    if (navigator.vibrate) navigator.vibrate([12, 8, 25]);
  }
  renderWird();
  // Sync: update Smart Card in checklist if visible
  if (typeof renderLevel === 'function' && typeof currentLevel !== 'undefined') {
    setTimeout(() => renderLevel(currentLevel), 60);
  }
  // Check if a full session just completed
  if (wirdState[id]) {
    ['matin','soir'].forEach(function(ses) {
      var s = WIRD_DATA[ses];
      if (!s || !s.items) return;
      var allDone = s.items.every(function(i) { return !!wirdState[i.id]; });
      if (!allDone) return;
      var key = 'niyyah_wird_done_' + ses + '_' + todayKey();
      if (safeGetItem(key)) return;
      safeSetItem(key, '1');
      showWirdCompleteOverlay();
    });
  }
}
function showWirdCompleteOverlay() {
  var ov = document.createElement('div');
  ov.className = 'wird-complete-overlay';
  ov.innerHTML = '<div class="wird-complete-card">'
    + '<div class="wird-complete-star">\u2726</div>'
    + '<div class="wird-complete-arabic">\u0627\u0644\u0644\u0651\u064E\u0647\u064F\u0645\u0651\u064E \u062A\u064E\u0642\u064E\u0628\u0651\u064E\u0644\u0652</div>'
    + '<div class="wird-complete-label">All\u00e2humma taqabbal</div>'
    + '<button class="wird-complete-btn" onclick="this.closest(\'.wird-complete-overlay\').remove();v2GoTo(\'sanctuaire\');">Revenir au sanctuaire</button>'
    + '</div>';
  document.body.appendChild(ov);
}
window.showWirdCompleteOverlay = showWirdCompleteOverlay;
function renderWird() {
  const content = document.getElementById('wirdContent');
  if (!content) return;
  var _wirdArabicSession = {matin:'أَوْرَاد الصَّبَاح',soir:'أَوْرَاد الْمَسَاء'};
  let html = '<button class="wird-back-btn" onclick="wirdGoBack()" aria-label="Retour">\u2039</button>';
  if (!_currentWirdSession) { html += '<div class="section-header"><div class="section-arabic">\u0623\u064E\u0648\u0652\u0631\u0627\u062F</div><div class="section-name">' + t('wird_daily') + '</div><div class="section-line"></div></div>'; }
  var _sessions = _currentWirdSession ? [_currentWirdSession] : ['matin', 'soir'];
  var _wirdDup = { w_ayat_kursi:'ayat_kursi', w_ayat_kursi_s:'ayat_kursi', w_ikhlass_m:'muawwidhat', w_falaq_m:'muawwidhat', w_nas_m:'muawwidhat', w_ikhlass_s:'muawwidhat', w_falaq_s:'muawwidhat', w_nas_s:'muawwidhat', w_istighfar_m:'istighfar' };
  var _spState = (typeof safeParseJSON === 'function') ? safeParseJSON('spiritual_v2', {}) : {};
  var _wirdDupChanged = false;
  _sessions.forEach(function(_ses){ (WIRD_DATA[_ses].items||[]).forEach(function(_it){ var _k=_wirdDup[_it.id]; if(_k && _spState[_k] && !wirdState[_it.id]){ wirdState[_it.id]=true; _wirdDupChanged=true; } }); });
  if (_wirdDupChanged && typeof saveWirdState === 'function') saveWirdState();
  _sessions.forEach(session => {
    const s = WIRD_DATA[session];
    const done = s.items.filter(i => wirdState[i.id]).length;
    const pct = Math.round(done / s.items.length * 100);
    var _wTitle = session === 'matin' ? t('wird_matin') : t('wird_soir');
    html += `<div class="wird-session"><div class="section-header" style="padding:16px 4px 8px;"><div class="section-arabic" style="font-size:18px;">${_wirdArabicSession[session]}</div><div class="section-name">${_wTitle} · ${done}/${s.items.length}</div><div class="section-line"></div></div><div class="wird-session-bar"><div class="wird-session-bar-fill" style="width:${pct}%"></div></div>`;
    s.items.forEach(item => {
      const checked = !!wirdState[item.id];
      const dupNote = (_wirdDup[item.id] && _spState[_wirdDup[item.id]]) ? '<div class="wird-dup-note">\u2713 D\u00e9j\u00e0 fait apr\u00e8s ta pri\u00e8re \u00b7 une seule fois suffit</div>' : '';
      const audioData = item.audio ? JSON.stringify(item.audio) : null;
      const audioBtn = item.audio ? `<button class="btn-wird-audio" aria-label="Écouter" ontouchstart="event.stopPropagation()" onclick="playAudioFromBtn(this,event)" data-audio="${audioData ? audioData.replace(/"/g,'&quot;') : ''}" title="${t('btn_listen')}">🔊</button>` : '';
      const phonEsc = (item.phonetic||'').replace(/"/g,'&quot;');
      const arabEsc = (item.arabic||'').replace(/"/g,'&quot;');
      const srcEsc  = (item.source||'').replace(/"/g,'&quot;');
      const labelEsc = tI(item,'label').replace(/"/g,'&quot;');
      const infoBtn = `<button class="btn-wird-info" aria-label="Détails" onclick="event.stopPropagation();openInfoSheet('','','','',event)" data-label="${labelEsc}" data-arabic="${arabEsc}" data-phonetic="${phonEsc}" data-translation="${srcEsc}"><i>i</i></button>`;
      html += `<div class="wird-item${checked?' checked':''}" onclick="toggleWirdItem('${item.id}',event)"><div class="wird-check"><svg class="wird-check-svg" width="11" height="9" viewBox="0 0 12 10" fill="none"><path d="M1 5L4.5 8.5L11 1" stroke="#000" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"/></svg></div><div class="wird-body"><div class="wird-label">${tI(item,"label")}</div><div class="wird-sub">${tI(item,"sub")}</div><div class="wird-arabic">${item.arabic}</div>${dupNote}</div><div class="wird-actions">${audioBtn}${infoBtn}</div></div>`;
    });
    html += `<button class="wird-reset-btn" aria-label="${t('settings_reset')}" onclick="resetWirdSession('${session}')">${t('settings_reset')}</button></div>`;
  });
  content.innerHTML = html;
}
function resetWirdSession(session) {
  WIRD_DATA[session].items.forEach(i => { wirdState[i.id] = false; });
  saveWirdState();
  renderWird();
}

