    + '.bab-card:hover,.bab-card:active{transform:translateY(-5px) scale(1.012);box-shadow:inset 0 0 0 1px rgba(200,168,75,.4),0 0 44px rgba(var(--g),.55),0 14px 34px rgba(0,0,0,.7);}'
