    + '<button id="_niEnter" style="width:100%;max-width:300px;padding:16px;border:none;border-radius:14px;cursor:pointer;background:linear-gradient(165deg,#cdb15c 0%,#bd9c45 55%,#a8862f 100%);color:#2a1c0c;font-family:var(--serif);font-size:17px;font-weight:600;letter-spacing:0.18em;text-transform:uppercase;box-shadow:0 10px 26px rgba(168,134,47,0.30),inset 0 1px 0 rgba(255,255,255,0.4);">' + escapeHtml(cfg.enterLabel || 'Entrer') + '</button>'
