      var ids2 = ['qui','ou','quand','comment','pourquoi'];
      var n2 = {}; for (var i2 = 0; i2 < ids2.length; i2++) n2[ids2[i2]] = (document.getElementById('_cureJ2_' + ids2[i2]) || {}).value || '';
      notes = n2;
