// ── CURE ANXIÉTÉ ──────────────────────────────────────────────────────────────
function openCureAnxiete() {
  var cure = {}; try { cure = JSON.parse(safeGetItem('cure_anxiete') || '{}'); } catch(e) {}
  var day = cure.current_day || 1;
  if (cure.completed === true) day = 'complete';
  var today = new Date().toISOString().slice(0, 10);
  var lastDay = cure['jour' + (day - 1) + '_date'] ? cure['jour' + (day - 1) + '_date'].slice(0, 10) : null;
  _cureWizardState.porte = 'anxiete';
  if (lastDay === today && day !== 'complete' && day > 1) {
    _cureTransition(day - 1);
    return;
  }
  if (day === 'complete') {
    _babImmersion = true; _showAideBtn(); var nb2 = document.getElementById('nav-bar-v2'); if (nb2) nb2.classList.add('hidden-immersion');
    document.body.classList.add('in-bab-an-nafs');
    _cureCompletePremium('anxiete');
    return;
  }
  openCureJour('anxiete', typeof day === 'number' ? day : 1);
}
window.openCureAnxiete = openCureAnxiete;

var _curePorteConfig = {
  colere:  { color: '#B33A3A', dataKey: 'CURE_COLERE_CYCLE1',  storageKey: 'cure_colere',  imgDir: 'assets/cure-colere' },
  anxiete: { color: '#3F51B5', dataKey: 'CURE_ANXIETE_CYCLE1', storageKey: 'cure_anxiete', imgDir: 'assets/cure-anxiete' },
  regard:    { color: '#6B5B9A', dataKey: 'CURE_REGARD_CYCLE1',    storageKey: 'cure_regard',    imgDir: 'assets/cure-regard' },
  arrogance: { color: '#6A1B7A', dataKey: 'CURE_ARROGANCE_CYCLE1', storageKey: 'cure_arrogance', imgDir: 'assets/cure-arrogance' },
  paresse:   { color: '#6E6E6E', dataKey: 'CURE_PARESSE_CYCLE1',   storageKey: 'cure_paresse',   imgDir: 'assets/cure-paresse' },
  medisance: { color: '#8D6E63', dataKey: 'CURE_MEDISANCE_CYCLE1', storageKey: 'cure_medisance', imgDir: 'assets/cure-medisance' }
};
function _getCureData() {
  var porte = (_cureWizardState && _cureWizardState.porte) || 'anxiete';
  var cfg = _curePorteConfig[porte] || _curePorteConfig.anxiete;
  return window[cfg.dataKey] || null;
}
function _getCureColor() {
  var porte = (_cureWizardState && _cureWizardState.porte) || 'anxiete';
  return (_curePorteConfig[porte] || _curePorteConfig.anxiete).color;
}
function _getCureImgDir() {
  var porte = (_cureWizardState && _cureWizardState.porte) || 'anxiete';
  return (_curePorteConfig[porte] || _curePorteConfig.anxiete).imgDir;
}

function _cureAnxieteGenericDay(el, dayNum) {
  var _curPorte = (_cureWizardState && _cureWizardState.porte) || 'anxiete';
  var c = _getCureColor();
  var data = _getCureData();
  var j = data && data.jours && data.jours['j' + dayNum];
  if (!j) { el.innerHTML = '<div style="padding:60px 24px;text-align:center;color:rgba(255,255,255,0.4);">Contenu en cours de chargement\u2026</div>'; return; }
  var isLast = (dayNum === 7);

  // Build steps array (v2: 5 blocs)
  var steps = [];
  // Step 0: ouverture (image + station + titre)
  steps.push({ type: '_ouverture_anxiete', data: j, dayNum: dayNum });
  // Bloc 1: ouverture spirituelle (verset)
  if (j.bloc_1_ouverture_spirituelle) steps.push({ type: '_bloc_verset', data: j.bloc_1_ouverture_spirituelle });
  // Bloc 2: sagesse (parole de sage)
  if (j.bloc_2_sagesse) steps.push({ type: '_bloc_sagesse', data: j.bloc_2_sagesse });
  // Bloc 3: outils psy (identique à v1)
  var outils = j.bloc_3_outils_psy || j.outils || [];
  if (dayNum === 1) {
    var _vertus = { colere:'la longanimité', anxiete:'l\u2019apaisement', regard:'un regard plus juste', arrogance:'l\u2019humilité', paresse:'l\u2019élan vers le bien', medisance:'la maîtrise de ta langue' };
    var _v = _vertus[_curPorte] || 'cette vertu';
    var _skPacte = ((_curePorteConfig[_curPorte] || {}).storageKey || ('cure_' + _curPorte)) + '_j1_pacte';
    outils = [{
      type: 'champ_texte_long',
      amorce: 'Avant de commencer — pose ton intention.',
      introduction: 'Sept jours pour faire grandir ' + _v + '.\nEn une phrase : qu\u2019est-ce que tu veux cultiver ?',
      champ: { stockage: _skPacte, placeholder: 'Mon intention\u2026', max_caracteres: 200 }
    }].concat(outils);
  }
  outils.forEach(function(o, oi) { steps.push({ type: '_outil_anxiete', data: o, idx: oi, total: outils.length }); });
  // Bloc 4: dhikr quantifié
  if (j.bloc_4_dhikr_quantifie) steps.push({ type: '_bloc_dhikr', data: j.bloc_4_dhikr_quantifie });
  // Bloc 5: pratique corporelle
  if (j.bloc_5_pratique_corporelle) steps.push({ type: '_bloc_corporel', data: j.bloc_5_pratique_corporelle });
  // Clôture (phrase-ancre intégrée dans la finale)
  steps.push({ type: '_finale_anxiete', data: j, dayNum: dayNum });

  _cureWizardState = { dayNum: dayNum, step: 0, steps: steps, saved: {}, isLast: isLast, filRouge: '', c: c, porte: _curPorte };
  _cureAnxieteWizardRender(el);
}

function _dhkTap(k, t) {
  var n = (parseInt(safeGetItem(k) || '0', 10) || 0) + 1;
  if (n > t) n = t;
  safeSetItem(k, n);
  var el = document.getElementById('dhkNum'); if (el) el.textContent = n;
  if (navigator.vibrate) { try { navigator.vibrate(8); } catch (e) {} }
  if (n >= t) {
    var c = document.getElementById('dhkCircle'); if (c) c.style.borderColor = '#C8A84A';
    var d = document.getElementById('dhkDone'); if (d) d.style.display = 'block';
  }
}
function _dhkReset(k) {
  safeSetItem(k, 0);
  var el = document.getElementById('dhkNum'); if (el) el.textContent = '0';
  var c = document.getElementById('dhkCircle'); if (c) c.style.borderColor = 'rgba(200,168,75,0.33)';
  var d = document.getElementById('dhkDone'); if (d) d.style.display = 'none';
}
function _renderOutilAnxiete(o, c) {
  var renderer = _outilAnxieteRenderers[o.type];
  if (renderer) return renderer(o, c);
  return '<div style="border:1px solid ' + c + '33;border-radius:14px;padding:20px;margin-bottom:16px;text-align:center;">'
    + '<div style="font-size:15px;color:rgba(200,168,75,0.5);font-style:italic;">Outil \u00e0 venir \u2014 type\u00a0: ' + escapeHtml(o.type) + '</div></div>';
}
var _outilAnxieteRenderers = {};

// 3.1 — double_slider
_outilAnxieteRenderers.double_slider = function(o, c) {
  var sz = o.slider_zone || {};
  var si = o.slider_intensite || {};
  var options = sz.options || [];
  var skZ = sz.stockage || 'cure_anxiete_zone';
  var skI = si.stockage || 'cure_anxiete_intensite';
  var savedZ = safeGetItem(skZ) || '';
  var savedI = safeGetItem(skI) || '';
  var html = '';
  // Zone selector
  html += '<div style="margin-bottom:24px;">';
  html += '<div style="font-family:var(--serif);font-size:18px;color:rgba(200,168,75,0.8);margin-bottom:10px;text-align:center;">O\u00f9 la sens-tu\u00a0?</div>';
  html += '<div style="display:flex;flex-wrap:wrap;gap:8px;justify-content:center;">';
  options.forEach(function(opt) {
    var sel = savedZ === opt;
    html += '<button onclick="this.parentNode.querySelectorAll(\'button\').forEach(function(b){b.style.background=\'rgba(200,168,75,0.06)\';b.style.borderColor=\'rgba(200,168,75,0.2)\';b.style.color=\'rgba(240,234,214,0.6)\';});this.style.background=\'' + c + '22\';this.style.borderColor=\'' + c + '\';this.style.color=\'#C8A84A\';safeSetItem(\'' + skZ + '\',\'' + escapeHtml(opt) + '\')" style="padding:10px 16px;border-radius:10px;border:1px solid ' + (sel ? c : 'rgba(200,168,75,0.2)') + ';background:' + (sel ? c + '22' : 'rgba(200,168,75,0.06)') + ';color:' + (sel ? '#C8A84A' : 'rgba(240,234,214,0.6)') + ';font-family:var(--serif);font-size:16px;cursor:pointer;">' + escapeHtml(opt.charAt(0).toUpperCase() + opt.slice(1)) + '</button>';
  });
  html += '</div></div>';
  // Intensity slider
  html += '<div style="margin-bottom:16px;">';
  html += '<div style="font-family:var(--serif);font-size:18px;color:rgba(200,168,75,0.8);margin-bottom:10px;text-align:center;">Intensit\u00e9</div>';
  html += '<div style="display:flex;align-items:center;gap:10px;max-width:340px;margin:0 auto;">';
  html += '<div style="font-size:16px;color:rgba(200,168,75,0.65);font-style:italic;min-width:60px;text-align:right;">' + escapeHtml(si.label_min || '0') + '</div>';
  html += '<input type="range" min="' + (si.min || 0) + '" max="' + (si.max || 10) + '" value="' + (savedI || '5') + '" oninput="safeSetItem(\'' + skI + '\',this.value);this.nextElementSibling.textContent=this.value" style="flex:1;accent-color:#C8A84A;">';
  html += '<div style="font-size:18px;color:#C8A84A;font-family:var(--serif);font-weight:600;min-width:24px;text-align:center;">' + (savedI || '5') + '</div>';
  html += '<div style="font-size:16px;color:rgba(200,168,75,0.65);font-style:italic;min-width:60px;">' + escapeHtml(si.label_max || '10') + '</div>';
  html += '</div></div>';
  // Notes (psy + spi)
  if (o.note_spi) {
    html += '<div style="border-top:1px solid rgba(200,168,75,0.1);margin-top:16px;padding-top:12px;font-family:var(--serif);font-size:17px;font-style:italic;color:rgba(232,208,140,0.95);text-align:left;line-height:1.55;">' + escapeHtml(o.note_spi) + '</div>';
  }
  return html;
};

// 3.22 — ecran_final_sans_action
_outilAnxieteRenderers.ecran_final_sans_action = function(o, c) {
  var contenu = o.contenu || {};
  var duree = (o.duree_affichage_sec || 8) * 1000;
  var efId = '_ef_' + (o.id || 'final');
  var html = '<div id="' + efId + '" style="display:flex;flex-direction:column;align-items:center;justify-content:center;min-height:50vh;text-align:center;">';
  html += '<div id="' + efId + '_cal" style="opacity:0;transition:opacity 3s ease;">';
  html += '<div style="font-family:\'Scheherazade New\',serif;font-size:48px;color:#C8A84A;direction:rtl;margin-bottom:12px;">' + escapeHtml(contenu.ar_centre || '') + '</div>';
  if (contenu.translit) html += '<div style="font-family:var(--serif);font-size:16px;font-style:italic;color:rgba(200,168,75,0.5);margin-bottom:6px;">' + escapeHtml(contenu.translit) + '</div>';
  if (contenu.fr) html += '<div style="font-family:var(--serif);font-size:16px;color:rgba(200,168,75,0.6);">' + escapeHtml(contenu.fr) + '</div>';
  html += '</div></div>';
  // Fade in after render, then auto-advance after duration
  setTimeout(function() {
    var cal = document.getElementById(efId + '_cal');
    if (cal) cal.style.opacity = '1';
    setTimeout(function() {
      // Auto-advance to next wizard step (the finale/save step)
      if (_cureWizardState && _cureWizardState.step < _cureWizardState.steps.length - 1) {
        _cureWizardState.step++;
        _cureAnxieteWizardRender();
      }
    }, duree);
  }, 300);
  return html;
};

