  var inspSec = r.inspir_sec || 4;
  var expSec = r.expir_sec || 6;
  var cycleSec = inspSec + expSec;
  var duree = o.duree_visee_sec || 120;
  var sk = o.stockage || 'cure_anxiete_respiration';
  var breathId = '_breath_' + o.id;
