// ── COFFRET GÉNÉRIQUE (réutilisé par Anxiété + Colère) ────────────────────────
function _openCoffret(key, jsonFile, section) {
  var d = window['COFFRET_' + key.toUpperCase()];
  if (!d) { fetch(jsonFile).then(function(r){return r.ok?r.json():null}).then(function(data){if(data){window['COFFRET_'+key.toUpperCase()]=data;_openCoffret(key,jsonFile,section);}else{showToast('Coffret \u2014 chargement impossible');}}).catch(function(){showToast('Coffret \u2014 chargement impossible');}); return; }
  var ovId = 'coffret-' + key + '-overlay';
  var existing = document.getElementById(ovId);
  if (existing) existing.remove();
  var ov = document.createElement('div');
  ov.id = ovId;
  ov.style.cssText = 'position:fixed;inset:0;z-index:9999;background:#0A0908;display:flex;flex-direction:column;overflow:hidden;animation:fadeSlideV2 0.4s ease forwards;';
  var activeSection = section || (d.sections[0] && d.sections[0].id) || 'versets';
  ov.innerHTML = _coffretHtml(key, d, activeSection);
  document.body.appendChild(ov);
}
function _coffretHtml(key, d, activeId) {
  var ovId = 'coffret-' + key + '-overlay';
  var globalKey = 'COFFRET_' + key.toUpperCase();
  var closeBtn = '<button onclick="document.getElementById(\'' + ovId + '\').remove()" style="position:fixed;top:calc(var(--safe-top,0px)+12px);right:16px;z-index:10000;background:rgba(10,10,10,0.7);border:1px solid rgba(200,168,74,0.3);border-radius:50%;color:#C8A84A;cursor:pointer;padding:0;width:40px;height:40px;display:flex;align-items:center;justify-content:center;backdrop-filter:blur(8px);font-size:18px;">\u2715</button>';
  var html = closeBtn;
  html += '<div style="padding:calc(var(--safe-top,0px)+16px) 20px 0;text-align:center;">';
  html += '<div style="font-family:\'Scheherazade New\',serif;font-size:22px;color:#C8A84A;direction:rtl;margin-bottom:4px;">' + escapeHtml(d.titre_ar) + '</div>';
  html += '<div style="font-family:var(--serif);font-size:12px;letter-spacing:2px;color:rgba(200,168,75,0.5);margin-bottom:16px;">' + escapeHtml(d.titre_fr.toUpperCase()) + '</div>';
  html += '</div>';
  html += '<div style="display:flex;gap:0;border-bottom:1px solid rgba(200,168,75,0.15);padding:0 12px;overflow-x:auto;flex-shrink:0;">';
  d.sections.forEach(function(s) {
    var active = s.id === activeId;
    html += '<button onclick="document.getElementById(\'' + ovId + '\').innerHTML=_coffretHtml(\'' + key + '\',window.' + globalKey + ',\'' + s.id + '\')" style="flex-shrink:0;padding:10px 14px;border:none;background:none;font-family:var(--serif);font-size:13px;color:' + (active ? '#C8A84A' : 'rgba(240,234,214,0.4)') + ';cursor:pointer;border-bottom:2px solid ' + (active ? '#C8A84A' : 'transparent') + ';letter-spacing:0.5px;">' + escapeHtml(s.titre_fr) + '</button>';
  });
  html += '</div>';
  var sec = d.sections.find(function(s) { return s.id === activeId; });
  if (!sec) return html;
  html += '<div style="flex:1;overflow-y:auto;-webkit-overflow-scrolling:touch;padding:16px 20px 100px;">';
  if (sec.description) html += '<div style="font-family:var(--serif);font-size:15px;font-style:italic;color:rgba(200,168,75,0.5);margin-bottom:16px;line-height:1.5;">' + escapeHtml(sec.description) + '</div>';
  sec.entrees.forEach(function(e) {
    html += '<div style="border:1px solid rgba(200,168,75,0.12);border-radius:12px;padding:16px;margin-bottom:12px;background:rgba(200,168,75,0.03);">';
    if (e.image) html += '<img src="' + escapeHtml(e.image) + '" alt="' + escapeHtml(e.alt || '') + '" onclick="openImageOverlay(this.src)" style="width:100%;border-radius:10px;display:block;cursor:zoom-in;" loading="lazy">';
    if (e.ar) html += '<div style="font-family:\'Scheherazade New\',serif;font-size:23px;color:#C8A84A;direction:rtl;text-align:right;line-height:1.6;margin-bottom:8px;">' + escapeHtml(e.ar) + '</div>';
    if (e.translit) html += '<div style="font-family:var(--serif);font-size:15px;font-style:italic;color:rgba(200,168,75,0.55);margin-bottom:6px;">' + escapeHtml(e.translit) + '</div>';
    if (e.fr) html += '<div style="font-family:var(--serif);font-size:18px;color:rgba(240,234,214,0.85);line-height:1.6;margin-bottom:6px;">' + escapeHtml(e.fr) + '</div>';
    if (e.definition) html += '<div style="font-family:var(--serif);font-size:16px;color:rgba(240,234,214,0.75);line-height:1.6;margin-bottom:6px;">' + escapeHtml(e.definition) + '</div>';
    if (e.source) html += '<div style="font-size:13px;color:rgba(200,168,75,0.4);">\u2014 ' + escapeHtml(e.source) + '</div>';
    if (e.quand) html += '<div style="font-size:14px;color:rgba(240,234,214,0.5);font-style:italic;line-height:1.5;margin-top:6px;border-top:1px solid rgba(200,168,75,0.08);padding-top:6px;">' + escapeHtml(e.quand) + '</div>';
    if (e.nom) html += '<div style="font-family:var(--serif);font-size:18px;color:#C8A84A;margin-bottom:4px;">' + escapeHtml(e.nom) + (e.dates ? ' <span style="font-size:12px;color:rgba(200,168,75,0.5);">(' + escapeHtml(e.dates) + ')</span>' : '') + '</div>';
    if (e.oeuvre) html += '<div style="font-family:var(--serif);font-size:15px;font-style:italic;color:rgba(240,234,214,0.7);margin-bottom:4px;">' + escapeHtml(e.oeuvre) + '</div>';
    if (e.apport) html += '<div style="font-family:var(--serif);font-size:16px;color:rgba(240,234,214,0.75);line-height:1.6;">' + escapeHtml(e.apport) + '</div>';
    html += '</div>';
  });
  html += '</div>';
  return html;
}
window._coffretHtml = _coffretHtml;
function openImageOverlay(src){
  var ov=document.createElement('div');
  ov.id='img-overlay';
  ov.style.cssText='position:fixed;inset:0;z-index:10001;background:rgba(8,10,18,0.96);backdrop-filter:blur(6px);overflow:auto;-webkit-overflow-scrolling:touch;display:flex;align-items:flex-start;justify-content:center;padding:calc(var(--safe-top,0px)+56px) 12px 40px;box-sizing:border-box;';
  var img=document.createElement('img');
  img.src=src;
  img.style.cssText='max-width:100%;height:auto;border-radius:10px;cursor:zoom-in;';
  img.dataset.z='0';
  img.onclick=function(e){
    e.stopPropagation();
    if(img.dataset.z==='0'){img.style.maxWidth='none';img.style.width='200%';img.dataset.z='1';img.style.cursor='zoom-out';}
    else{img.style.maxWidth='100%';img.style.width='';img.dataset.z='0';img.style.cursor='zoom-in';}
  };
  ov.onclick=function(){ov.remove();};
  var close=document.createElement('button');
  close.textContent='\u2715';
  close.style.cssText='position:fixed;top:calc(var(--safe-top,0px)+12px);right:16px;z-index:10002;background:rgba(10,10,10,0.7);border:1px solid rgba(200,168,74,0.3);border-radius:50%;color:#C8A84A;width:40px;height:40px;font-size:18px;cursor:pointer;';
  close.onclick=function(e){e.stopPropagation();ov.remove();};
  ov.appendChild(img); ov.appendChild(close);
  document.body.appendChild(ov);
}
window.openImageOverlay=openImageOverlay;

/* ===== Overlay respiration guidée (réutilisable) ===== */
var NIYYAH_BREATH_PRESETS = {
  apaiser: {
    cycles: 6,
    phases: [
      { label: 'Inspire par le nez', sec: 2.5, scale: 1.4 },
      { label: 'Encore un peu', sec: 1.0, scale: 1.6 },
      { label: 'Expire lentement', sec: 6.0, scale: 1.0 }
    ],
    fin: 'La vague est passée.'
  },
  dormir: {
    cycles: 4,
    phases: [
      { label: 'Inspire (nez)', sec: 4, scale: 1.6 },
      { label: 'Retiens', sec: 7, scale: 1.6 },
      { label: 'Expire (bouche)', sec: 8, scale: 1.0 }
    ],
    fin: 'Laisse-toi aller.'
  }
};
var _niyyahBreathTimers = [];
function closeBreathOverlay() {
  _niyyahBreathTimers.forEach(function (t) { clearTimeout(t); });
  _niyyahBreathTimers = [];
  var ov = document.getElementById('niyyah-breath-overlay');
  if (ov && ov.parentNode) ov.parentNode.removeChild(ov);
}
function openBreathOverlay(presetKey) {
  var p = NIYYAH_BREATH_PRESETS[presetKey] || NIYYAH_BREATH_PRESETS.apaiser;
  closeBreathOverlay();
  var ov = document.createElement('div');
  ov.id = 'niyyah-breath-overlay';
  ov.className = 'niyyah-breath-overlay';
  ov.innerHTML =
    '<div class="niyyah-breath-inner">'
    + '<div id="niyyah-breath-label" class="niyyah-breath-label">Pr\u00eat ?</div>'
    + '<div class="niyyah-breath-wrap"><div id="niyyah-breath-circle" class="niyyah-breath-circle"></div></div>'
    + '<div id="niyyah-breath-count" class="niyyah-breath-count"></div>'
    + '<button id="niyyah-breath-end" class="niyyah-breath-btn">Terminer</button>'
    + '</div>';
  document.body.appendChild(ov);
  document.getElementById('niyyah-breath-end').onclick = closeBreathOverlay;
  var circle = document.getElementById('niyyah-breath-circle');
  var label = document.getElementById('niyyah-breath-label');
  var count = document.getElementById('niyyah-breath-count');
  var cyc = 0;
  function runCycle() {
    if (cyc >= p.cycles) {
      label.textContent = p.fin || 'Termin\u00e9.';
      count.textContent = '';
      circle.style.transitionDuration = '2s';
      circle.style.transform = 'scale(1)';
      var b = document.getElementById('niyyah-breath-end');
      if (b) b.textContent = 'Fermer';
      return;
    }
    cyc++;
    count.textContent = 'Cycle ' + cyc + ' / ' + p.cycles;
    var i = 0;
    function runPhase() {
      if (i >= p.phases.length) { runCycle(); return; }
      var ph = p.phases[i];
      label.textContent = ph.label;
      circle.style.transitionDuration = ph.sec + 's';
      circle.style.transform = 'scale(' + ph.scale + ')';
      i++;
      _niyyahBreathTimers.push(setTimeout(runPhase, ph.sec * 1000));
    }
    runPhase();
  }
  _niyyahBreathTimers.push(setTimeout(runCycle, 800));
}
window.openBreathOverlay = openBreathOverlay;
window.closeBreathOverlay = closeBreathOverlay;

