function obTypeWriter(elId, text, i) {
  var el = document.getElementById(elId);
  if (!el || i >= text.length) return;
  el.textContent = text.substring(0, i + 1);
  setTimeout(function() { obTypeWriter(elId, text, i + 1); }, 40);
}
function obSelectMotiv(el, value) {
  document.querySelectorAll('.ob-motiv-card').forEach(function(c) { c.classList.remove('selected'); });
  el.classList.add('selected');
  safeSetItem('niyyah_motivation', value);
  var btn = document.getElementById('obMotivBtn');
  if (btn) { btn.style.opacity = '1'; btn.style.pointerEvents = 'auto'; }
}
var _cavCtx=null,_cavMaster=null,_cavOscs=[],_cavLfo=null;
window._cavSound=false;
function cavSoundEnabled(){ return safeGetItem('niyyah_sound')!=='off'; }
function cavAudioStart(){
  try{
    _cavCtx=new (window.AudioContext||window.webkitAudioContext)();
    var t=_cavCtx.currentTime;
    _cavMaster=_cavCtx.createGain(); _cavMaster.gain.value=0.0001; _cavMaster.connect(_cavCtx.destination);
    var lp=_cavCtx.createBiquadFilter(); lp.type='lowpass'; lp.frequency.value=820; lp.Q.value=0.6; lp.connect(_cavMaster);
    var fr=[110,164.81,220], ty=['sine','triangle','sine'], ga=[0.5,0.2,0.16];
    _cavOscs=fr.map(function(f,i){ var o=_cavCtx.createOscillator(); o.type=ty[i]; o.frequency.value=f; var g=_cavCtx.createGain(); g.gain.value=ga[i]; o.connect(g); g.connect(lp); o.start(); return o; });
    _cavLfo=_cavCtx.createOscillator(); _cavLfo.frequency.value=0.12; var lg=_cavCtx.createGain(); lg.gain.value=0.035; _cavLfo.connect(lg); lg.connect(_cavMaster.gain); _cavLfo.start();
    _cavMaster.gain.setValueAtTime(0.0001,t);
    _cavMaster.gain.linearRampToValueAtTime(0.14,t+3.5);
    window._cavSound=true;
  }catch(e){ window._cavSound=false; }
}
function cavChime(base,vol,dur){
  if(!_cavCtx||!_cavMaster) return;
  var t=_cavCtx.currentTime;
  [1,2.01,2.99].forEach(function(m,idx){
    var o=_cavCtx.createOscillator(); o.type='sine'; o.frequency.value=base*m;
    var g=_cavCtx.createGain();
    g.gain.setValueAtTime(0.0001,t);
    g.gain.linearRampToValueAtTime(vol/(idx+1.2),t+0.02);
    g.gain.exponentialRampToValueAtTime(0.0006,t+(idx===0?dur:dur*0.6));
    o.connect(g); g.connect(_cavMaster); o.start(t); o.stop(t+dur+0.3);
  });
}
function cavBloomSound(){
  if(!_cavCtx||!_cavMaster) return;
  var t=_cavCtx.currentTime;
  var sw=_cavCtx.createOscillator(); sw.type='sine';
  sw.frequency.setValueAtTime(220,t); sw.frequency.exponentialRampToValueAtTime(440,t+2);
  var swg=_cavCtx.createGain(); swg.gain.setValueAtTime(0.0001,t); swg.gain.linearRampToValueAtTime(0.13,t+1.3); swg.gain.exponentialRampToValueAtTime(0.0006,t+3.2);
  sw.connect(swg); swg.connect(_cavMaster); sw.start(t); sw.stop(t+3.4);
  _cavMaster.gain.cancelScheduledValues(t);
  _cavMaster.gain.setValueAtTime(_cavMaster.gain.value,t);
  _cavMaster.gain.linearRampToValueAtTime(0.0001,t+2.6);
  setTimeout(cavAudioStop,3600);
}
function cavAudioStop(){
  try{ _cavOscs.forEach(function(o){o.stop();}); if(_cavLfo)_cavLfo.stop(); if(_cavCtx)_cavCtx.close(); }catch(e){}
  _cavCtx=null;_cavMaster=null;_cavOscs=[];_cavLfo=null;window._cavSound=false;
}
function cavRenderSeuil(el, stage, enterFn){
  var snd = cavSoundEnabled();
  function paint(){
    stage.innerHTML =
      '<div style="margin-bottom:24px"><span class="onboard-logo-halo" style="display:inline-block;border-radius:50%"><img src="./imageslogo.webp" alt="Niyyah" style="width:128px;height:auto;display:block;border-radius:50%"></span></div>'
      + '<div style="font-family:\'Cormorant Garamond\',serif;font-style:italic;font-weight:300;font-size:22px;color:rgba(232,213,160,0.72);letter-spacing:0.04em">Touchez pour entrer</div>'
      + '<div style="margin-top:30px"><span id="cavMute" style="display:inline-flex;align-items:center;gap:7px;font-family:var(--sans);font-size:13px;color:rgba(200,168,75,0.6);border:0.5px solid rgba(200,168,75,0.3);border-radius:20px;padding:7px 16px;cursor:pointer">'
      + (snd?'\u266A Son activ\u00e9':'\u2715 Son coup\u00e9') + '</span></div>';
    stage.style.opacity='1';
    var mute=document.getElementById('cavMute');
    if(mute) mute.onclick=function(ev){ ev.stopPropagation(); snd=!snd; safeSetItem('niyyah_sound', snd?'on':'off'); paint(); };
  }
  paint();
  function enter(){
    el.removeEventListener('click', enter);
    if(snd) cavAudioStart();
    stage.style.opacity='0';
    setTimeout(enterFn, 360);
  }
  el.addEventListener('click', enter);
}
function renderCaverne() {
  var el = document.getElementById('onboard-caverne');
  if (!el) return;
  el.style.display = 'flex';
  var stage = document.getElementById('caverne-stage');
  var glow = document.getElementById('caverne-glow');
  var bloom = document.getElementById('caverne-bloom');
  if (!stage || !glow) return;
  stage.style.transition = 'opacity 0.45s ease';
  if (bloom) bloom.style.opacity = '0';
  glow.style.display = 'block';
  var beats = [
    {dur:5200,html:'<div class="cav-n">\u00c0 cinquante m\u00e8tres d\u2019ici,<br>une caverne.</div><div style="height:18px"></div><div class="cav-n"><span class="word">Or.</span> <span class="word">Perles.</span> <span class="word">Diamants.</span></div><div style="height:26px"></div><div class="cav-n" style="font-size:20px;color:rgba(232,213,160,0.85)">Sur la porte, trois mots :</div><div style="height:12px"></div><div class="cav-a">\u00ab Tout est \u00e0 toi. \u00bb</div>'},
    {dur:4400,html:'<div class="cav-n">Qui passerait son chemin ?</div><div style="height:30px"></div><div class="cav-m">Personne</div><div style="height:36px"></div><div class="cav-q">On y reviendrait chaque matin.<br>Chaque soir. Toute une vie.</div>'},
    {dur:5800,html:'<div class="cav-n">Or une autre caverne existe.</div><div style="height:16px"></div><div class="cav-n"><span class="word">Juste l\u00e0.</span> <span class="word">Devant toi.</span> <span class="word">Chaque jour.</span></div><div style="height:26px"></div><div class="cav-n" style="font-weight:500;color:#D9B45A">Invisible \u2014 et mille fois plus riche.</div><div style="height:22px"></div><div class="cav-a">Une caverne de hassan\u00e2t.</div>'},
    {dur:5400,html:'<div class="cav-n cav-t shimline">Un Bismillah sinc\u00e8re.</div><div style="height:16px"></div><div class="cav-n cav-t shimline">Un pardon offert.</div><div style="height:16px"></div><div class="cav-n cav-t shimline">Un silence patient. Un sourire.</div><div style="height:30px"></div><div class="cav-a" style="color:#E8D5A0">Des tr\u00e9sors qui ne rouillent jamais.</div>'},
    {dur:4400,html:'<div class="cav-n">Et devant celle-l\u00e0 ?</div><div style="height:26px"></div><div class="cav-n">Presque tous passent.</div><div style="height:16px"></div><div class="cav-a">Rares sont ceux qui s\u2019arr\u00eatent.</div>'},
    {dur:5000,html:'<div class="cav-n">L\u2019or, tu le laisseras derri\u00e8re toi.</div><div style="height:30px"></div><div class="cav-c">Cela, tu l\u2019emporteras.</div>'},
    {dur:3900,html:'<div class="cav-q" style="font-size:19px">La porte est ouverte.<br>Personne ne la garde.</div><div style="height:32px"></div><div class="cav-s">All\u00e2h est Celui qui donne.</div>'},
    {dur:5400,html:'<div class="cav-c" style="font-size:28px">Sois de ceux qui s\u2019arr\u00eatent.</div><div style="height:30px"></div><div class="cav-m">Entre</div><div style="height:34px"></div><div class="cav-q">Niyyah marche \u00e0 tes c\u00f4t\u00e9s.</div>'}
  ];
  var glows = [
    {w:220,h:150,o:0.20,c:'200,168,75',y:50},
    {w:245,h:165,o:0.26,c:'200,168,75',y:50},
    {w:385,h:285,o:0.50,c:'217,169,74',y:46},
    {w:405,h:300,o:0.55,c:'217,169,74',y:48},
    {w:375,h:280,o:0.50,c:'217,169,74',y:48},
    {w:435,h:320,o:0.62,c:'224,176,80',y:48},
    {w:475,h:350,o:0.70,c:'232,200,120',y:48},
    {w:530,h:400,o:0.80,c:'232,200,120',y:48}
  ];
  function setGlow(g) {
    glow.style.width = g.w + 'px';
    glow.style.height = g.h + 'px';
    glow.style.top = g.y + '%';
    glow.style.opacity = g.o;
    glow.style.background = 'radial-gradient(ellipse,rgba(255,244,210,0.26) 0%,rgba(' + g.c + ',0.5) 26%,rgba(' + g.c + ',0.12) 54%,transparent 78%)';
  }
  function twinkle(elx) {
    elx.style.textShadow = '0 0 22px rgba(232,210,150,0.9)';
    setTimeout(function() { elx.style.textShadow = '0 0 14px rgba(200,168,75,0.45)'; }, 520);
  }
  glow.style.transition = 'none';
  setGlow(glows[0]);
  requestAnimationFrame(function() {
    glow.style.transition = 'width 1.8s ease,height 1.8s ease,opacity 1.8s ease,top 1.8s ease,background 1.8s ease';
  });
  function showBeat(i) {
    if (i >= beats.length) { doBloom(); return; }
    stage.style.opacity = '0';
    setTimeout(function() {
      stage.innerHTML = beats[i].html;
      if (window._cavSound && i === 2) cavChime(880, 0.20, 3.2);
      if (window._cavSound && i === 3) cavChime(1174.66, 0.13, 2.6);
      setGlow(glows[i]);
      requestAnimationFrame(function() { requestAnimationFrame(function() {
        stage.style.opacity = '1';
        var words = stage.querySelectorAll('.word');
        words.forEach(function(w, k) { setTimeout(function() { w.style.opacity = '1'; }, 260 + k * 400); });
        var sh = stage.querySelectorAll('.shimline');
        sh.forEach(function(elx, k) { setTimeout(function() { twinkle(elx); }, 500 + k * 520); });
        setTimeout(function() { showBeat(i + 1); }, beats[i].dur);
      }); });
    }, 360);
  }
  function doBloom() {
    stage.style.opacity = '0';
    if (bloom) bloom.style.opacity = '1';
    glow.style.transition = 'width 1.6s ease,height 1.6s ease,opacity 1.6s ease,background 1.6s ease';
    glow.style.width = '1200px';
    glow.style.height = '1200px';
    glow.style.opacity = '1';
    if (window._cavSound) cavBloomSound();
    setTimeout(function() {
      el.style.transition = 'opacity 1200ms ease';
      el.style.opacity = '0';
      setTimeout(function() { onboardNext(); }, 1300);
    }, 1600);
  }
  cavRenderSeuil(el, stage, function(){ showBeat(0); });
}

function onboardRender() {
  if (_onboardStep === 0) {
    // Caverne slide
    var obs = document.getElementById('onboardScreen');
    if (obs) obs.style.display = 'none';
    renderCaverne();
    var btn = document.getElementById('caverne-continue');
    if (btn) btn.onclick = function() { onboardNext(); };
    return;
  }
  // Steps 1+ → ONBOARD_SLIDES[step - 1]
  var cav = document.getElementById('onboard-caverne');
  if (cav) cav.style.display = 'none';
  var obs = document.getElementById('onboardScreen');
  if (obs) obs.style.display = '';
  var slideIdx = _onboardStep - 1;
  requestAnimationFrame(function() {
    var content = document.getElementById('onboardContent');
    if (content && ONBOARD_SLIDES[slideIdx]) content.innerHTML = ONBOARD_SLIDES[slideIdx]();
    if (slideIdx === 3 && !isPremium() && safeGetItem('niyyah_plus_intro') !== '1') {
      safeSetItem('niyyah_plus_intro', '1');
      setTimeout(function(){ openFreemium(); }, 350);
    }
    if (content) content.querySelectorAll('.ob-rise').forEach(function(el,k){ el.style.animationDelay=(k*0.07)+'s'; });
    var _obScreen = document.getElementById('onboardScreen');
    if (_obScreen) _obScreen.scrollTop = 0;
    [0,1,2,3].forEach(function(i) {
      var dot = document.getElementById('dot' + i);
      if (dot) dot.className = 'onboard-dot' + (i === slideIdx ? ' active' : '');
    });
  });
}
function onboardNext() {
  if (_onboardStep < ONBOARD_SLIDES.length) {
    _onboardStep++;
    onboardRender();
  } else {
    onboardFinish();
  }
}
// onboardSaveCity supprimé (code mort — étape ville retirée)
// onboardRequestGeoloc supprimé (code mort — étape ville retirée)
function onboardFinish() {
  document.body.classList.remove('onboarding-active');
  safeSetItem('niyyah_onboard', '1');
  if (!safeGetItem('niyyah_install_date')) safeSetItem('niyyah_install_date', String(Date.now()));
  const screen = document.getElementById('onboardScreen');
  if (screen) {
    screen.style.opacity = '0';
    setTimeout(() => screen.classList.add('hidden'), 350);
  }
  // Charger horaires — géoloc silencieuse si pas encore faite
  var _onboardCoords = safeGetItem('niyyah_coords');
  if (_onboardCoords) {
    try { var _c = JSON.parse(_onboardCoords); _loadPrayerByCoords(_c.lat, _c.lng); } catch(e) {}
  } else if (_prayerCity) {
    _loadPrayerByCity();
  } else if (navigator.geolocation) {
    navigator.geolocation.getCurrentPosition(function(pos) {
      safeSetItem('niyyah_coords', JSON.stringify({ lat: pos.coords.latitude, lng: pos.coords.longitude }));
      if (typeof _loadPrayerByCoords === 'function') _loadPrayerByCoords(pos.coords.latitude, pos.coords.longitude);
    }, function() {}, { enableHighAccuracy: false, timeout: 10000, maximumAge: 300000 });
  }
  // Aller directement au Sanctuaire
  setTimeout(() => {
    showNiyyahScreen();
  }, 500);
}
function applyScrollScale() {
  const items = document.querySelectorAll('.items-group .item:not(.wird-inner-item)');
  if (!items.length) return;
  const centerY = window.innerHeight / 2;
  items.forEach(item => {
    const rect = item.getBoundingClientRect();
    if (rect.bottom < 0 || rect.top > window.innerHeight) return;
    const itemCenterY = rect.top + rect.height / 2;
    const distFromCenter = Math.abs(itemCenterY - centerY);
    const maxDist = window.innerHeight * 0.5;
    const ratio = Math.max(0, 1 - distFromCenter / maxDist);
    const scale = 0.93 + ratio * 0.07;
    const opacity = 0.55 + ratio * 0.45;
    item.style.setProperty('transform', `scale(${scale.toFixed(3)})`, 'important');
    item.style.setProperty('opacity', opacity.toFixed(3), 'important');
  });
}
let _scrollTicking = false;
function onScroll() {
  if (!_scrollTicking) {
    requestAnimationFrame(() => {
      applyScrollScale();
      _scrollTicking = false;
    });
    _scrollTicking = true;
  }
}
let currentTheme = 'dark';
function applyTheme(theme) {
  if (theme === 'light') {
    document.documentElement.setAttribute('data-theme', 'light');
  } else {
    document.documentElement.removeAttribute('data-theme');
  }
  currentTheme = theme;
  safeSetItem('niyyah_theme', theme);
  // Mettre à jour l'icône du bouton
  const btn = document.getElementById('btnTheme');
  if (btn) btn.textContent = theme === 'light' ? '🌙' : '☀️';
}
function toggleTheme() {
  applyTheme(currentTheme === 'dark' ? 'light' : 'dark');
}


