var WAQT_CATALOG = {
  matin: [
    {fr:'Avant ton premier acte aujourd\u2019hui, pose une intention secr\u00e8te. Une seule. Pour qui ?',en:'Before your first act today, set one secret intention. Just one. For whom?',ar:'\u0642\u064E\u0628\u0652\u0644\u064E \u0623\u064E\u0648\u0651\u064E\u0644\u0650 \u0641\u0650\u0639\u0652\u0644\u064D \u0627\u0644\u064A\u064E\u0648\u0652\u0645\u060C \u0636\u064E\u0639\u0652 \u0646\u0650\u064A\u0651\u064E\u0629\u064B \u0633\u0650\u0631\u0651\u0650\u064A\u0651\u064E\u0629. \u0648\u0627\u062D\u0650\u062F\u064E\u0629. \u0644\u0650\u0645\u064E\u0646\u061F'},
    {fr:'Avant tout, dis Bismillah. Trois syllabes pour ouvrir la journ\u00e9e. Aucune cl\u00e9 n\u2019est plus puissante.',en:'Place your hand on your heart. Three beats of silence. On the fourth: SubhanAllah.',ar:'\u0636\u064E\u0639\u0652 \u064A\u064E\u062F\u064E\u0643\u064E \u0639\u064E\u0644\u064E\u0649 \u0642\u064E\u0644\u0652\u0628\u0650\u0643. \u062B\u064E\u0644\u0627\u062B\u064F \u0646\u064E\u0628\u064E\u0636\u0627\u062A\u064D \u0635\u0627\u0645\u0650\u062A\u064E\u0629. \u0639\u0650\u0646\u0652\u062F\u064E \u0627\u0644\u0631\u0651\u0627\u0628\u0650\u0639\u064E\u0629: \u0633\u064F\u0628\u0652\u062D\u0627\u0646\u064E \u0627\u0644\u0644\u0651\u064E\u0647.'},
    {fr:'Ferme les yeux dix secondes. Pas pour dormir. Pour arriver.',en:'Close your eyes for ten seconds. Not to sleep. To arrive.',ar:'\u0623\u064E\u063A\u0652\u0644\u0650\u0642\u0652 \u0639\u064E\u064A\u0652\u0646\u064E\u064A\u0652\u0643 \u0639\u064E\u0634\u0652\u0631\u064E \u062B\u064E\u0648\u0627\u0646. \u0644\u064E\u064A\u0652\u0633\u064E \u0644\u0650\u0644\u0646\u0651\u064E\u0648\u0652\u0645. \u0644\u0650\u062A\u064E\u0635\u0650\u0644\u064E.'},
    {fr:'Regarde tes mains. Elles ont travaill\u00e9, serr\u00e9, donn\u00e9. Dis-leur merci en silence.',en:'Look at your hands. They\u2019ve worked, held, given. Thank them in silence.',ar:'\u0627\u0646\u0652\u0638\u064F\u0631\u0652 \u0625\u0650\u0644\u064E\u0649 \u064A\u064E\u062F\u064E\u064A\u0652\u0643. \u0639\u064E\u0645\u0650\u0644\u064E\u062A\u0627\u060C \u0636\u064E\u0645\u0651\u064E\u062A\u0627\u060C \u0623\u064E\u0639\u0652\u0637\u064E\u062A\u0627. \u0627\u0634\u0652\u0643\u064F\u0631\u0652\u0647\u064F\u0645\u0627 \u0628\u0650\u0635\u064E\u0645\u0652\u062A.'},
    {fr:'Choisis une personne que tu croises aujourd\u2019hui. Fais un dua pour elle sans qu\u2019elle le sache.',en:'Choose someone you\u2019ll meet today. Make du\u2019a for them without them knowing.',ar:'\u0627\u062E\u0652\u062A\u064E\u0631\u0652 \u0634\u064E\u062E\u0652\u0635\u064B\u0627 \u0633\u064E\u062A\u064E\u0644\u0652\u0642\u0627\u0647\u064F \u0627\u0644\u064A\u064E\u0648\u0652\u0645. \u0627\u062F\u0652\u0639\u064F \u0644\u064E\u0647\u064F \u062F\u064F\u0648\u0646\u064E \u0639\u0650\u0644\u0652\u0645\u0650\u0647.'},
    {fr:'S\u2019il reste un poids depuis hier \u2014 nomme-le dans ton c\u0153ur. Puis l\u00e2che-le, pour Allah.',en:'There\u2019s a weight in your heart since yesterday. Name it. Then let it go \u2014 for Allah.',ar:'\u0647\u064F\u0646\u0627\u0643\u064E \u062B\u0650\u0642\u064E\u0644\u064C \u0641\u0650\u064A \u0642\u064E\u0644\u0652\u0628\u0650\u0643 \u0645\u064F\u0646\u0652\u0630\u064F \u0627\u0644\u0623\u064E\u0645\u0652\u0633. \u0633\u064E\u0645\u0651\u0650\u0647. \u062B\u064F\u0645\u0651\u064E \u0623\u064E\u0637\u0652\u0644\u0650\u0642\u0652\u0647 \u2014 \u0644\u0650\u0644\u0651\u064E\u0647.'},
    {fr:'Ne parle pas pendant 60 secondes. Pas par contrainte. Par choix. C\u2019est du sabr.',en:'Don\u2019t speak for 60 seconds. Not by constraint. By choice. That\u2019s sabr.',ar:'\u0644\u0627 \u062A\u064E\u062A\u064E\u0643\u064E\u0644\u0651\u064E\u0645\u0652 \u0644\u0650\u0633\u0650\u062A\u0651\u0650\u064A\u0646\u064E \u062B\u0627\u0646\u0650\u064A\u064E\u0629. \u0644\u064E\u064A\u0652\u0633\u064E \u0625\u0650\u062C\u0652\u0628\u0627\u0631\u064B\u0627. \u0627\u062E\u0652\u062A\u0650\u064A\u0627\u0631\u064B\u0627. \u0647\u0630\u0627 \u0635\u064E\u0628\u0652\u0631.'},
    {fr:'Ta premi\u00e8re gorg\u00e9e du matin \u2014 eau, caf\u00e9, th\u00e9 \u2014 bois-la en pensant \u00e0 celui qui marche pour la trouver.',en:'Your first coffee this morning \u2014 drink it thinking of someone who only has water.',ar:'\u0642\u064E\u0647\u0652\u0648\u064E\u062A\u064F\u0643\u064E \u0627\u0644\u0623\u064F\u0648\u0644\u064E\u0649 \u2014 \u0627\u0634\u0652\u0631\u064E\u0628\u0652\u0647\u0627 \u0645\u064F\u062A\u064E\u0641\u064E\u0643\u0651\u0650\u0631\u064B\u0627 \u0641\u0650\u064A\u0645\u064E\u0646\u0652 \u0644\u0627 \u064A\u064E\u0645\u0652\u0644\u0650\u0643\u064F \u0625\u0650\u0644\u0651\u0627 \u0627\u0644\u0645\u0627\u0621.'},
    {fr:'Quel est le premier visage que tu verras aujourd\u2019hui ? Souris-lui avant m\u00eame de parler.',en:'Who is the first face you\u2019ll see today? Smile at them before you even speak.',ar:'\u0645\u064E\u0646\u0652 \u0623\u064E\u0648\u0651\u064E\u0644\u064F \u0648\u064E\u062C\u0652\u0647\u064D \u0633\u064E\u062A\u064E\u0631\u0627\u0647\u064F \u0627\u0644\u064A\u064E\u0648\u0652\u0645\u061F \u0627\u0628\u0652\u062A\u064E\u0633\u0650\u0645\u0652 \u0644\u064E\u0647\u064F \u0642\u064E\u0628\u0652\u0644\u064E \u0623\u064E\u0646\u0652 \u062A\u064E\u062A\u064E\u0643\u064E\u0644\u0651\u064E\u0645.'},
    {fr:'Ar-Razzaq. Celui qui pourvoit. M\u00eame \u00e0 ce que tu n\u2019as pas demand\u00e9. R\u00e9p\u00e8te Son Nom trois fois.',en:'Ar-Razzaq. The One who provides. Even what you didn\u2019t ask for. Repeat His Name three times.',ar:'\u0627\u0644\u0631\u0651\u064E\u0632\u0651\u0627\u0642. \u0627\u0644\u0651\u064E\u0630\u0650\u064A \u064A\u064E\u0631\u0652\u0632\u064F\u0642\u064F \u062D\u064E\u062A\u0651\u064E\u0649 \u0645\u0627 \u0644\u064E\u0645\u0652 \u062A\u064E\u0637\u0652\u0644\u064F\u0628. \u0631\u064E\u062F\u0651\u0650\u062F\u0652 \u0627\u0633\u0652\u0645\u064E\u0647\u064F \u062B\u064E\u0644\u0627\u062B\u064B\u0627.'},
    {fr:'Pose tes pieds au sol. Sens la terre. Elle te porte sans rien demander.',en:'Place your feet on the ground. Feel the earth. It carries you without asking anything.',ar:'\u0636\u064E\u0639\u0652 \u0642\u064E\u062F\u064E\u0645\u064E\u064A\u0652\u0643\u064E \u0639\u064E\u0644\u064E\u0649 \u0627\u0644\u0623\u064E\u0631\u0652\u0636. \u0627\u0634\u0652\u0639\u064F\u0631\u0652 \u0628\u0650\u0647\u0627. \u062A\u064E\u062D\u0652\u0645\u0650\u0644\u064F\u0643\u064E \u062F\u064F\u0648\u0646\u064E \u0623\u064E\u0646\u0652 \u062A\u064E\u0637\u0652\u0644\u064F\u0628\u064E \u0634\u064E\u064A\u0652\u0626\u064B\u0627.'},
    {fr:'\u00c9coute le premier son autour de toi. Le monde tourne d\u00e9j\u00e0 \u2014 sans ton effort.',en:'Listen to the first sound around you. The world is already turning \u2014 without your effort.',ar:'\u0627\u0633\u0652\u062A\u064E\u0645\u0650\u0639\u0652 \u0644\u0650\u0623\u064E\u0648\u0651\u064E\u0644\u0650 \u0635\u064E\u0648\u0652\u062A\u064D \u062D\u064E\u0648\u0652\u0644\u064E\u0643. \u0627\u0644\u0639\u0627\u0644\u064E\u0645\u064F \u064A\u064E\u062F\u064F\u0648\u0631\u064F \u0628\u0650\u0627\u0644\u0641\u0650\u0639\u0652\u0644 \u2014 \u062F\u064F\u0648\u0646\u064E \u062C\u064F\u0647\u0652\u062F\u0650\u0643.'},
    {fr:'Ne planifie rien pendant 30 secondes. Laisse le qadr respirer avant toi. Dis : Hasbiyallah wa ni\u2019mal Wakil.',en:'Plan nothing for 30 seconds. Let qadr breathe before you do.',ar:'\u0644\u0627 \u062A\u064F\u062E\u064E\u0637\u0651\u0650\u0637\u0652 \u0644\u0650\u0634\u064E\u064A\u0652\u0621\u064D \u0663\u0660 \u062B\u0627\u0646\u0650\u064A\u064E\u0629. \u062F\u064E\u0639\u0650 \u0627\u0644\u0642\u064E\u062F\u064E\u0631\u064E \u064A\u064E\u062A\u064E\u0646\u064E\u0641\u0651\u064E\u0633\u0652 \u0642\u064E\u0628\u0652\u0644\u064E\u0643.'},
    {fr:'Si tu passes devant un miroir ce matin \u2014 souris-toi. Le Proph\u00e8te \uFDFA disait : \u00ab Souris \u00e0 ton fr\u00e8re, c\u2019est une sadaqa. \u00bb',en:'The mirror this morning \u2014 look at yourself the way Allah looks at you: with mercy.',ar:'\u0627\u0644\u0645\u0650\u0631\u0652\u0622\u0629\u064F \u0647\u0630\u0627 \u0627\u0644\u0635\u0651\u064E\u0628\u0627\u062D \u2014 \u0627\u0646\u0652\u0638\u064F\u0631\u0652 \u0644\u0650\u0646\u064E\u0641\u0652\u0633\u0650\u0643\u064E \u0643\u064E\u0645\u0627 \u064A\u064E\u0646\u0652\u0638\u064F\u0631\u064F \u0627\u0644\u0644\u0651\u064E\u0647\u064F \u0625\u0650\u0644\u064E\u064A\u0652\u0643: \u0628\u0650\u0631\u064E\u062D\u0652\u0645\u064E\u0629.'},
    {fr:'Si tu n\u2019as encore parl\u00e9 \u00e0 personne \u2014 fais de ton premier mot un salam. M\u00eame \u00e0 toi-m\u00eame.',en:'Your first word today \u2014 make it a salam. Even to yourself.',ar:'\u0623\u064E\u0648\u0651\u064E\u0644\u064F \u0643\u064E\u0644\u0650\u0645\u064E\u0629\u064D \u0627\u0644\u064A\u064E\u0648\u0652\u0645 \u2014 \u0627\u062C\u0652\u0639\u064E\u0644\u0652\u0647\u0627 \u0633\u064E\u0644\u0627\u0645\u064B\u0627. \u062D\u064E\u062A\u0651\u064E\u0649 \u0644\u0650\u0646\u064E\u0641\u0652\u0633\u0650\u0643.'},
    {fr:'Cette nuit, un milliard de cellules ont travaill\u00e9 pour toi sans te demander la permission. Dis Alhamdulillah.',en:'You woke up. A billion cells worked for you last night. Say Alhamdulillah.',ar:'\u0627\u0633\u0652\u062A\u064E\u064A\u0652\u0642\u064E\u0638\u0652\u062A. \u0645\u0650\u0644\u064A\u0627\u0631\u064F \u062E\u064E\u0644\u0650\u064A\u0651\u064E\u0629\u064D \u0639\u064E\u0645\u0650\u0644\u064E\u062A\u0652 \u0644\u064E\u0643\u064E \u0627\u0644\u0644\u0651\u064E\u064A\u0652\u0644\u064E\u0629. \u0642\u064F\u0644\u0650 \u0627\u0644\u062D\u064E\u0645\u0652\u062F\u064F \u0644\u0650\u0644\u0651\u064E\u0647.'},
    {fr:'Quand tu feras le wudu \u2014 sens la fra\u00eecheur de l\u2019eau sur ton visage. Quelqu\u2019un marche des kilom\u00e8tres pour la trouver.',en:'The wudu water on your face \u2014 feel its coolness. Someone walks miles to find it.',ar:'\u0645\u0627\u0621\u064F \u0627\u0644\u0648\u064F\u0636\u064F\u0648\u0621 \u0639\u064E\u0644\u064E\u0649 \u0648\u064E\u062C\u0652\u0647\u0650\u0643 \u2014 \u0627\u0634\u0652\u0639\u064F\u0631\u0652 \u0628\u0650\u0628\u064E\u0631\u0652\u062F\u0650\u0647. \u063A\u064E\u064A\u0652\u0631\u064F\u0643\u064E \u064A\u064E\u0645\u0652\u0634\u0650\u064A \u0643\u0650\u064A\u0644\u0648\u0645\u0650\u062A\u0652\u0631\u0627\u062A\u064D \u0644\u0650\u064A\u064E\u062C\u0650\u062F\u064E\u0647.'},
    {fr:'S\u2019il y a une erreur d\u2019hier qui p\u00e8se \u2014 pardonne-toi. Tu n\u2019es plus cette personne ce matin.',en:'Forgive yourself for a mistake from yesterday. You\u2019re no longer that person this morning.',ar:'\u0633\u0627\u0645\u0650\u062D\u0652 \u0646\u064E\u0641\u0652\u0633\u064E\u0643\u064E \u0639\u064E\u0644\u064E\u0649 \u062E\u064E\u0637\u064E\u0623\u0650 \u0627\u0644\u0623\u064E\u0645\u0652\u0633. \u0644\u064E\u0633\u0652\u062A\u064E \u0630\u0644\u0650\u0643\u064E \u0627\u0644\u0634\u0651\u064E\u062E\u0652\u0635\u064E \u0647\u0630\u0627 \u0627\u0644\u0635\u0651\u064E\u0628\u0627\u062D.'},
    {fr:'Si quelqu\u2019un t\u2019a bless\u00e9 sans le savoir \u2014 lib\u00e8re-le dans ton c\u0153ur. Al-\u2018Afuww efface aussi.',en:'Someone hurt you without knowing. Release them in your heart \u2014 Al-\u2018Afuww erases too.',ar:'\u0622\u0630\u0627\u0643\u064E \u0623\u064E\u062D\u064E\u062F\u064C \u062F\u064F\u0648\u0646\u064E \u0639\u0650\u0644\u0652\u0645\u0650\u0647. \u0623\u064E\u0637\u0652\u0644\u0650\u0642\u0652\u0647\u064F \u0641\u0650\u064A \u0642\u064E\u0644\u0652\u0628\u0650\u0643 \u2014 \u0627\u0644\u0639\u064E\u0641\u064F\u0648\u0651\u064F \u064A\u064E\u0645\u0652\u062D\u064F\u0648 \u0623\u064E\u064A\u0652\u0636\u064B\u0627.'},
    {fr:'Avant d\u2019accomplir quoi que ce soit aujourd\u2019hui \u2014 Allah t\u2019a d\u00e9j\u00e0 nourri, abrit\u00e9, r\u00e9veill\u00e9. Le rizq pr\u00e9c\u00e8de l\u2019effort. Dis Alhamdulillah.',en:'You\u2019ve achieved nothing yet \u2014 and still Allah has fed, sheltered, and woken you. Rizq precedes effort.',ar:'\u0644\u064E\u0645\u0652 \u062A\u064F\u0646\u0652\u062C\u0650\u0632\u0652 \u0634\u064E\u064A\u0652\u0626\u064B\u0627 \u0628\u064E\u0639\u0652\u062F \u2014 \u0648\u0645\u064E\u0639\u064E \u0630\u0644\u0650\u0643\u064E \u0623\u064E\u0637\u0652\u0639\u064E\u0645\u064E\u0643\u064E \u0627\u0644\u0644\u0651\u064E\u0647 \u0648\u0622\u0648\u0627\u0643\u064E \u0648\u0623\u064E\u064A\u0652\u0642\u064E\u0638\u064E\u0643. \u0627\u0644\u0631\u0651\u0650\u0632\u0652\u0642\u064F \u064A\u064E\u0633\u0652\u0628\u0650\u0642\u064F \u0627\u0644\u062C\u064F\u0647\u0652\u062F.'},
    {fr:'Pour que l\u2019univers permette ta vie, sa constante initiale devait \u00eatre r\u00e9gl\u00e9e avec une pr\u00e9cision de 1 sur 10^123. Imagine ce chiffre : 10 suivi de 123 z\u00e9ros. Le hasard ne vise pas une cible. Ton existence est une intention.',en:'',ar:''},
    {fr:'Si la force qui lie tes atomes \u00e9tait 0,1% diff\u00e9rente \u2014 tu serais un nuage de poussi\u00e8re. Une d\u00e9cimale. Tout tient \u00e0 une d\u00e9cimale. Et Celui qui a fix\u00e9 cette d\u00e9cimale t\u2019a fait tenir.',en:'',ar:''},
    {fr:'Dans chacune de tes 37 000 milliards de cellules, 3 milliards de lettres d\u2019ADN sont \u00e9crites en ordre parfait. Une lettre d\u00e9plac\u00e9e \u2014 tu mourais. Qui tient la plume ?',en:'',ar:''},
    {fr:'Tu as commenc\u00e9 par une cellule. Elle a su, sans qu\u2019on lui dise, o\u00f9 placer ton c\u0153ur, tes yeux, tes oreilles. Le plan \u00e9tait d\u00e9j\u00e0 \u00e9crit en elle. Et Lui en conna\u00eet l\u2019auteur.',en:'',ar:''},
    {fr:'Ton c\u0153ur a battu 100 000 fois par jour. Il n\u2019a pas oubli\u00e9 une seule fois. Si tu devais le commander toi-m\u00eame une seule minute \u2014 tu mourrais. Quelqu\u2019un bat \u00e0 ta place. Quelqu\u2019un veille.',en:'',ar:''},
    {fr:'L\u2019astronome Fred Hoyle (ath\u00e9e toute sa vie) a calcul\u00e9 : la probabilit\u00e9 que la vie apparaisse par hasard est de 1 sur 10^40 000. Comme une tornade traversant une casse et assemblant un Boeing 747. Hoyle a abandonn\u00e9 l\u2019ath\u00e9isme. Que diras-tu, toi ?',en:'',ar:''},
    {fr:'En 615, le Coran annonce que les Romains, vaincus, vaincront \u00ab dans quelques ann\u00e9es \u00bb. En 627, ils gagnent \u2014 12 ans plus tard. Le texte existait avant l\u2019\u00e9v\u00e9nement. Aucune diseuse n\u2019aurait os\u00e9 une pr\u00e9diction politique aussi dat\u00e9e. (Coran 30:2-4)',en:'',ar:''},
    {fr:'Le Coran d\u00e9crit l\u2019embryon en 7 \u00e9tapes pr\u00e9cises : goutte, accroch\u00e9, m\u00e2ch\u00e9, ossifi\u00e9, rev\u00eatu de chair\u2026 14 si\u00e8cles avant l\u2019\u00e9chographie. Aucune m\u00e9decine antique n\u2019avait ces \u00e9tapes. (Coran 23:14)',en:'',ar:''},
    {fr:'Le Coran d\u00e9crit le d\u00e9veloppement des os PUIS leur rev\u00eatement par la chair \u2014 confirm\u00e9 par l\u2019embryologie moderne dans cet ordre exact. Inversion possible non d\u00e9tect\u00e9e au 7\u00e8me si\u00e8cle. (Coran 23:14)',en:'',ar:''},
    {fr:'Tu viens d\u2019ouvrir les yeux. Personne ne t\u2019a appris \u00e0 le faire. Personne ne t\u2019a r\u00e9veill\u00e9 \u00e0 l\u2019int\u00e9rieur. Le matin est un miracle qui se cache dans l\u2019\u00e9vidence. All\u00e2h te donne le jour.',en:'',ar:''},
    {fr:'Tu crois qu\u2019All\u00e2h est en col\u00e8re contre toi ? Sa mis\u00e9ricorde pr\u00e9c\u00e8de Sa col\u00e8re. C\u2019est un hadith authentique. C\u2019est inscrit avant tout. Tu n\u2019es pas l\u2019exception.',en:'',ar:''},
    {fr:'Tu penses qu\u2019Il ne veut plus de toi ? Dans un hadith qudsi, All\u00e2h dit : \u00ab Si vos p\u00e9ch\u00e9s atteignaient les nuages du ciel et que vous reveniez \u00e0 Moi, Je vous pardonnerais. \u00bb C\u2019est Lui qui parle. Directement.',en:'',ar:''},
    {fr:'Tu cherches un signe qu\u2019Il t\u2019aime ? Tu respires. Tu lis ceci. Tu Le cherches. Le simple fait que tu Le cherches est d\u00e9j\u00e0 la preuve qu\u2019Il t\u2019a trouv\u00e9.',en:'',ar:''},
    {fr:'Le Proph\u00e8te \uFDFA a dit : \u00ab Sois dans ce monde comme un \u00e9tranger, ou un voyageur de passage. \u00bb Tu ne d\u00e9balles pas tes valises dans un h\u00f4tel. Pourquoi le ferais-tu dans cette vie ?',en:'',ar:''},
    {fr:'Tu s\u00e8mes un grain de bl\u00e9. Tu attends 3 mois pour r\u00e9colter. Et tu t\u2019\u00e9tonnes que ce qu\u2019on s\u00e8me aujourd\u2019hui pousse dans l\u2019au-del\u00e0 ? Le temps qui s\u00e9pare l\u2019acte de sa r\u00e9compense est juste plus long.',en:'',ar:''},
    {fr:'Une rivi\u00e8re contourn\u00e9e par un rocher ne meurt pas. Elle creuse, ou elle passe \u00e0 c\u00f4t\u00e9. Mais elle ne s\u2019arr\u00eate pas. All\u00e2h n\u2019a pas cr\u00e9\u00e9 d\u2019obstacle sans avoir pr\u00e9vu un chemin de contournement.',en:'',ar:''},
    {fr:'Un oiseau quitte sa cage ouverte et vole vers le ciel. Un autre oiseau, cage ouverte aussi, reste pr\u00e8s des barreaux. Le confort de la prison vaut-il l\u2019envol ? Tes habitudes sont la cage. La salat est l\u2019envol.',en:'',ar:''},
    {fr:'Un voleur entre dans une maison vide. Il en repart avec rien. Si ton c\u0153ur est vide d\u2019All\u00e2h, ce monde te volera sans rien y trouver. Si ton c\u0153ur est plein de Lui, rien ne peut t\u2019\u00eatre vol\u00e9.',en:'',ar:''},
    {fr:'Un fleuve coule vers la mer. Il ne sait pas qu\u2019il deviendra mer. Tu marches vers All\u00e2h. Tu ne sais pas ce que tu deviendras en arrivant. Mais tu y vas. Et chaque pas est une fonte vers le grand.',en:'',ar:''},
    {fr:'All\u00e2h t\u2019a cr\u00e9\u00e9. C\u2019est d\u00e9j\u00e0 une preuve qu\u2019Il te voulait dans ce monde. Pas un hasard. Pas une erreur. Une volont\u00e9.',en:'',ar:''},
    {fr:'Tu te trouves m\u00e9diocre. Mais All\u00e2h, en te cr\u00e9ant, a dit : \u00ab Que b\u00e9ni soit All\u00e2h, le Meilleur des cr\u00e9ateurs \u00bb (Coran 23:14). Tu es l\u2019\u0153uvre du Meilleur. Tu n\u2019es pas m\u00e9diocre \u2014 tu te juges sans Sa loupe.',en:'',ar:''},
    {fr:'Quelque part dans le monde, on emp\u00eache un musulman de prier librement. Toi tu peux. Cette libert\u00e9 est une ni\u2019ma \u00e0 prot\u00e9ger \u2014 pour toi et pour eux.',en:'',ar:''},
    {fr:'Quelqu\u2019un fait un dua pour toi en ce moment, sans le savoir. Le Proph\u00e8te \uFDFA a dit : \u00ab Le dua du musulman pour son fr\u00e8re en son absence est exauc\u00e9. \u00bb Une cha\u00eene invisible te porte. Toi aussi, tu peux y entrer.',en:'',ar:''},
    {fr:'\u00c0 cet instant exact, un adhan est en train d\u2019\u00eatre prononc\u00e9 quelque part dans le monde. Depuis 1400 ans, sans interruption d\u2019une seconde. Tu fais partie d\u2019une cha\u00eene qui ne s\u2019arr\u00eate jamais.',en:'',ar:''},
    {fr:'Au moment o\u00f9 tu lis ceci, des millions de musulmans viennent de prier le Fajr quelque part. La Terre est ronde \u2014 chaque fuseau a sa pri\u00e8re. L\u2019oumma est \u00e9veill\u00e9e 24h/24.',en:'',ar:''},
    {fr:'Le Coran est r\u00e9cit\u00e9 24h/24 sur Terre. Aucune seconde ne passe sans qu\u2019une voix le porte. Cette continuit\u00e9 n\u2019existe pour AUCUN autre livre dans l\u2019histoire humaine.',en:'',ar:''},
    {fr:'Pendant la minute o\u00f9 tu lis ces mots, environ 100 musulmans viennent de na\u00eetre dans le monde. Ils porteront ta foi quand toi tu ne seras plus.',en:'',ar:''},
    {fr:'Le Proph\u00e8te \uFDFA a dit : \u00ab H\u00e2te-toi d\u2019accomplir tes \u0153uvres avant sept choses : la pauvret\u00e9 qui fait oublier, la richesse qui rend rebelle, la maladie qui handicape, la vieillesse qui affaiblit, la mort soudaine, ou l\u2019Heure. \u00bb Tu n\u2019attends pas. Tu s\u00e8mes maintenant.',en:'',ar:''},
    {fr:'Le nourrisson cherche le sein sans qu\u2019on le lui apprenne. Qui le lui a dit ?',en:'',ar:''},
    {fr:'Deux atomes d\u2019hydrog\u00e8ne + un d\u2019oxyg\u00e8ne = de l\u2019eau. Pourquoi pas un poison ?',en:'',ar:''},
    {fr:'Le b\u00e9b\u00e9 dans le ventre respire dans l\u2019eau. Dehors, il respire dans l\u2019air. Il a appris quand ?',en:'',ar:''},
    {fr:'Tu te l\u00e8ves pour Fajr \u2014 \u00e0 la m\u00eame heure que Bilal a appel\u00e9 pour la premi\u00e8re fois \u00e0 M\u00e9dine, il y a 14 si\u00e8cles. La cha\u00eene des voix n\u2019a jamais \u00e9t\u00e9 interrompue.',en:'',ar:''}
  ],
  midi: [
    {fr:'Arr\u00eate-toi. Juste arr\u00eate-toi. 10 secondes sans rien faire. Puis dis SubhanAllah. C\u2019est d\u00e9j\u00e0 une ibadah.',en:'Stop. Just stop. 10 seconds of doing nothing. That\u2019s already ibadah.',ar:'\u062A\u064E\u0648\u064E\u0642\u0651\u064E\u0641. \u0641\u064E\u0642\u064E\u0637 \u062A\u064E\u0648\u064E\u0642\u0651\u064E\u0641. \u0661\u0660 \u062B\u064E\u0648\u0627\u0646\u064D \u0628\u0650\u0644\u0627 \u0634\u064E\u064A\u0652\u0621. \u0647\u0630\u0650\u0647\u0650 \u0639\u0650\u0628\u0627\u062F\u064E\u0629.'},
    {fr:'Quand tu prendras la premi\u00e8re bouch\u00e9e \u2014 ferme les yeux en m\u00e2chant. Go\u00fbte ce qu\u2019Allah t\u2019a donn\u00e9.',en:'Your first bite \u2014 close your eyes as you chew. Taste what Allah gave you.',ar:'\u0623\u064E\u0648\u0651\u064E\u0644\u064F \u0644\u064F\u0642\u0652\u0645\u064E\u0629 \u2014 \u0623\u064E\u063A\u0652\u0644\u0650\u0642\u0652 \u0639\u064E\u064A\u0652\u0646\u064E\u064A\u0652\u0643 \u0648\u0623\u064E\u0646\u0652\u062A\u064E \u062A\u064E\u0645\u0652\u0636\u064E\u063A. \u062A\u064E\u0630\u064E\u0648\u0651\u064E\u0642\u0652 \u0645\u0627 \u0623\u064E\u0639\u0652\u0637\u0627\u0643\u064E \u0627\u0644\u0644\u0651\u064E\u0647.'},
    {fr:'Il y a quelqu\u2019un autour de toi qui porte un poids invisible. Prie pour lui. Maintenant.',en:'There\u2019s someone near you carrying an invisible weight. Pray for them. Now.',ar:'\u0647\u064F\u0646\u0627\u0643\u064E \u0634\u064E\u062E\u0652\u0635\u064C \u0642\u064E\u0631\u0650\u064A\u0628\u064C \u064A\u064E\u062D\u0652\u0645\u0650\u0644\u064F \u062B\u0650\u0642\u064E\u0644\u064B\u0627 \u062E\u064E\u0641\u0650\u064A\u0651\u064B\u0627. \u0627\u062F\u0652\u0639\u064F \u0644\u064E\u0647. \u0627\u0644\u0622\u0646.'},
    {fr:'Ce que tu vas manger aujourd\u2019hui \u2014 combien de mains l\u2019ont pr\u00e9par\u00e9 avant d\u2019arriver \u00e0 toi ? Pense \u00e0 elles.',en:'This meal \u2014 how many hands prepared it before it reached you? Think of them.',ar:'\u0647\u0630\u0627 \u0627\u0644\u0637\u0651\u064E\u0639\u0627\u0645 \u2014 \u0643\u064E\u0645\u0652 \u064A\u064E\u062F\u064B\u0627 \u0623\u064E\u0639\u064E\u062F\u0651\u064E\u062A\u0652\u0647\u064F \u0642\u064E\u0628\u0652\u0644\u064E \u0623\u064E\u0646\u0652 \u064A\u064E\u0635\u0650\u0644\u064E \u0625\u0650\u0644\u064E\u064A\u0652\u0643\u061F \u0641\u064E\u0643\u0651\u0650\u0631\u0652 \u0641\u0650\u064A\u0647\u0650\u0645.'},
    {fr:'Si tes yeux sont sur un \u00e9cran \u2014 d\u00e9tache-les. Regarde au-del\u00e0. Qu\u2019y a-t-il de vrai, l\u00e0-bas ?',en:'Look at the screen you were staring at. Then look beyond. What\u2019s real out there?',ar:'\u0627\u0646\u0652\u0638\u064F\u0631\u0652 \u0625\u0650\u0644\u064E\u0649 \u0627\u0644\u0634\u0651\u0627\u0634\u064E\u0629 \u0627\u0644\u0651\u064E\u062A\u0650\u064A \u0643\u064F\u0646\u0652\u062A\u064E \u062A\u064F\u062D\u064E\u062F\u0651\u0650\u0642\u064F\u0647\u0627. \u062B\u064F\u0645\u0651\u064E \u0627\u0646\u0652\u0638\u064F\u0631\u0652 \u0623\u064E\u0628\u0652\u0639\u064E\u062F. \u0645\u0627 \u0627\u0644\u062D\u064E\u0642\u0650\u064A\u0642\u0650\u064A\u0651\u064F \u0647\u064F\u0646\u0627\u0643\u061F'},
    {fr:'S\u2019il reste un agacement de ce matin \u2014 l\u00e2che-le. Pas pour lui. Pour toi.',en:'Someone annoyed you this morning. Release that anger \u2014 not for them. For you.',ar:'\u0623\u064E\u063A\u0652\u0636\u064E\u0628\u064E\u0643\u064E \u0623\u064E\u062D\u064E\u062F\u064C \u0647\u0630\u0627 \u0627\u0644\u0635\u0651\u064E\u0628\u0627\u062D. \u0623\u064E\u0637\u0652\u0644\u0650\u0642\u0652 \u0630\u0644\u0650\u0643\u064E \u0627\u0644\u063A\u064E\u0636\u064E\u0628 \u2014 \u0644\u064E\u064A\u0652\u0633\u064E \u0644\u064E\u0647. \u0644\u064E\u0643.'},
    {fr:'Quand tu manges \u2014 pose ce que tu tiens entre deux bouch\u00e9es. Respire. C\u2019est la sunnah de manger doucement.',en:'Put your fork down between bites. Breathe. It\u2019s the sunnah of eating slowly.',ar:'\u0636\u064E\u0639\u0652 \u0634\u064E\u0648\u0652\u0643\u064E\u062A\u064E\u0643 \u0628\u064E\u064A\u0652\u0646\u064E \u0627\u0644\u0644\u0651\u064F\u0642\u064E\u0645. \u062A\u064E\u0646\u064E\u0641\u0651\u064E\u0633. \u0633\u064F\u0646\u0651\u064E\u0629\u064F \u0627\u0644\u0623\u064E\u0643\u0652\u0644\u0650 \u0628\u0650\u062A\u064E\u0623\u064E\u0646\u0651\u064D.'},
    {fr:'Dis dans ton c\u0153ur : \u00ab Ya Sabur, accorde-moi Ta patience pour cet apr\u00e8s-midi. \u00bb',en:'Say in your heart: \u201cYa Sabur, grant me Your patience for this afternoon.\u201d',ar:'\u0642\u064F\u0644\u0652 \u0641\u0650\u064A \u0642\u064E\u0644\u0652\u0628\u0650\u0643: \u00ab\u064A\u0627 \u0635\u064E\u0628\u064F\u0648\u0631\u060C \u0627\u0645\u0652\u0646\u064E\u062D\u0652\u0646\u0650\u064A \u0635\u064E\u0628\u0652\u0631\u064E\u0643\u064E \u0644\u0650\u0647\u0630\u0627 \u0627\u0644\u0645\u064E\u0633\u0627\u0621.\u00bb'},
    {fr:'Envoie un message \u00e0 quelqu\u2019un que tu n\u00e9gliges. Juste : \u00ab Je pense \u00e0 toi. \u00bb',en:'Send a message to someone you\u2019ve neglected. Just: \u201cThinking of you.\u201d',ar:'\u0623\u064E\u0631\u0652\u0633\u0650\u0644\u0652 \u0631\u0650\u0633\u0627\u0644\u064E\u0629\u064B \u0644\u0650\u0645\u064E\u0646\u0652 \u0623\u064E\u0647\u0652\u0645\u064E\u0644\u0652\u062A\u064E\u0647. \u0641\u064E\u0642\u064E\u0637: \u00ab\u0623\u064F\u0641\u064E\u0643\u0651\u0650\u0631\u064F \u0641\u0650\u064A\u0643.\u00bb'},
    {fr:'As-Sabur. Le Patient. Celui qui ne Se presse pas. R\u00e9p\u00e8te Son Nom en expirant.',en:'As-Sabur. The Patient. The One who never rushes. Repeat His Name as you exhale.',ar:'\u0627\u0644\u0635\u0651\u064E\u0628\u064F\u0648\u0631. \u0627\u0644\u0651\u064E\u0630\u0650\u064A \u0644\u0627 \u064A\u064E\u0633\u0652\u062A\u064E\u0639\u0652\u062C\u0650\u0644. \u0631\u064E\u062F\u0651\u0650\u062F\u0652 \u0627\u0633\u0652\u0645\u064E\u0647\u064F \u0645\u064E\u0639\u064E \u0627\u0644\u0632\u0651\u064E\u0641\u0650\u064A\u0631.'},
    {fr:'Ta charge mentale n\u2019est pas \u00e0 toi seul. D\u00e9pose-la 10 secondes \u2014 Allah est Al-Wakil.',en:'Your mental load isn\u2019t yours alone. Set it down 10 seconds \u2014 Allah is Al-Wakil.',ar:'\u062D\u0650\u0645\u0652\u0644\u064F\u0643\u064E \u0627\u0644\u0630\u0651\u0650\u0647\u0652\u0646\u0650\u064A\u0651\u064F \u0644\u064E\u064A\u0652\u0633\u064E \u0644\u064E\u0643\u064E \u0648\u064E\u062D\u0652\u062F\u064E\u0643. \u0636\u064E\u0639\u0652\u0647\u064F \u0661\u0660 \u062B\u064E\u0648\u0627\u0646 \u2014 \u0627\u0644\u0644\u0651\u064E\u0647\u064F \u0627\u0644\u0648\u064E\u0643\u0650\u064A\u0644.'},
    {fr:'Si tu b\u00e2illes, le Proph\u00e8te \uFDFA a dit : \u00ab Couvre-toi quand tu b\u00e2illes. \u00bb Une pudeur jusque dans la fatigue.',en:'Yawn without shame. Your body asks you to slow down \u2014 obey it, that\u2019s shukr.',ar:'\u062A\u064E\u062B\u0627\u0621\u064E\u0628\u0652 \u062F\u064F\u0648\u0646\u064E \u062E\u064E\u062C\u064E\u0644. \u062C\u064E\u0633\u064E\u062F\u064F\u0643\u064E \u064A\u064E\u0637\u0652\u0644\u064F\u0628\u064F \u0627\u0644\u062A\u0651\u064E\u0628\u0627\u0637\u064F\u0624 \u2014 \u0623\u064E\u0637\u0650\u0639\u0652\u0647\u060C \u0647\u0630\u0627 \u0634\u064F\u0643\u0652\u0631.'},
    {fr:'Pose ta paume sur ce qui est devant toi. Sens la surface. Reviens ici \u2014 pas dans ta t\u00eate.',en:'Place your palm on the table. Feel the surface. Come back here \u2014 not in your head.',ar:'\u0636\u064E\u0639\u0652 \u0643\u064E\u0641\u0651\u064E\u0643\u064E \u0639\u064E\u0644\u064E\u0649 \u0627\u0644\u0637\u0651\u0627\u0648\u0650\u0644\u064E\u0629. \u0627\u0634\u0652\u0639\u064F\u0631\u0652 \u0628\u0650\u0627\u0644\u0633\u0651\u064E\u0637\u0652\u062D. \u0639\u064F\u062F\u0652 \u0625\u0650\u0644\u064E\u0649 \u0647\u064F\u0646\u0627 \u2014 \u0644\u0627 \u0641\u0650\u064A \u0631\u064E\u0623\u0652\u0633\u0650\u0643.'},
    {fr:'Si quelqu\u2019un mange avec toi \u2014 vous partagez la m\u00eame provision d\u2019Allah en ce moment.',en:'The person across from you is eating too \u2014 you share Allah\u2019s provision right now.',ar:'\u0627\u0644\u0634\u0651\u064E\u062E\u0652\u0635\u064F \u0623\u064E\u0645\u0627\u0645\u064E\u0643 \u064A\u064E\u0623\u0652\u0643\u064F\u0644\u064F \u0623\u064E\u064A\u0652\u0636\u064B\u0627 \u2014 \u062A\u064E\u062A\u064E\u0642\u0627\u0633\u064E\u0645\u0627\u0646\u0650 \u0631\u0650\u0632\u0652\u0642\u064E \u0627\u0644\u0644\u0651\u064E\u0647 \u0627\u0644\u0622\u0646.'},
    {fr:'Quand tu parles \u00e0 quelqu\u2019un aujourd\u2019hui \u2014 appelle-le par son pr\u00e9nom. La connexion humaine commence l\u00e0.',en:'Call someone by their first name, not their title. Human connection starts there.',ar:'\u0646\u0627\u062F\u0650 \u0623\u064E\u062D\u064E\u062F\u064B\u0627 \u0628\u0650\u0627\u0633\u0652\u0645\u0650\u0647\u060C \u0644\u0627 \u0628\u0650\u0644\u064E\u0642\u064E\u0628\u0650\u0647. \u0627\u0644\u0631\u0651\u0627\u0628\u0650\u0637\u064F \u0627\u0644\u0625\u0650\u0646\u0652\u0633\u0627\u0646\u0650\u064A\u0651\u064F \u064A\u064E\u0628\u0652\u062F\u064E\u0623\u064F \u0645\u0650\u0646\u0652 \u0647\u064F\u0646\u0627.'},
    {fr:'Ce qui te nourrit ce midi \u2014 ne va pas de soi. M\u00e2che plus lentement. Dis Alhamdulillah.',en:'Your stomach fills up \u2014 800 million don\u2019t have this luxury right now. Alhamdulillah.',ar:'\u0645\u064E\u0639\u0650\u062F\u064E\u062A\u064F\u0643\u064E \u062A\u064E\u0645\u0652\u062A\u064E\u0644\u0650\u0626\u064F \u2014 \u0668\u0660\u0660 \u0645\u0650\u0644\u064A\u0648\u0646 \u0644\u0627 \u064A\u064E\u0645\u0652\u0644\u0650\u0643\u064F\u0648\u0646\u064E \u0647\u0630\u0627 \u0627\u0644\u0622\u0646. \u0627\u0644\u062D\u064E\u0645\u0652\u062F\u064F \u0644\u0650\u0644\u0651\u064E\u0647.'},
    {fr:'La lumi\u00e8re du midi \u2014 o\u00f9 qu\u2019elle te trouve. Gratuite. In\u00e9puis\u00e9e. C\u2019est un verset visible. Dis : Allahu Nur as-samawati wal-ard.',en:'Midday light streams through the window. Free. Inexhaustible. A visible verse.',ar:'\u0636\u064E\u0648\u0652\u0621\u064F \u0627\u0644\u0638\u0651\u064F\u0647\u0652\u0631\u0650 \u064A\u064E\u062F\u0652\u062E\u064F\u0644\u064F \u0645\u0650\u0646\u064E \u0627\u0644\u0646\u0651\u0627\u0641\u0650\u0630\u064E\u0629. \u0645\u064E\u062C\u0651\u0627\u0646\u0650\u064A\u0651. \u0644\u0627 \u064A\u064E\u0646\u0652\u0641\u064E\u062F. \u0622\u064A\u064E\u0629\u064C \u0645\u064E\u0631\u0652\u0626\u0650\u064A\u0651\u064E\u0629.'},
    {fr:'On se juge tous s\u00e9v\u00e8rement parfois. Allah est plus doux avec toi que toi-m\u00eame.',en:'You judged yourself harshly this morning. Stop. Allah is gentler with you than you are.',ar:'\u062D\u0627\u0633\u064E\u0628\u0652\u062A\u064E \u0646\u064E\u0641\u0652\u0633\u064E\u0643\u064E \u0628\u0650\u0642\u064E\u0633\u0652\u0648\u064E\u0629\u064D \u0647\u0630\u0627 \u0627\u0644\u0635\u0651\u064E\u0628\u0627\u062D. \u062A\u064E\u0648\u064E\u0642\u0651\u064E\u0641. \u0627\u0644\u0644\u0651\u064E\u0647\u064F \u0623\u064E\u0631\u0652\u0641\u064E\u0642\u064F \u0628\u0650\u0643\u064E \u0645\u0650\u0646\u0652\u0643.'},
    {fr:'Tu manges seul ? Le Proph\u00e8te \uFDFA d\u00e9testait manger seul. Partage ne serait-ce qu\u2019un regard avec quelqu\u2019un.',en:'Eating alone? The Prophet \uFDFA disliked eating alone. Share even just a glance with someone.',ar:'\u062A\u064E\u0623\u0652\u0643\u064F\u0644\u064F \u0648\u064E\u062D\u0652\u062F\u064E\u0643\u061F \u0627\u0644\u0646\u0651\u064E\u0628\u0650\u064A\u0651\u064F \uFDFA \u0643\u0627\u0646\u064E \u064A\u064E\u0643\u0652\u0631\u064E\u0647\u064F \u0627\u0644\u0623\u064E\u0643\u0652\u0644\u064E \u0648\u064E\u062D\u0652\u062F\u064E\u0647. \u0634\u0627\u0631\u0650\u0643\u0652 \u0648\u064E\u0644\u064E\u0648\u0652 \u0646\u064E\u0638\u0652\u0631\u064E\u0629\u064B \u0645\u064E\u0639\u064E \u0623\u064E\u062D\u064E\u062F.'},
    {fr:'Le Proph\u00e8te \uFDFA ne remplissait jamais son estomac. Un tiers repas, un tiers eau, un tiers air.',en:'The Prophet \uFDFA never filled his stomach. One third food, one third water, one third air.',ar:'\u0627\u0644\u0646\u0651\u064E\u0628\u0650\u064A\u0651\u064F \uFDFA \u0644\u064E\u0645\u0652 \u064A\u064E\u0645\u0652\u0644\u064E\u0623\u0652 \u0645\u064E\u0639\u0650\u062F\u064E\u062A\u064E\u0647\u064F \u0642\u064E\u0637\u0651. \u062B\u064F\u0644\u064F\u062B\u064C \u0637\u064E\u0639\u0627\u0645\u060C \u062B\u064F\u0644\u064F\u062B\u064C \u0645\u0627\u0621\u060C \u062B\u064F\u0644\u064F\u062B\u064C \u0647\u064E\u0648\u0627\u0621.'},
    {fr:'La Terre fonce dans l\u2019espace \u00e0 107 000 km/h. Tu marches dessus sans rien sentir. Quelqu\u2019un a si bien r\u00e9gl\u00e9 le voyage que tu peux lire en marchant. Qui ?',en:'',ar:''},
    {fr:'L\u2019eau se DILATE en gelant \u2014 anomalie unique dans l\u2019univers connu. Sans elle, les oc\u00e9ans g\u00e8leraient depuis le fond et toute vie aurait disparu. Une exception physique. Pour toi.',en:'',ar:''},
    {fr:'La lumi\u00e8re met 8 minutes \u00e0 arriver depuis le Soleil. Quand tu la sens, elle est partie il y a 8 minutes. All\u00e2h t\u2019\u00e9crit en avance. Tu vis dans la trace de Sa d\u00e9cision pass\u00e9e.',en:'',ar:''},
    {fr:'Tu as 86 milliards de neurones \u2014 plus que d\u2019\u00e9toiles dans la Voie lact\u00e9e. Tu portes un univers en toi, fa\u00e7onn\u00e9 par Celui qui a fa\u00e7onn\u00e9 les \u00e9toiles.',en:'',ar:''},
    {fr:'Tu lis ces mots. La lumi\u00e8re entre dans tes yeux, devient signal \u00e9lectrique, devient pens\u00e9e. Aucun scientifique ne sait comment. Et pourtant tu comprends. La compr\u00e9hension elle-m\u00eame est une gr\u00e2ce.',en:'',ar:''},
    {fr:'Tu existes parce que ton p\u00e8re a produit 200 millions de spermatozo\u00efdes ce jour-l\u00e0. Un seul a gagn\u00e9 \u2014 le tien. Probabilit\u00e9 de toi sp\u00e9cifiquement : 1 sur 200 millions. Et pourtant tu lis ceci.',en:'',ar:''},
    {fr:'Pour qu\u2019une seule prot\u00e9ine fonctionnelle apparaisse par hasard, il faudrait 10^164 essais. L\u2019univers entier n\u2019a connu que 10^80 r\u00e9actions depuis le Big Bang. Le calcul est clos. Le hasard est insuffisant.',en:'',ar:''},
    {fr:'Ton cerveau effectue environ 10^16 op\u00e9rations par seconde, en consommant l\u2019\u00e9nergie d\u2019une ampoule basse consommation. Aucun supercalculateur du monde n\u2019atteint cette efficacit\u00e9 par watt. Tu portes une merveille dans la t\u00eate \u2014 pour le prix d\u2019une assiette. All\u00e2h, le G\u00e9n\u00e9reux.',en:'',ar:''},
    {fr:'Le Coran parle de deux mers qui se rencontrent sans se m\u00e9langer \u2014 s\u00e9par\u00e9es par une barri\u00e8re. Ph\u00e9nom\u00e8ne oc\u00e9anographique confirm\u00e9 au 20\u00e8me si\u00e8cle (halocline). Le texte d\u00e9crit ce que personne ne pouvait voir au 7\u00e8me si\u00e8cle. (Coran 25:53)',en:'',ar:''},
    {fr:'Le Coran dit que toute chose vivante est faite \u00e0 partir de l\u2019eau. La biologie moderne confirme : aucune vie sans eau, 70% de toi est eau, jusqu\u2019\u00e0 la derni\u00e8re bact\u00e9rie. (Coran 21:30)',en:'',ar:''},
    {fr:'Tu as arr\u00eat\u00e9 de prier depuis longtemps ? La porte du tawba n\u2019a JAMAIS de file d\u2019attente. Elle s\u2019ouvre d\u00e8s que tu te l\u00e8ves. All\u00e2h n\u2019a pas tenu de compte du temps \u00e9coul\u00e9.',en:'',ar:''},
    {fr:'Tu doutes d\u2019\u00eatre aim\u00e9 ? All\u00e2h t\u2019a donn\u00e9 100 fois plus de raisons d\u2019esp\u00e9rer que de craindre. 113 sourates sur 114 commencent par Sa Mis\u00e9ricorde. Une seule fois sur 114 \u2014 Sa rigueur passe en premier.',en:'',ar:''},
    {fr:'Imagine une aiguille tremp\u00e9e dans l\u2019oc\u00e9an, puis retir\u00e9e. La goutte qui reste sur l\u2019aiguille \u2014 c\u2019est ce monde. L\u2019oc\u00e9an \u2014 c\u2019est l\u2019au-del\u00e0. Sur quoi mises-tu ?',en:'',ar:''},
    {fr:'Deux hommes au march\u00e9. L\u2019un ach\u00e8te tout ce qu\u2019il voit, plein les bras. L\u2019autre n\u2019ach\u00e8te qu\u2019une chose, l\u00e9g\u00e8re, qu\u2019il portera longtemps. Le second arrive plus loin. Le rizq ne p\u00e8se pas sur celui qui choisit.',en:'',ar:''},
    {fr:'L\u2019arbre qui donne le plus de fruits est celui que les passants frappent le plus. Si tu re\u00e7ois des pierres dans ta vie \u2014 c\u2019est peut-\u00eatre parce qu\u2019Il a mis des fruits en toi.',en:'',ar:''},
    {fr:'Un homme se plaint de devoir prier 5 fois par jour. Le m\u00eame homme mange 3 fois, boit 8 fois, regarde son t\u00e9l\u00e9phone 80 fois. Le corps obtient ses pauses. L\u2019\u00e2me aussi en demande. Cinq, c\u2019est tr\u00e8s peu.',en:'',ar:''},
    {fr:'Une rivi\u00e8re ne se plaint pas de la pente. Sans la pente, elle ne coulerait pas. Sans les \u00e9preuves, ton iman ne progresserait pas. Remercie ce qui t\u2019oblige \u00e0 descendre \u2014 c\u2019est ce qui te fait avancer.',en:'',ar:''},
    {fr:'Tu as ouvert l\u2019app aujourd\u2019hui. Quelqu\u2019un d\u2019autre, pas. All\u00e2h t\u2019a guid\u00e9 \u00e0 un geste qu\u2019Il valorise. Tu ne t\u2019es pas amen\u00e9 ici tout seul.',en:'',ar:''},
    {fr:'Tu existes. Ce mot est petit, mais immense. Sur des milliards de possibilit\u00e9s, c\u2019est TOI qui es l\u00e0, \u00e0 lire ceci. Tu as une place r\u00e9serv\u00e9e dans le r\u00e9el.',en:'',ar:''},
    {fr:'Pendant que tu manges sereinement, un musulman a faim quelque part. Ce n\u2019est pas culpabilit\u00e9 \u2014 c\u2019est lien. L\u2019oumma est un seul corps. Quand une partie a mal, l\u2019autre la porte.',en:'',ar:''},
    {fr:'L\u2019oumma fait plus de 2 milliards d\u2019\u00e2mes. Tu n\u2019es pas seul. Ton iman se renforce du leur, le leur se renforce du tien. Aucun musulman ne marche v\u00e9ritablement seul.',en:'',ar:''},
    {fr:'Une femme musulmane se cache pour porter son hijab quelque part dans le monde. Toi tu portes le tien (ou pas) librement. La libert\u00e9 du voile est aussi une cause silencieuse. Honore-la en pens\u00e9e.',en:'',ar:''},
    {fr:'\u00c0 la Mecque, en ce moment m\u00eame, des milliers de personnes tournent autour de la Kaaba. Sans arr\u00eat. Jour, nuit, \u00e9t\u00e9, hiver. Depuis 1400 ans. Le centre de gravit\u00e9 spirituel du monde ne s\u2019\u00e9teint jamais.',en:'',ar:''},
    {fr:'Pendant que tu manges, plusieurs millions de musulmans sont en prosternation quelque part. Quelqu\u2019un, en ce moment, dit Subhana Rabbiyal A\u2019la. Tu n\u2019es jamais seul dans l\u2019adoration.',en:'',ar:''},
    {fr:'En ce moment, des milliers d\u2019imams r\u00e9citent Sourate Al-Fatiha dans leur pri\u00e8re. La m\u00eame sourate. Les m\u00eames mots. Depuis 14 si\u00e8cles. Une seule m\u00e9lodie r\u00e9p\u00e9t\u00e9e par l\u2019univers musulman.',en:'',ar:''},
    {fr:'Pendant cette plage du dhuhr, environ 500 millions de musulmans s\u2019arr\u00eatent de travailler pour prier. Une \u00e9conomie mondiale qui ralentit pour All\u00e2h, 5 fois par jour, sans contrat.',en:'',ar:''},
    {fr:'Le Proph\u00e8te \uFDFA a dit : \u00ab Le temps se rapprochera, les \u0153uvres diminueront, l\u2019avarice se r\u00e9pandra, et les \u00e9preuves appara\u00eetront. \u00bb Tu sens le temps qui file plus vite chaque ann\u00e9e ? Tu n\u2019es pas seul. C\u2019est annonc\u00e9. Donc tu peux choisir : courir avec le temps, ou avec ton \u00e2me.',en:'',ar:''},
    {fr:'Une orange a la peau qui prot\u00e8ge, la chair qui nourrit, le p\u00e9pin qui refait l\u2019arbre. Qui a pens\u00e9 \u00e0 tout ?',en:'',ar:''},
    {fr:'Ton \u0153il a 130 millions de cellules qui captent la lumi\u00e8re. Tu en demandais combien ?',en:'',ar:''},
    {fr:'Tu peux distinguer 10\u00a0000 odeurs. Tu n\u2019en as jamais demand\u00e9 une seule.',en:'',ar:''},
    {fr:'Une graine de tomate conna\u00eet la forme finale de la tomate. O\u00f9 est-elle \u00e9crite ?',en:'',ar:''},
    {fr:'La banane m\u00fbrit pile au moment o\u00f9 tu en as besoin. Et l\u2019emballage est inclus.',en:'',ar:''},
    {fr:'Le miel ne pourrit jamais. On en a trouv\u00e9 dans les pyramides, encore mangeable.',en:'',ar:''},
    {fr:'Mangue, fraise, ananas, past\u00e8que, datte, p\u00eache, raisin, figue, kiwi, grenade. Chacune un go\u00fbt unique. Pourquoi tant ? Personne ne t\u2019aurait fait de proc\u00e8s s\u2019il n\u2019y en avait qu\u2019un.',en:'',ar:''},
    {fr:'En ce moment, partout dans le monde, des hommes et des femmes m\u00e9morisent le Coran lettre par lettre \u2014 comme on le fait sans interruption depuis 14 si\u00e8cles. C\u2019est l\u2019un des miracles silencieux de l\u2019oumma.',en:'',ar:''},
    {fr:'\u00c0 Sana\u2019a, en 1972, des ouvriers ont trouv\u00e9 dans le plafond d\u2019une mosqu\u00e9e des manuscrits coraniques du 7e si\u00e8cle, oubli\u00e9s depuis mille ans. All\u00e2h pr\u00e9serve ce qu\u2019Il a choisi de pr\u00e9server.',en:'',ar:''}
  ],
  apresmidi: [
    {fr:'L\u2019ombre a tourn\u00e9 depuis ce matin. Remarque-la. Tout bouge sauf Celui qui fait bouger. Dis : Ya Hayy, Ya Qayyum.',en:'The shadow has shifted since morning. Notice it. Everything moves except the One who moves it.',ar:'\u062A\u064E\u062D\u064E\u0648\u0651\u064E\u0644\u064E \u0627\u0644\u0638\u0651\u0650\u0644\u0651\u064F \u0645\u064F\u0646\u0652\u0630\u064F \u0627\u0644\u0635\u0651\u064E\u0628\u0627\u062D. \u0644\u0627\u062D\u0650\u0638\u0652\u0647. \u0643\u064F\u0644\u0651\u064F \u0634\u064E\u064A\u0652\u0621\u064D \u064A\u064E\u062A\u064E\u062D\u064E\u0631\u0651\u064E\u0643\u064F \u0625\u0650\u0644\u0651\u0627 \u0645\u064F\u062D\u064E\u0631\u0651\u0650\u0643\u064E\u0647.'},
    {fr:'D\u00e9tourne le regard de ce que tu fais. Pas pour chercher. Pour recevoir ce qu\u2019Allah te montre.',en:'Look out the window. Not to search. To receive what Allah shows you.',ar:'\u0627\u0646\u0652\u0638\u064F\u0631\u0652 \u0645\u0650\u0646\u064E \u0627\u0644\u0646\u0651\u0627\u0641\u0650\u0630\u064E\u0629. \u0644\u064E\u064A\u0652\u0633\u064E \u0644\u0650\u062A\u064E\u0628\u0652\u062D\u064E\u062B. \u0644\u0650\u062A\u064E\u062A\u064E\u0644\u064E\u0642\u0651\u064E\u0649 \u0645\u0627 \u064A\u064F\u0631\u0650\u064A\u0643\u064E \u0627\u0644\u0644\u0651\u064E\u0647.'},
    {fr:'Ce que tu fais l\u00e0, maintenant \u2014 pour qui le fais-tu vraiment ? Recalibre.',en:'What you\u2019re doing right now \u2014 who are you truly doing it for? Recalibrate.',ar:'\u0645\u0627 \u062A\u064E\u0641\u0652\u0639\u064E\u0644\u064F\u0647\u064F \u0627\u0644\u0622\u0646 \u2014 \u0644\u0650\u0645\u064E\u0646\u0652 \u062D\u064E\u0642\u0651\u064B\u0627\u061F \u0623\u064E\u0639\u0650\u062F\u0652 \u0627\u0644\u0636\u0651\u064E\u0628\u0652\u0637.'},
    {fr:'Si tes parents sont en vie \u2014 ils vieillissent pendant que tu vis. Appelle. Ou juste dis : Rabbir hamhuma.',en:'Your parents age while you scroll. Call them. Or just say: Rabbir hamhuma.',ar:'\u0648\u0627\u0644\u0650\u062F\u0627\u0643\u064E \u064A\u064E\u0643\u0652\u0628\u064F\u0631\u0627\u0646\u0650 \u0648\u0623\u064E\u0646\u0652\u062A\u064E \u062A\u064E\u062A\u064E\u0635\u064E\u0641\u0651\u064E\u062D. \u0627\u062A\u0651\u064E\u0635\u0650\u0644\u0652. \u0623\u064E\u0648\u0652 \u0642\u064F\u0644: \u0631\u064E\u0628\u0651\u0650 \u0627\u0631\u0652\u062D\u064E\u0645\u0652\u0647\u064F\u0645\u0627.'},
    {fr:'Choisis un objet devant toi. Pense \u00e0 qui l\u2019a fabriqu\u00e9. Fais un dua pour cette personne.',en:'Pick an object in front of you. Think of who made it. Make du\u2019a for that person.',ar:'\u0627\u062E\u0652\u062A\u064E\u0631\u0652 \u0634\u064E\u064A\u0652\u0626\u064B\u0627 \u0623\u064E\u0645\u0627\u0645\u064E\u0643. \u0641\u064E\u0643\u0651\u0650\u0631\u0652 \u0641\u0650\u064A\u0645\u064E\u0646\u0652 \u0635\u064E\u0646\u064E\u0639\u064E\u0647. \u0627\u062F\u0652\u0639\u064F \u0644\u064E\u0647.'},
    {fr:'Quand tu marcheras ensuite \u2014 ralentis trois foul\u00e9es. Le Proph\u00e8te \uFDFA marchait avec s\u00e9r\u00e9nit\u00e9.',en:'Slow your pace. Just three steps in slow motion. The Prophet \uFDFA walked with serenity.',ar:'\u0623\u064E\u0628\u0652\u0637\u0650\u0626\u0652 \u062E\u064F\u0637\u0627\u0643. \u062B\u064E\u0644\u0627\u062B\u064F \u062E\u064F\u0637\u064F\u0648\u0627\u062A\u064D \u0628\u0650\u0628\u064F\u0637\u0652\u0621. \u0643\u0627\u0646\u064E \u0627\u0644\u0646\u0651\u064E\u0628\u0650\u064A\u0651\u064F \uFDFA \u064A\u064E\u0645\u0652\u0634\u0650\u064A \u0628\u0650\u0633\u064E\u0643\u0650\u064A\u0646\u064E\u0629.'},
    {fr:'SubhanAllah wa bihamdihi. Une phrase. Un arbre plant\u00e9 au Paradis. R\u00e9p\u00e8te-la sept fois.',en:'SubhanAllah wa bihamdihi. One phrase. A tree planted in Paradise. Repeat it as you walk.',ar:'\u0633\u064F\u0628\u0652\u062D\u0627\u0646\u064E \u0627\u0644\u0644\u0651\u064E\u0647 \u0648\u0628\u0650\u062D\u064E\u0645\u0652\u062F\u0650\u0647. \u062C\u064F\u0645\u0652\u0644\u064E\u0629\u064C \u0648\u0627\u062D\u0650\u062F\u064E\u0629. \u0634\u064E\u062C\u064E\u0631\u064E\u0629\u064C \u0641\u0650\u064A \u0627\u0644\u062C\u064E\u0646\u0651\u064E\u0629. \u0631\u064E\u062F\u0651\u0650\u062F\u0652\u0647\u0627 \u0648\u0623\u064E\u0646\u0652\u062A\u064E \u062A\u064E\u0645\u0652\u0634\u0650\u064A.'},
    {fr:'Expire lentement. Dis en toi : \u00ab Hasbiyallah. \u00bb Ce que tu portes n\u2019est pas \u00e0 toi seul.',en:'Exhale slowly. Say within: \u201cHasbiyallah.\u201d What you carry isn\u2019t yours alone.',ar:'\u0627\u0632\u0652\u0641\u0650\u0631\u0652 \u0628\u0650\u0628\u064F\u0637\u0652\u0621. \u0642\u064F\u0644\u0652 \u0641\u0650\u064A \u0646\u064E\u0641\u0652\u0633\u0650\u0643: \u00ab\u062D\u064E\u0633\u0652\u0628\u0650\u064A\u064E \u0627\u0644\u0644\u0651\u064E\u0647.\u00bb \u0645\u0627 \u062A\u064E\u062D\u0652\u0645\u0650\u0644\u064F\u0647 \u0644\u064E\u064A\u0652\u0633\u064E \u0644\u064E\u0643\u064E \u0648\u064E\u062D\u0652\u062F\u064E\u0643.'},
    {fr:'S\u2019il y a quelqu\u2019un pr\u00e8s de toi \u2014 imagine son dua le plus profond. Rejoins-le en silence.',en:'The person next to you \u2014 imagine their deepest du\u2019a. Join it silently.',ar:'\u0627\u0644\u0634\u0651\u064E\u062E\u0652\u0635\u064F \u0628\u0650\u062C\u0627\u0646\u0650\u0628\u0650\u0643 \u2014 \u062A\u064E\u062E\u064E\u064A\u0651\u064E\u0644\u0652 \u0623\u064E\u0639\u0652\u0645\u064E\u0642\u064E \u062F\u064F\u0639\u0627\u0626\u0650\u0647. \u0627\u0646\u0652\u0636\u064E\u0645\u0651\u064E \u0625\u0650\u0644\u064E\u064A\u0652\u0647\u0650 \u0628\u0650\u0635\u064E\u0645\u0652\u062A.'},
    {fr:'Al-Wadud. Le Tout-Aimant. Il t\u2019aime m\u00eame quand tu L\u2019oublies. Dis Son Nom trois fois.',en:'Al-Wadud. The Most Loving. He loves you even when you forget Him. Say His Name three times.',ar:'\u0627\u0644\u0648\u064E\u062F\u064F\u0648\u062F. \u064A\u064F\u062D\u0650\u0628\u0651\u064F\u0643\u064E \u062D\u064E\u062A\u0651\u064E\u0649 \u062D\u0650\u064A\u0646\u064E \u062A\u064E\u0646\u0652\u0633\u0627\u0647. \u0631\u064E\u062F\u0651\u0650\u062F\u0652 \u0627\u0633\u0652\u0645\u064E\u0647\u064F \u062B\u064E\u0644\u0627\u062B\u064B\u0627.'},
    {fr:'Si tu scrolles \u2014 pose le pouce 20 secondes. Le vide est permis.',en:'Your scrolling isn\u2019t feeding you. Rest your thumb 20 seconds. Emptiness is allowed.',ar:'\u062A\u064E\u0635\u064E\u0641\u0651\u064F\u062D\u064F\u0643\u064E \u0644\u0627 \u064A\u064F\u063A\u064E\u0630\u0651\u0650\u064A\u0643. \u0623\u064E\u0631\u0650\u062D\u0652 \u0625\u0650\u0628\u0652\u0647\u0627\u0645\u064E\u0643 \u0662\u0660 \u062B\u0627\u0646\u0650\u064A\u064E\u0629. \u0627\u0644\u0641\u064E\u0631\u0627\u063A\u064F \u0645\u064F\u0628\u0627\u062D.'},
    {fr:'\u00c9tire ton dos doucement. Allah a fait ton corps pour te servir, pas l\u2019inverse. Rends-lui justice.',en:'Pull your shoulders back. Your body carries your day \u2014 lighten it consciously.',ar:'\u0627\u0633\u0652\u062D\u064E\u0628\u0652 \u0643\u064E\u062A\u0650\u0641\u064E\u064A\u0652\u0643 \u0644\u0650\u0644\u062E\u064E\u0644\u0652\u0641. \u062C\u064E\u0633\u064E\u062F\u064F\u0643\u064E \u064A\u064E\u062D\u0652\u0645\u0650\u0644\u064F \u064A\u064E\u0648\u0652\u0645\u064E\u0643 \u2014 \u062E\u064E\u0641\u0651\u0650\u0641\u0652 \u0639\u064E\u0646\u0652\u0647\u064F \u0628\u0650\u0648\u064E\u0639\u0652\u064A.'},
    {fr:'Choisis une distraction et l\u00e2che-la. Une seule. C\u2019est le premier pas du sabr moderne.',en:'Close one tab. Just one. That\u2019s inner decluttering.',ar:'\u0623\u064E\u063A\u0652\u0644\u0650\u0642\u0652 \u062A\u064E\u0628\u0652\u0648\u064A\u0628\u064B\u0627 \u0648\u0627\u062D\u0650\u062F\u064B\u0627. \u0641\u064E\u0642\u064E\u0637 \u0648\u0627\u062D\u0650\u062F. \u0647\u0630\u0627 \u062A\u064E\u0631\u0652\u062A\u0650\u064A\u0628\u064C \u062F\u0627\u062E\u0650\u0644\u0650\u064A\u0651.'},
    {fr:'Si tu peux croiser un regard maintenant \u2014 fais-le. Un vrai. C\u2019est une ibadah oubli\u00e9e.',en:'Lift your head from the screen and meet a real gaze. That\u2019s a forgotten ibadah.',ar:'\u0627\u0631\u0652\u0641\u064E\u0639\u0652 \u0631\u064E\u0623\u0652\u0633\u064E\u0643\u064E \u0639\u064E\u0646\u0650 \u0627\u0644\u0634\u0651\u0627\u0634\u064E\u0629 \u0648\u0627\u0644\u0652\u0642\u064E \u0646\u064E\u0638\u0652\u0631\u064E\u0629\u064B \u062D\u064E\u0642\u0650\u064A\u0642\u0650\u064A\u0651\u064E\u0629. \u0639\u0650\u0628\u0627\u062F\u064E\u0629\u064C \u0645\u064E\u0646\u0652\u0633\u0650\u064A\u0651\u064E\u0629.'},
    {fr:'Pense \u00e0 quelqu\u2019un qui t\u2019a transmis quelque chose. Il ne sait pas qu\u2019il t\u2019a chang\u00e9. Fais dua pour lui.',en:'Think of your favorite teacher. They don\u2019t know they changed you. Make dua for them.',ar:'\u0641\u064E\u0643\u0651\u0650\u0631\u0652 \u0641\u0650\u064A \u0645\u064F\u0639\u064E\u0644\u0651\u0650\u0645\u0650\u0643\u064E \u0627\u0644\u0645\u064F\u0641\u064E\u0636\u0651\u064E\u0644. \u0644\u0627 \u064A\u064E\u0639\u0652\u0644\u064E\u0645\u064F \u0623\u064E\u0646\u0651\u064E\u0647\u064F \u063A\u064E\u064A\u0651\u064E\u0631\u064E\u0643. \u0627\u062F\u0652\u0639\u064F \u0644\u064E\u0647.'},
    {fr:'Tu as un toit, un si\u00e8ge, de l\u2019\u00e9lectricit\u00e9. Trois ni\u2019ma que tu n\u2019as pas demand\u00e9es. Dis Alhamdulillah pour les ni\u2019ma invisibles.',en:'You have a roof, a seat, electricity. Three blessings you didn\u2019t ask for.',ar:'\u0644\u064E\u062F\u064E\u064A\u0652\u0643\u064E \u0633\u064E\u0642\u0652\u0641\u064C \u0648\u0645\u064E\u0642\u0652\u0639\u064E\u062F\u064C \u0648\u0643\u064E\u0647\u0652\u0631\u064E\u0628\u0627\u0621. \u062B\u064E\u0644\u0627\u062B\u064F \u0646\u0650\u0639\u064E\u0645\u064D \u0644\u064E\u0645\u0652 \u062A\u064E\u0637\u0652\u0644\u064F\u0628\u0652\u0647\u0627.'},
    {fr:'L\u00e8ve les yeux. Le bleu du ciel cet apr\u00e8s-midi \u2014 une \u00e2ya parmi Ses \u00e2y\u00e2t. La cr\u00e9ation parle de Lui.',en:'Your eyes read these words \u2014 285 million people cannot see. Alhamdulillah.',ar:'\u0639\u064E\u064A\u0652\u0646\u0627\u0643\u064E \u062A\u064E\u0642\u0652\u0631\u064E\u0622\u0646\u0650 \u0647\u0630\u0627 \u2014 \u0662\u0668\u0665 \u0645\u0650\u0644\u064A\u0648\u0646 \u0644\u0627 \u064A\u064E\u0631\u064E\u0648\u0652\u0646. \u0627\u0644\u062D\u064E\u0645\u0652\u062F\u064F \u0644\u0650\u0644\u0651\u064E\u0647.'},
    {fr:'Si ton esprit s\u2019agite \u2014 pose une main sur le sol. Ram\u00e8ne-toi ici. La terre est immobile pour toi.',en:'Your mind is looping. Write one thought on paper \u2014 getting it out of your head is already relief.',ar:'\u0639\u064E\u0642\u0652\u0644\u064F\u0643\u064E \u064A\u064E\u062F\u064F\u0648\u0631\u064F. \u0627\u0643\u0652\u062A\u064F\u0628\u0652 \u0641\u0650\u0643\u0652\u0631\u064E\u0629\u064B \u0648\u0627\u062D\u0650\u062F\u064E\u0629\u064B \u0639\u064E\u0644\u064E\u0649 \u0648\u064E\u0631\u064E\u0642 \u2014 \u0625\u0650\u062E\u0652\u0631\u0627\u062C\u064F\u0647\u0627 \u0645\u0650\u0646\u0652 \u0631\u064E\u0623\u0652\u0633\u0650\u0643\u064E \u0631\u0627\u062D\u064E\u0629\u064C \u0628\u0650\u0630\u0627\u062A\u0650\u0647\u0627.'},
    {fr:'Si quelqu\u2019un ne t\u2019a pas r\u00e9pondu \u2014 avant de juger, peut-\u00eatre qu\u2019il porte plus lourd que toi.',en:'Someone didn\u2019t reply. Before judging \u2014 maybe they carry more than you.',ar:'\u0644\u064E\u0645\u0652 \u064A\u064E\u0631\u064F\u062F\u0651\u064E \u0639\u064E\u0644\u064E\u064A\u0652\u0643 \u0623\u064E\u062D\u064E\u062F. \u0642\u064E\u0628\u0652\u0644\u064E \u0627\u0644\u062D\u064F\u0643\u0652\u0645 \u2014 \u0631\u064F\u0628\u0651\u064E\u0645\u0627 \u064A\u064E\u062D\u0652\u0645\u0650\u0644\u064F \u0623\u064E\u062B\u0652\u0642\u064E\u0644\u064E \u0645\u0650\u0646\u0652\u0643.'},
    {fr:'Sourate Al-\u2018Asr : l\u2019homme est en perte, sauf ceux qui s\u2019exhortent \u00e0 la patience. Relis-la en toi. Bismillah\u2026 Wal-\u2018Asr\u2026',en:'Surah Al-\u2018Asr: mankind is in loss, except those who counsel patience. Recite it within.',ar:'\u0633\u064F\u0648\u0631\u064E\u0629\u064F \u0627\u0644\u0639\u064E\u0635\u0652\u0631: \u0627\u0644\u0625\u0650\u0646\u0652\u0633\u0627\u0646\u064E \u0641\u0650\u064A \u062E\u064F\u0633\u0652\u0631\u060C \u0625\u0650\u0644\u0651\u0627 \u0627\u0644\u0651\u064E\u0630\u0650\u064A\u0646\u064E \u062A\u064E\u0648\u0627\u0635\u064E\u0648\u0652\u0627 \u0628\u0650\u0627\u0644\u0635\u0651\u064E\u0628\u0652\u0631. \u0623\u064E\u0639\u0650\u062F\u0652\u0647\u0627 \u0641\u0650\u064A \u0646\u064E\u0641\u0652\u0633\u0650\u0643.'},
    {fr:'La Terre est \u00e0 149 600 000 km du Soleil. Une fen\u00eatre de 5%. Plus pr\u00e8s, on grille. Plus loin, on g\u00e8le. Le hasard ne vise pas une fen\u00eatre. Quelqu\u2019un t\u2019a fait place.',en:'',ar:''},
    {fr:'La Terre tourne \u00e0 1 670 km/h \u00e0 l\u2019\u00e9quateur. Si elle tournait beaucoup plus vite, les vents seraient destructeurs et tu p\u00e8serais moins. Plus lentement, les jours seraient br\u00fblants et les nuits glaciales. La vitesse choisie te laisse vivre. Quelqu\u2019un a r\u00e9gl\u00e9 le tour.',en:'',ar:''},
    {fr:'Toutes les esp\u00e8ces vivantes utilisent le M\u00caME code g\u00e9n\u00e9tique : 4 lettres, 64 mots. Une seule grammaire pour tout le vivant. La bact\u00e9rie, l\u2019arbre, toi \u2014 m\u00eame alphabet. Qui a \u00e9crit la grammaire ?',en:'',ar:''},
    {fr:'\u00c0 chaque inspiration, tu absorbes 25 000 milliards de mol\u00e9cules d\u2019oxyg\u00e8ne. Chacune fabriqu\u00e9e par un arbre que tu n\u2019as jamais rencontr\u00e9. All\u00e2h nourrit ton souffle par un inconnu.',en:'',ar:''},
    {fr:'Pendant cette seconde, ton corps a fait 100 000 r\u00e9actions chimiques. Tu n\u2019en as command\u00e9 aucune. Tu es un orchestre qui joue parfaitement \u2014 alors que tu ne le diriges pas. Le Chef est ailleurs.',en:'',ar:''},
    {fr:'Sur 8 milliards d\u2019humains, ton iris est unique. Ton visage est unique. Tes empreintes sont uniques. Le hasard ne signe pas 8 milliards de fois sans se r\u00e9p\u00e9ter. All\u00e2h, oui.',en:'',ar:''},
    {fr:'Pour qu\u2019une cellule fonctionne, il faut 250 prot\u00e9ines minimum, chacune correctement pli\u00e9e. Probabilit\u00e9 par hasard : 1 sur 10^85 000. Plus que d\u2019atomes dans l\u2019univers visible. Le hasard a renonc\u00e9. Pas Lui.',en:'',ar:''},
    {fr:'Si on tirait au hasard parmi tous les arrangements possibles d\u2019atomes, la probabilit\u00e9 d\u2019obtenir ne serait-ce qu\u2019une fourmi fonctionnelle est statistiquement nulle. Et tu vois des fourmis tous les jours. La nullit\u00e9 statistique est un miracle quotidien.',en:'',ar:''},
    {fr:'G\u00e9ologie du 20\u00e8me si\u00e8cle : la majorit\u00e9 des grands fleuves naissent dans la fonte des glaciers \u2014 les sommets neigeux nourrissent la terre. Le Coran \u00e9voque ces eaux abondantes que Nous faisons descendre des nu\u00e9es (Coran 78:14). Ce que la science explique aujourd\u2019hui, le Coran l\u2019\u00e9voquait il y a 14 si\u00e8cles.',en:'',ar:''},
    {fr:'Tu peux te demander \u00ab pourquoi suis-je ici ? \u00bb. Un caillou ne le fera jamais. Cette question seule te place ailleurs que dans la mati\u00e8re. La question est la preuve que tu n\u2019es pas seulement mati\u00e8re.',en:'',ar:''},
    {fr:'Tu lis ces mots. Ce sont des lignes noires sur un fond clair. Et pourtant, \u00e0 l\u2019int\u00e9rieur de toi, elles produisent un sens, parfois une \u00e9motion, parfois une d\u00e9cision. La compr\u00e9hension elle-m\u00eame est un miracle. All\u00e2h enseigne par le calame. (Coran 96:4)',en:'',ar:''},
    {fr:'Tu te crois trop loin pour revenir ? All\u00e2h dit : \u00ab Si Mon serviteur s\u2019approche de Moi d\u2019un empan, Je M\u2019approche de lui d\u2019une coud\u00e9e. S\u2019il vient \u00e0 Moi en marchant, Je viens \u00e0 lui en courant. \u00bb Tu n\u2019as qu\u2019un pas \u00e0 faire. Le reste, Il le couvre.',en:'',ar:''},
    {fr:'Tu as honte de revenir ? Plus tu reviens souvent, plus Il se r\u00e9jouit. Le Proph\u00e8te \uFDFA a dit : \u00ab All\u00e2h se r\u00e9jouit du retour de Son serviteur plus qu\u2019un homme qui retrouve sa monture perdue dans le d\u00e9sert. \u00bb Tu ne L\u2019ennuies pas. Tu Le combles.',en:'',ar:''},
    {fr:'Un homme s\u2019arr\u00eate sous un arbre pour se reposer une heure. Va-t-il construire une maison sous cet arbre ? Va-t-il s\u2019inqui\u00e9ter de la peinture du tronc ? Ce monde est cet arbre. Tu n\u2019es l\u00e0 que pour le repos.',en:'',ar:''},
    {fr:'Un homme entre dans un jardin et arrache toutes les fleurs pour les mettre dans son salon. Trois jours plus tard, elles sont fan\u00e9es. Celui qui les a laiss\u00e9es en place les voit fleurir 6 mois. Le monde se savoure debout, pas arrach\u00e9.',en:'',ar:''},
    {fr:'Un voyageur dans le d\u00e9sert garde son eau pr\u00e9cieuse pour la fin du voyage. Un autre la boit en entier d\u00e8s le premier jour. Lequel arrive ? Tes ann\u00e9es sont cette eau. Tes pri\u00e8res sont la rationing.',en:'',ar:''},
    {fr:'Une bougie \u00e9claire une autre bougie sans rien perdre de sa propre flamme. Donner du bien \u00e0 autrui ne te diminue pas. All\u00e2h a invent\u00e9 cette physique-l\u00e0 sp\u00e9cialement pour Ses serviteurs.',en:'',ar:''},
    {fr:'Un homme re\u00e7oit 1000 dinars en or. Il en perd 1 dans la rue. Il passe la journ\u00e9e \u00e0 le chercher en oubliant les 999 qu\u2019il a. Tu as 1000 ni\u2019ma. Tu te plains de la seule qui manque.',en:'',ar:''},
    {fr:'Un homme regarde un puzzle dans le d\u00e9sordre. Il dit : \u00ab C\u2019est laid. \u00bb L\u2019autre homme conna\u00eet l\u2019image finale et patiente. All\u00e2h voit le puzzle assembl\u00e9. Toi tu vois les pi\u00e8ces. Aie confiance dans l\u2019image qu\u2019Il a en t\u00eate.',en:'',ar:''},
    {fr:'Tu te l\u00e8ves pour prier malgr\u00e9 la fatigue. All\u00e2h sait l\u2019effort que \u00e7a co\u00fbte aujourd\u2019hui. Et Il le compte diff\u00e9remment.',en:'',ar:''},
    {fr:'Tu n\u2019as accompli aucune \u0153uvre extraordinaire aujourd\u2019hui. All\u00e2h aime quand m\u00eame. Son amour n\u2019est pas conditionn\u00e9 par tes r\u00e9sultats.',en:'',ar:''},
    {fr:'Tu marches sereinement. Quelqu\u2019un, ailleurs, marche sous les bombes. Ton apparente normalit\u00e9 est une gr\u00e2ce. Ne la consomme pas \u2014 partage-la en dua.',en:'',ar:''},
    {fr:'Un musulman a \u00e9t\u00e9 humili\u00e9 aujourd\u2019hui dans le monde. Tu n\u2019as rien vu. Mais All\u00e2h a tout vu. Le compte des humiliations est tenu \u2014 et la justice viendra. Patience pour eux. Patience pour nous.',en:'',ar:''},
    {fr:'\u00c0 cet instant, en Asie, c\u2019est d\u00e9j\u00e0 la nuit. Quelqu\u2019un, l\u00e0-bas, a fini sa journ\u00e9e et fait dua. All\u00e2h entend simultan\u00e9ment ta plage et la sienne. Le temps ne L\u2019arr\u00eate pas.',en:'',ar:''},
    {fr:'Pendant cette plage de l\u2019Asr, des centaines de millions de musulmans se pr\u00e9parent \u00e0 prier. Tous ensemble. Un seul Seigneur. Sans coordination. Sans calendrier partag\u00e9. Juste l\u2019appel.',en:'',ar:''},
    {fr:'Quelque part dans le monde, \u00e0 cet instant, un imam m\u00e9morise son 1 000\u00e8me verset du Coran. Un autre vient d\u2019achever le sien. La hifz (m\u00e9morisation) ne s\u2019arr\u00eate jamais. Le Livre reste vivant par c\u0153ur.',en:'',ar:''},
    {fr:'Pendant cette heure, des milliers de musulmans se sont convertis dans le monde. L\u2019islam grandit pendant que tu doutes. Ta foi est jeune dans une oumma qui s\u2019agrandit.',en:'',ar:''},
    {fr:'Le Proph\u00e8te \uFDFA a dit : \u00ab L\u2019Heure ne viendra pas tant que la science ne dispara\u00eetra et que l\u2019ignorance n\u2019appara\u00eetra. \u00bb Aujourd\u2019hui, l\u2019information est partout. La sagesse, moins. M\u00e9dite cela \u2014 et choisis quel c\u00f4t\u00e9 tu nourris.',en:'',ar:''},
    {fr:'L\u2019abeille danse pour expliquer o\u00f9 sont les fleurs. Qui lui a appris la g\u00e9om\u00e9trie ?',en:'',ar:''},
    {fr:'Le sang coagule pile quand tu te coupes. Pas avant. Pas apr\u00e8s. Qui r\u00e8gle l\u2019horloge ?',en:'',ar:''},
    {fr:'Un saumon n\u00e9 dans une rivi\u00e8re retrouve la m\u00eame rivi\u00e8re des ann\u00e9es plus tard. Avec quel GPS ?',en:'',ar:''},
    {fr:'Tu marches sur une boule en suspension dans le vide. Tu ne tombes pas. Personne ne t\u2019a expliqu\u00e9 pourquoi.',en:'',ar:''},
    {fr:'Une pomme tombe. Newton a vu une loi. Avant lui, qui avait fait tenir les pommes ?',en:'',ar:''},
    {fr:'Quand tu t\u2019orientes vers la Mecque pour prier \u2014 un milliard d\u2019\u00eatres humains font le m\u00eame geste, vers le m\u00eame point, depuis 14 si\u00e8cles. Aucune religion n\u2019a connu cette pr\u00e9cision g\u00e9ographique.',en:'',ar:''},
    {fr:'En quelques si\u00e8cles, l\u2019arabe est devenu la langue de la science mondiale \u2014 m\u00e9decine, astronomie, math\u00e9matiques. Les chiffres que tu utilises aujourd\u2019hui pour faire tes comptes sont pass\u00e9s par Bagdad.',en:'',ar:''}
  ],
  soir: [
    {fr:'Quand tu rentres ce soir \u2014 laisse derri\u00e8re toi le personnage du jour. Entre comme toi.',en:'As you walk through your door tonight, leave behind the character of the day. Enter as yourself.',ar:'\u0639\u0650\u0646\u0652\u062F\u064E \u062F\u064F\u062E\u064F\u0648\u0644\u0650\u0643 \u0627\u0644\u0644\u0651\u064E\u064A\u0652\u0644\u064E\u0629\u060C \u0627\u062A\u0652\u0631\u064F\u0643\u0652 \u0634\u064E\u062E\u0652\u0635\u0650\u064A\u0651\u064E\u0629\u064E \u0627\u0644\u0646\u0651\u064E\u0647\u0627\u0631 \u062E\u064E\u0644\u0652\u0641\u064E\u0643. \u0627\u062F\u0652\u062E\u064F\u0644\u0652 \u0643\u064E\u0645\u0627 \u0623\u064E\u0646\u0652\u062A.'},
    {fr:'Assieds-toi. Ne fais rien. 30 secondes de d\u00e9compression sacr\u00e9e avant de parler \u00e0 quiconque.',en:'Sit down. Do nothing. 30 seconds of sacred decompression before speaking to anyone.',ar:'\u0627\u062C\u0652\u0644\u0650\u0633. \u0644\u0627 \u062A\u064E\u0641\u0652\u0639\u064E\u0644\u0652 \u0634\u064E\u064A\u0652\u0626\u064B\u0627. \u0663\u0660 \u062B\u0627\u0646\u0650\u064A\u064E\u0629 \u0645\u064F\u0642\u064E\u062F\u0651\u064E\u0633\u064E\u0629 \u0642\u064E\u0628\u0652\u0644\u064E \u0623\u064E\u0646\u0652 \u062A\u064F\u0643\u064E\u0644\u0651\u0650\u0645\u064E \u0623\u064E\u062D\u064E\u062F\u064B\u0627.'},
    {fr:'Ta journ\u00e9e a eu un moment o\u00f9 Allah t\u2019a port\u00e9 sans que tu le voies. Lequel ?',en:'Your day had a moment where Allah carried you without you seeing. Which one?',ar:'\u0643\u0627\u0646\u064E \u0641\u0650\u064A \u064A\u064E\u0648\u0652\u0645\u0650\u0643 \u0644\u064E\u062D\u0652\u0638\u064E\u0629\u064C \u062D\u064E\u0645\u064E\u0644\u064E\u0643\u064E \u0641\u0650\u064A\u0647\u0627 \u0627\u0644\u0644\u0651\u064E\u0647 \u062F\u064F\u0648\u0646\u064E \u0623\u064E\u0646\u0652 \u062A\u064E\u0631\u064E\u0649. \u0623\u064E\u064A\u0651\u064F\u0647\u0627\u061F'},
    {fr:'Quelqu\u2019un a peut-\u00eatre \u00e9t\u00e9 patient avec toi aujourd\u2019hui sans que tu le remarques. Pense \u00e0 lui.',en:'Someone was patient with you today. You may not have noticed. Think of them.',ar:'\u0643\u0627\u0646\u064E \u0623\u064E\u062D\u064E\u062F\u064C \u0635\u0627\u0628\u0650\u0631\u064B\u0627 \u0645\u064E\u0639\u064E\u0643 \u0627\u0644\u064A\u064E\u0648\u0652\u0645. \u0631\u064F\u0628\u0651\u064E\u0645\u0627 \u0644\u064E\u0645\u0652 \u062A\u064E\u0646\u0652\u062A\u064E\u0628\u0650\u0647. \u0641\u064E\u0643\u0651\u0650\u0631\u0652 \u0641\u0650\u064A\u0647.'},
    {fr:'Ton corps t\u2019a servi toute la journ\u00e9e sans se plaindre. Remercie chaque organe en silence.',en:'Your body served you all day without complaint. Thank each organ in silence.',ar:'\u062E\u064E\u062F\u064E\u0645\u064E\u0643 \u062C\u064E\u0633\u064E\u062F\u064F\u0643 \u0637\u064E\u0648\u0627\u0644\u064E \u0627\u0644\u064A\u064E\u0648\u0652\u0645 \u062F\u064F\u0648\u0646\u064E \u0634\u064E\u0643\u0652\u0648\u064E\u0649. \u0627\u0634\u0652\u0643\u064F\u0631\u0652 \u0643\u064F\u0644\u0651\u064E \u0639\u064F\u0636\u0652\u0648\u064D \u0628\u0650\u0635\u064E\u0645\u0652\u062A.'},
    {fr:'S\u2019il y a une parole que tu regrettes aujourd\u2019hui \u2014 dis Astaghfirullah pour elle.',en:'There\u2019s a word you said today that you regret. Say Astaghfirullah for it.',ar:'\u0647\u064F\u0646\u0627\u0643\u064E \u0643\u064E\u0644\u0650\u0645\u064E\u0629\u064C \u0642\u064F\u0644\u0652\u062A\u064E\u0647\u0627 \u0648\u062A\u064E\u0646\u0652\u062F\u064E\u0645\u064F. \u0642\u064F\u0644\u0652 \u0623\u064E\u0633\u0652\u062A\u064E\u063A\u0652\u0641\u0650\u0631\u064F \u0627\u0644\u0644\u0651\u064E\u0647 \u0639\u064E\u0644\u064E\u064A\u0652\u0647\u0627.'},
    {fr:'Avant de prendre ton t\u00e9l\u00e9phone ce soir \u2014 si quelqu\u2019un que tu aimes est pr\u00e8s de toi, touche son front.',en:'Before touching your phone tonight, touch the forehead of someone you love.',ar:'\u0642\u064E\u0628\u0652\u0644\u064E \u0623\u064E\u0646\u0652 \u062A\u064E\u0644\u0652\u0645\u064E\u0633\u064E \u0647\u0627\u062A\u0650\u0641\u064E\u0643 \u0627\u0644\u0644\u0651\u064E\u064A\u0652\u0644\u064E\u0629\u060C \u0627\u0644\u0652\u0645\u0650\u0633\u0652 \u062C\u064E\u0628\u0650\u064A\u0646\u064E \u0645\u064E\u0646\u0652 \u062A\u064F\u062D\u0650\u0628\u0651.'},
    {fr:'Al-Ghafur. Le Pardonneur. Il efface m\u00eame ce que tu n\u2019oses pas nommer. Respire Son Nom.',en:'Al-Ghafur. The Forgiving. He erases even what you dare not name. Breathe His Name.',ar:'\u0627\u0644\u063A\u064E\u0641\u064F\u0648\u0631. \u064A\u064E\u0645\u0652\u062D\u064F\u0648 \u062D\u064E\u062A\u0651\u064E\u0649 \u0645\u0627 \u0644\u0627 \u062A\u064E\u062C\u0652\u0631\u064F\u0624\u064F \u0639\u064E\u0644\u064E\u0649 \u062A\u064E\u0633\u0652\u0645\u0650\u064A\u064E\u062A\u0650\u0647. \u062A\u064E\u0646\u064E\u0641\u0651\u064E\u0633\u0652 \u0627\u0633\u0652\u0645\u064E\u0647.'},
    {fr:'Cette journ\u00e9e est termin\u00e9e. Tu ne la revivras plus. Qu\u2019en gardes-tu pour l\u2019\u00e9ternit\u00e9 ? Dis Astaghfirullah pour ce qui doit \u00eatre effac\u00e9.',en:'This day is over. You\u2019ll never live it again. What do you keep for eternity?',ar:'\u0627\u0646\u0652\u062A\u064E\u0647\u064E\u0649 \u0647\u0630\u0627 \u0627\u0644\u064A\u064E\u0648\u0652\u0645. \u0644\u064E\u0646\u0652 \u064A\u064E\u0639\u064F\u0648\u062F. \u0645\u0627\u0630\u0627 \u062A\u064E\u062D\u0652\u0641\u064E\u0638\u064F \u0645\u0650\u0646\u0652\u0647\u064F \u0644\u0650\u0644\u0623\u064E\u0628\u064E\u062F\u061F'},
    {fr:'Ce soir tu es en vie. Demain n\u2019est promis \u00e0 personne. Souris \u00e0 cette \u00e9vidence \u2014 et dis Alhamdulillah qui m\u2019a fait vivre ce jour.',en:'Tonight you are alive. Tomorrow is promised to no one. Smile at this truth.',ar:'\u0627\u0644\u0644\u0651\u064E\u064A\u0652\u0644\u064E\u0629\u064E \u0623\u064E\u0646\u0652\u062A\u064E \u062D\u064E\u064A\u0651. \u063A\u064E\u062F\u064B\u0627 \u0644\u064E\u064A\u0652\u0633\u064E \u0645\u064E\u0648\u0652\u0639\u064F\u0648\u062F\u064B\u0627 \u0644\u0650\u0623\u064E\u062D\u064E\u062F. \u0627\u0628\u0652\u062A\u064E\u0633\u0650\u0645\u0652 \u0644\u0650\u0647\u0630\u0650\u0647\u0650 \u0627\u0644\u062D\u064E\u0642\u0650\u064A\u0642\u064E\u0629.'},
    {fr:'Quand tu enl\u00e8veras tes chaussures \u2014 fais-le lentement. Chaque geste conscient est une pri\u00e8re silencieuse.',en:'Take off your shoes slowly. Every conscious gesture is a silent prayer.',ar:'\u0627\u062E\u0652\u0644\u064E\u0639\u0652 \u062D\u0650\u0630\u0627\u0621\u064E\u0643\u064E \u0628\u0650\u0628\u064F\u0637\u0652\u0621. \u0643\u064F\u0644\u0651\u064F \u062D\u064E\u0631\u064E\u0643\u064E\u0629\u064D \u0648\u0627\u0639\u0650\u064A\u064E\u0629\u064D \u0635\u064E\u0644\u0627\u0629\u064C \u0635\u0627\u0645\u0650\u062A\u064E\u0629.'},
    {fr:'Quand tu te laveras ce soir \u2014 imagine l\u2019eau emporter la fatigue. C\u2019est un ghusl de l\u2019\u00e2me.',en:'Tonight\u2019s shower \u2014 imagine the water washing away fatigue. A ghusl of the soul.',ar:'\u062F\u064F\u0634\u064F \u0627\u0644\u0644\u0651\u064E\u064A\u0652\u0644\u064E\u0629 \u2014 \u062A\u064E\u062E\u064E\u064A\u0651\u064E\u0644\u0650 \u0627\u0644\u0645\u0627\u0621\u064E \u064A\u064E\u062C\u0652\u0631\u0650\u0641\u064F \u0627\u0644\u062A\u0651\u064E\u0639\u064E\u0628. \u063A\u064F\u0633\u0652\u0644\u064C \u0644\u0650\u0644\u0631\u0651\u064F\u0648\u062D.'},
    {fr:'Ne r\u00e9ponds \u00e0 aucun message pendant 5 minutes. Le silence du soir est un droit.',en:'Don\u2019t reply to any message for 5 minutes. Evening silence is a right.',ar:'\u0644\u0627 \u062A\u064E\u0631\u064F\u062F\u0651\u064E \u0639\u064E\u0644\u064E\u0649 \u0623\u064E\u064A\u0651\u0650 \u0631\u0650\u0633\u0627\u0644\u064E\u0629\u064D \u0665 \u062F\u064E\u0642\u0627\u0626\u0650\u0642. \u0633\u064F\u0643\u064F\u0648\u0646\u064F \u0627\u0644\u0645\u064E\u0633\u0627\u0621 \u062D\u064E\u0642\u0651.'},
    {fr:'Si quelqu\u2019un est avec toi ce soir \u2014 demande-lui : \u00ab Comment tu vas vraiment ? \u00bb Et \u00e9coute jusqu\u2019au bout.',en:'Ask someone at home: \u201cHow are you really?\u201d \u2014 and listen to the end.',ar:'\u0627\u0633\u0652\u0623\u064E\u0644\u0652 \u0623\u064E\u062D\u064E\u062F\u064B\u0627 \u0641\u0650\u064A \u0628\u064E\u064A\u0652\u062A\u0650\u0643: \u00ab\u0643\u064E\u064A\u0652\u0641\u064E \u062D\u0627\u0644\u064F\u0643\u064E \u062D\u064E\u0642\u0651\u064B\u0627\u061F\u00bb \u2014 \u0648\u0627\u0633\u0652\u0645\u064E\u0639\u0652 \u062D\u064E\u062A\u0651\u064E\u0649 \u0627\u0644\u0646\u0651\u0650\u0647\u0627\u064A\u064E\u0629.'},
    {fr:'Si quelqu\u2019un est pr\u00e8s de toi \u2014 pose ta main sur son \u00e9paule sans parler. Le toucher dit ce que les mots ne peuvent pas.',en:'Place your hand on someone\u2019s shoulder without speaking. Touch says what words cannot.',ar:'\u0636\u064E\u0639\u0652 \u064A\u064E\u062F\u064E\u0643\u064E \u0639\u064E\u0644\u064E\u0649 \u0643\u064E\u062A\u0650\u0641\u0650 \u0623\u064E\u062D\u064E\u062F\u064D \u062F\u064F\u0648\u0646\u064E \u0643\u064E\u0644\u0627\u0645. \u0627\u0644\u0644\u0651\u064E\u0645\u0652\u0633\u064F \u064A\u064E\u0642\u064F\u0648\u0644\u064F \u0645\u0627 \u0644\u0627 \u062A\u064E\u0642\u064F\u0648\u0644\u064F\u0647\u064F \u0627\u0644\u0643\u064E\u0644\u0650\u0645\u0627\u062A.'},
    {fr:'Tu as travers\u00e9 une journ\u00e9e de plus. Pose ta main droite sur ton c\u0153ur et dis Alhamdulillah.',en:'You made it home safe. Thousands didn\u2019t make it back tonight. Alhamdulillah.',ar:'\u0639\u064F\u062F\u0652\u062A\u064E \u0633\u0627\u0644\u0650\u0645\u064B\u0627. \u0622\u0644\u0627\u0641\u064C \u0644\u064E\u0645\u0652 \u064A\u064E\u0639\u064F\u0648\u062F\u064F\u0648\u0627 \u0627\u0644\u0644\u0651\u064E\u064A\u0652\u0644\u064E\u0629. \u0627\u0644\u062D\u064E\u0645\u0652\u062F\u064F \u0644\u0650\u0644\u0651\u064E\u0647.'},
    {fr:'Le repas du soir est pr\u00eat \u2014 ou tu peux le pr\u00e9parer. Les deux sont des ni\u2019ma.',en:'Dinner is ready \u2014 or you can make it. Both are blessings.',ar:'\u0639\u064E\u0634\u0627\u0624\u064F\u0643\u064E \u062C\u0627\u0647\u0650\u0632\u064C \u2014 \u0623\u064E\u0648\u0652 \u062A\u064E\u0633\u0652\u062A\u064E\u0637\u0650\u064A\u0639\u064F \u0625\u0650\u0639\u0652\u062F\u0627\u062F\u064E\u0647. \u0643\u0650\u0644\u0627\u0647\u064F\u0645\u0627 \u0646\u0650\u0639\u0652\u0645\u064E\u0629.'},
    {fr:'On n\u2019est pas toujours sa meilleure version. C\u2019est humain. Demain est une page blanche.',en:'You weren\u2019t your best self today. That\u2019s human. Tomorrow is a blank page.',ar:'\u0644\u064E\u0645\u0652 \u062A\u064E\u0643\u064F\u0646\u0652 \u0623\u064E\u0641\u0652\u0636\u064E\u0644\u064E \u0646\u064F\u0633\u0652\u062E\u064E\u0629\u064D \u0645\u0650\u0646\u0652\u0643\u064E \u0627\u0644\u064A\u064E\u0648\u0652\u0645. \u0647\u0630\u0627 \u0625\u0650\u0646\u0652\u0633\u0627\u0646\u0650\u064A\u0651. \u063A\u064E\u062F\u064B\u0627 \u0635\u064E\u0641\u0652\u062D\u064E\u0629\u064C \u0628\u064E\u064A\u0652\u0636\u0627\u0621.'},
    {fr:'Si tu portes une montre \u2014 enl\u00e8ve-la. Tu n\u2019as plus besoin de l\u2019heure. Le soir t\u2019appartient d\u00e9j\u00e0.',en:'Take off your watch. You don\u2019t need the time anymore. The evening is already yours.',ar:'\u0627\u062E\u0652\u0644\u064E\u0639\u0652 \u0633\u0627\u0639\u064E\u062A\u064E\u0643. \u0644\u064E\u0645\u0652 \u062A\u064E\u0639\u064F\u062F\u0652 \u0628\u0650\u062D\u0627\u062C\u064E\u0629\u064D \u0644\u0650\u0644\u0648\u064E\u0642\u0652\u062A. \u0627\u0644\u0645\u064E\u0633\u0627\u0621\u064F \u0644\u064E\u0643\u064E \u0628\u0650\u0627\u0644\u0641\u0650\u0639\u0652\u0644.'},
    {fr:'Le Proph\u00e8te \uFDFA rentrait chez lui en servant sa famille. Le foyer est une ibadah, pas un repos.',en:'The Prophet \uFDFA came home to serve his family. Home is ibadah, not just rest.',ar:'\u0627\u0644\u0646\u0651\u064E\u0628\u0650\u064A\u0651\u064F \uFDFA \u0643\u0627\u0646\u064E \u064A\u064E\u0639\u064F\u0648\u062F\u064F \u0644\u0650\u064A\u064E\u062E\u0652\u062F\u064F\u0645\u064E \u0623\u064E\u0647\u0652\u0644\u064E\u0647. \u0627\u0644\u0628\u064E\u064A\u0652\u062A\u064F \u0639\u0650\u0628\u0627\u062F\u064E\u0629\u060C \u0644\u0627 \u0631\u0627\u062D\u064E\u0629\u064C \u0641\u064E\u0642\u064E\u0637.'},
    {fr:'Une larme contient sels, prot\u00e9ines, enzymes \u2014 composition diff\u00e9rente selon ton \u00e9motion. Ton corps \u00e9crit ta tristesse en chimie. All\u00e2h a inscrit un langage jusque dans tes pleurs.',en:'',ar:''},
    {fr:'Cette nuit, 3 millions de cellules vont mourir et 3 millions vont na\u00eetre en toi. Tu changes sans t\u2019en apercevoir. Tu n\u2019es pas ton corps \u2014 tu es ce qui le traverse. Et Lui te tient \u00e0 travers les changements.',en:'',ar:''},
    {fr:'En 1931, Kurt G\u00f6del a prouv\u00e9 math\u00e9matiquement qu\u2019il existe des v\u00e9rit\u00e9s vraies qu\u2019on ne peut PAS prouver de l\u2019int\u00e9rieur du syst\u00e8me. La science elle-m\u00eame reconna\u00eet un dehors qu\u2019elle ne peut pas atteindre. Ce dehors a un Nom.',en:'',ar:''},
    {fr:'Le Coran d\u00e9crit la lune comme \u00ab lumi\u00e8re r\u00e9fl\u00e9chie \u00bb (n\u00fbr) et le soleil comme \u00ab lampe \u00bb (sir\u00e2j). Distinction confirm\u00e9e 1000 ans plus tard : la lune ne produit pas de lumi\u00e8re, le soleil oui. (Coran 71:16)',en:'',ar:''},
    {fr:'Le mot \u00ab jour \u00bb appara\u00eet 365 fois dans le Coran. Le mot \u00ab mois \u00bb exactement 12 fois. Le mot \u00ab ciel \u00bb exactement 7 fois. Statistiquement, ce n\u2019est pas du hasard.',en:'',ar:''},
    {fr:'Tu reconnais la voix de ta m\u00e8re parmi des milliers en moins d\u2019une seconde. Aucun ordinateur au monde ne sait faire \u00e7a. Toi, sans r\u00e9fl\u00e9chir. Celui qui t\u2019a fait t\u2019a fait pour aimer.',en:'',ar:''},
    {fr:'Tu peux fermer les yeux et te souvenir du visage de ton p\u00e8re. Cette image n\u2019existe nulle part dans le monde physique \u2014 seulement en toi. Qui la garde quand tu n\u2019y penses pas ?',en:'',ar:''},
    {fr:'Tu pleures quand quelqu\u2019un que tu n\u2019as jamais rencontr\u00e9 meurt. Aucun int\u00e9r\u00eat biologique. Aucune logique \u00e9volutive. C\u2019est gratuit. C\u2019est humain. C\u2019est signe que ton c\u0153ur ne vient pas seulement de la mati\u00e8re.',en:'',ar:''},
    {fr:'Tu rentres chez toi ce soir et ton cerveau sait, sans calcul, o\u00f9 est \u00ab chez toi \u00bb. Qui a inscrit ce chemin en toi ? Qui a invent\u00e9 l\u2019id\u00e9e m\u00eame de chez-soi ?',en:'',ar:''},
    {fr:'Tu ressens l\u2019amour. Une \u00e9motion qui change ta chimie, ralentit ton c\u0153ur, t\u2019emp\u00eache de manger. Une chose qui p\u00e8se plus lourd que la mati\u00e8re. Qui a plac\u00e9 ce poids dans le vide ?',en:'',ar:''},
    {fr:'Tu portes une faute que tu n\u2019as dite \u00e0 personne ? Elle ne sortira pas de Lui non plus. Le sitr \u2014 la protection de la pudeur \u2014 est l\u2019un de Ses Noms cach\u00e9s. Ce que tu Lui confies reste avec Lui.',en:'',ar:''},
    {fr:'\u00ab La vie d\u2019ici-bas n\u2019est que jeu et divertissement. La demeure derni\u00e8re est meilleure pour ceux qui pratiquent la pi\u00e9t\u00e9. \u00bb (Coran 6:32) Tu joues \u00e0 un jeu qui finit. Pendant que tu joues, l\u2019\u00e9ternit\u00e9 s\u2019\u00e9crit.',en:'',ar:''},
    {fr:'Tu traverses un pont. Tu ne demandes pas au pont d\u2019\u00eatre beau, confortable, durable. Tu lui demandes juste de tenir le temps de passer. Ce monde est ce pont. Pas plus.',en:'',ar:''},
    {fr:'Le riche meurt \u00e0 80 ans. Le pauvre meurt \u00e0 80 ans. Sous terre, ils ont la m\u00eame taille. Au-dessous de cette ligne, rien ne distingue le palais de la cabane.',en:'',ar:''},
    {fr:'Un enfant pleure parce que son p\u00e8re lui retire un couteau. L\u2019enfant croit qu\u2019on lui veut du mal. Le p\u00e8re sait. Quand All\u00e2h te retire quelque chose, tu pleures. Lui sait.',en:'',ar:''},
    {fr:'Tu re\u00e7ois un cadeau dans une bo\u00eete d\u00e9cor\u00e9e. Si tu passes ta vie \u00e0 admirer la bo\u00eete sans l\u2019ouvrir, tu meurs sans avoir vu le cadeau. Ce monde est la bo\u00eete. La rencontre avec All\u00e2h est le cadeau.',en:'',ar:''},
    {fr:'Un m\u00e9decin s\u00e9pare un enfant de sa m\u00e8re pour une op\u00e9ration n\u00e9cessaire. L\u2019enfant hurle. La m\u00e8re pleure. Mais le m\u00e9decin sauve l\u2019enfant. Quand All\u00e2h s\u00e9pare ce qui te para\u00eet ins\u00e9parable \u2014 Il op\u00e8re.',en:'',ar:''},
    {fr:'Tu veux savoir qui tu es vraiment ? Regarde ce que tu fais quand personne ne te regarde. All\u00e2h, Lui, regarde toujours. Ce que tu fais dans le secret est ton vrai visage.',en:'',ar:''},
    {fr:'Tu portes un poids dont personne ne sait l\u2019\u00e9paisseur. Lui sait. Il p\u00e8se les invisibles \u00e0 leur juste valeur. Tu n\u2019es pas en retard, tu es en chemin.',en:'',ar:''},
    {fr:'Tu as pardonn\u00e9 \u00e0 quelqu\u2019un sans qu\u2019il le sache. All\u00e2h, Lui, l\u2019a vu. Et Il a pris note. Aucune bont\u00e9 n\u2019est jamais perdue.',en:'',ar:''},
    {fr:'Une m\u00e8re musulmane pleure ses enfants disparus en ce moment. Tu ne peux pas les ramener. Mais ton dua peut all\u00e9ger sa nuit. C\u2019est la seule chose qui traverse les fronti\u00e8res.',en:'',ar:''},
    {fr:'Tu te demandes si ta pri\u00e8re compte. Elle compte. Mais elle compte aussi POUR ceux qui ne peuvent plus prier. Ton iman porte le leur. C\u2019est un d\u00e9p\u00f4t invisible.',en:'',ar:''},
    {fr:'Au moment o\u00f9 tu lis ceci, des milliers de familles musulmanes rompent le je\u00fbne (Ramadan ou je\u00fbne sur\u00e9rogatoire) quelque part. L\u2019iftar n\u2019a jamais cess\u00e9 depuis 14 si\u00e8cles. Une rupture continue du je\u00fbne.',en:'',ar:''},
    {fr:'Pendant cette heure, environ 5 millions de musulmans dans le monde finissent la lecture compl\u00e8te du Coran ce mois-ci. Une foule silencieuse qui termine le voyage. Tu n\u2019es pas seul \u00e0 lire.',en:'',ar:''},
    {fr:'Quelque part dans le monde, \u00e0 cet instant, un nouveau-n\u00e9 musulman entend son premier adhan dans l\u2019oreille. Ses parents l\u2019accueillent au monde par cet appel. L\u2019oumma s\u2019augmente en silence \u00e0 cet instant.',en:'',ar:''},
    {fr:'Pendant que tu rentres chez toi, des dizaines de milliers de musulmans rentrent de la mosqu\u00e9e. La salat collective ne s\u2019\u00e9teint nulle part. C\u2019est un seul mouvement, en boucle, autour de la plan\u00e8te.',en:'',ar:''},
    {fr:'On demanda au Proph\u00e8te \uFDFA : \u00ab Quand viendra l\u2019Heure ? \u00bb Il r\u00e9pondit : \u00ab Que vous importe ! Que celui qui interroge se pr\u00e9occupe plut\u00f4t de ce qu\u2019il aura pr\u00e9par\u00e9 pour elle. \u00bb Tu ne sais pas quand. Tu sais quoi faire. C\u2019est la seule certitude utile.',en:'',ar:''},
    {fr:'La m\u00e8re reconna\u00eet le cri de son enfant entre mille. Personne ne lui a appris.',en:'',ar:''},
    {fr:'Les manuscrits d\u2019Avicenne ont voyag\u00e9 d\u2019Andalousie jusqu\u2019aux universit\u00e9s de Paris et Bologne \u2014 bien avant qu\u2019on imprime un seul livre en Europe. Le savoir n\u2019a pas de fronti\u00e8re, mais il a une dette.',en:'',ar:''},
    {fr:'Les caravanes des routes commerciales musulmanes reliaient Cordoue \u00e0 P\u00e9kin, Tombouctou \u00e0 Samarcande. L\u2019oumma a toujours march\u00e9 \u2014 bien avant les avions, bien avant les cartes.',en:'',ar:''}
  ],
  nuit: [
    {fr:'Pose ton t\u00e9l\u00e9phone face cach\u00e9e \u2014 la nuit appartient \u00e0 Allah.',en:'Place your phone face down \u2014 the night belongs to Allah.',ar:'\u0636\u064E\u0639\u0652 \u0647\u0627\u062A\u0650\u0641\u064E\u0643\u064E \u0645\u064E\u0642\u0652\u0644\u064F\u0648\u0628\u064B\u0627 \u2014 \u0627\u0644\u0644\u0651\u064E\u064A\u0652\u0644\u064F \u0644\u0650\u0644\u0651\u064E\u0647.'},
    {fr:'\u00c9coute ta respiration 5 cycles \u2014 chaque souffle est un d\u00e9p\u00f4t qu\u2019Allah reprendra.',en:'Listen to 5 breaths \u2014 each one is a trust Allah will reclaim.',ar:'\u0627\u0633\u0652\u0645\u064E\u0639\u0652 \u0665 \u0623\u064E\u0646\u0652\u0641\u0627\u0633 \u2014 \u0643\u064F\u0644\u0651\u064F \u0646\u064E\u0641\u064E\u0633\u064D \u0623\u064E\u0645\u0627\u0646\u064E\u0629\u064C \u0633\u064E\u064A\u064E\u0633\u0652\u062A\u064E\u0631\u0650\u062F\u0651\u064F\u0647\u0627.'},
    {fr:'S\u2019il y a un tort que tu portes \u2014 nomme-le dans ton c\u0153ur. Puis pardonne en silence.',en:'Name in your heart a wrong done to you \u2014 then forgive silently.',ar:'\u0633\u064E\u0645\u0651\u0650 \u0641\u0650\u064A \u0642\u064E\u0644\u0652\u0628\u0650\u0643\u064E \u0638\u064F\u0644\u0652\u0645\u064B\u0627 \u0623\u064F\u0635\u0650\u0628\u0652\u062A\u064E \u0628\u0650\u0647\u0650 \u2014 \u062B\u064F\u0645\u0651\u064E \u0627\u0639\u0652\u0641\u064F \u0628\u0650\u0635\u064E\u0645\u0652\u062A.'},
    {fr:'Ferme les yeux et demande-toi : si c\u2019\u00e9tait ma derni\u00e8re nuit, suis-je en paix ?',en:'Close your eyes and ask: if this were my last night, am I at peace?',ar:'\u0623\u064E\u063A\u0652\u0645\u0650\u0636\u0652 \u0639\u064E\u064A\u0652\u0646\u064E\u064A\u0652\u0643\u064E \u0648\u064E\u0627\u0633\u0652\u0623\u064E\u0644\u0652: \u0644\u064E\u0648\u0652 \u0643\u0627\u0646\u064E\u062A\u0652 \u0622\u062E\u0650\u0631\u064E \u0644\u064E\u064A\u0652\u0644\u064E\u0629\u060C \u0647\u064E\u0644\u0652 \u0623\u064E\u0646\u0627 \u0631\u0627\u0636\u064D\u061F'},
    {fr:'Ne cherche pas le sommeil \u2014 cherche le tawakkul. Le sommeil suivra.',en:'Don\u2019t chase sleep \u2014 chase tawakkul. Sleep will follow.',ar:'\u0644\u0627 \u062A\u064E\u0637\u0652\u0644\u064F\u0628\u0650 \u0627\u0644\u0646\u0651\u064E\u0648\u0652\u0645\u064E \u2014 \u0627\u0637\u0652\u0644\u064F\u0628\u0650 \u0627\u0644\u062A\u0651\u064E\u0648\u064E\u0643\u0651\u064F\u0644. \u0627\u0644\u0646\u0651\u064E\u0648\u0652\u0645\u064F \u0633\u064E\u064A\u064E\u0623\u0652\u062A\u0650\u064A.'},
    {fr:'S\u2019il y a eu une derni\u00e8re personne \u00e0 qui tu as parl\u00e9 aujourd\u2019hui \u2014 fais dua pour elle.',en:'The last person you spoke to today \u2014 make dua for them now.',ar:'\u0622\u062E\u0650\u0631\u064F \u0634\u064E\u062E\u0652\u0635\u064D \u0643\u064E\u0644\u0651\u064E\u0645\u0652\u062A\u064E\u0647\u064F \u0627\u0644\u064A\u064E\u0648\u0652\u0645\u064E \u2014 \u0627\u062F\u0652\u0639\u064F \u0644\u064E\u0647\u064F \u0627\u0644\u0622\u0646.'},
    {fr:'Si tu portes un souci que tu ne peux pas r\u00e9soudre cette nuit \u2014 remets-le \u00e0 Allah.',en:'Hand Allah a worry you cannot solve tonight.',ar:'\u0633\u064E\u0644\u0651\u0650\u0645\u0652 \u0644\u0650\u0644\u0651\u064E\u0647 \u0647\u064E\u0645\u0651\u064B\u0627 \u0644\u0627 \u062A\u064E\u0642\u0652\u062F\u0650\u0631\u064F \u0639\u064E\u0644\u0649 \u062D\u064E\u0644\u0651\u0650\u0647\u0650 \u0627\u0644\u0644\u0651\u064E\u064A\u0652\u0644\u064E\u0629.'},
    {fr:'Ton lit est un linceul d\u2019essai \u2014 allonge-toi sur le c\u00f4t\u00e9 droit comme le Proph\u00e8te \uFDFA.',en:'Your bed is a trial shroud \u2014 lie on your right side like the Prophet \uFDFA.',ar:'\u0641\u0650\u0631\u0627\u0634\u064F\u0643\u064E \u0643\u064E\u0641\u064E\u0646\u064C \u062A\u064E\u062C\u0652\u0631\u0650\u064A\u0628\u0650\u064A\u0651\u064C \u2014 \u0627\u0636\u0652\u0637\u064E\u062C\u0650\u0639\u0652 \u0639\u064E\u0644\u0649 \u064A\u064E\u0645\u0650\u064A\u0646\u0650\u0643\u064E \u0643\u0627\u0644\u0646\u0651\u064E\u0628\u0650\u064A\u0651\u0650 \uFDFA.'},
    {fr:'Ne rejoue pas ta journ\u00e9e \u2014 elle est d\u00e9j\u00e0 \u00e9crite. Repose-toi dans le maktub.',en:'Don\u2019t replay your day \u2014 it\u2019s already written. Rest in the maktub.',ar:'\u0644\u0627 \u062A\u064F\u0639\u0650\u062F\u0652 \u064A\u064E\u0648\u0652\u0645\u064E\u0643\u064E \u2014 \u0642\u064E\u062F\u0652 \u0643\u064F\u062A\u0650\u0628. \u0627\u0631\u0652\u062A\u064E\u062D\u0652 \u0641\u0650\u064A \u0627\u0644\u0645\u064E\u0643\u0652\u062A\u064F\u0648\u0628.'},
    {fr:'Bismika Allahumma amutu wa ahya \u2014 puis ne dis plus rien.',en:'Bismika Allahumma amutu wa ahya \u2014 then say nothing more.',ar:'\u0628\u0650\u0627\u0633\u0652\u0645\u0650\u0643\u064E \u0627\u0644\u0644\u0651\u064E\u0647\u064F\u0645\u0651\u064E \u0623\u064E\u0645\u064F\u0648\u062A\u064F \u0648\u064E\u0623\u064E\u062D\u0652\u064A\u0627 \u2014 \u062B\u064F\u0645\u0651\u064E \u0644\u0627 \u062A\u064E\u0642\u064F\u0644\u0652 \u0634\u064E\u064A\u0652\u0626\u064B\u0627.'},
    {fr:'L\u2019obscurit\u00e9 n\u2019est pas vide \u2014 elle est pleine de Celui qui entend m\u00eame ce que tu ne dis pas. Dis : Ya Sami\u2019, Ya \u2018Alim.',en:'The darkness isn\u2019t empty \u2014 it\u2019s full of the One who hears even what you don\u2019t say.',ar:'\u0627\u0644\u0638\u0651\u064E\u0644\u0627\u0645\u064F \u0644\u064E\u064A\u0652\u0633\u064E \u0641\u0627\u0631\u0650\u063A\u064B\u0627 \u2014 \u0645\u064E\u0644\u0650\u064A\u0621\u064C \u0628\u0650\u0645\u064E\u0646\u0652 \u064A\u064E\u0633\u0652\u0645\u064E\u0639\u064F \u062D\u064E\u062A\u0651\u064E\u0649 \u0645\u0627 \u0644\u0627 \u062A\u064E\u0642\u064F\u0648\u0644\u064F\u0647.'},
    {fr:'Rel\u00e2che ta m\u00e2choire. On la serre souvent sans le savoir. Le corps prie quand tu le lib\u00e8res.',en:'Unclench your jaw. You were tightening it without knowing. The body prays when you free it.',ar:'\u0623\u064E\u0631\u0652\u062E\u0650 \u0641\u064E\u0643\u0651\u064E\u0643. \u0643\u064F\u0646\u0652\u062A\u064E \u062A\u064E\u0634\u064F\u062F\u0651\u064F\u0647\u064F \u062F\u064F\u0648\u0646\u064E \u0639\u0650\u0644\u0652\u0645\u0650\u0643. \u0627\u0644\u062C\u064E\u0633\u064E\u062F\u064F \u064A\u064F\u0635\u064E\u0644\u0651\u0650\u064A \u062D\u0650\u064A\u0646\u064E \u062A\u064F\u062D\u064E\u0631\u0651\u0650\u0631\u064F\u0647.'},
    {fr:'Le bruit du monde s\u2019est arr\u00eat\u00e9. Ne le remplace par rien. Habite le silence.',en:'The noise of the world has stopped. Don\u2019t replace it with anything. Inhabit the silence.',ar:'\u062A\u064E\u0648\u064E\u0642\u0651\u064E\u0641\u064E \u0636\u064E\u062C\u0650\u064A\u062C\u064F \u0627\u0644\u0639\u0627\u0644\u064E\u0645. \u0644\u0627 \u062A\u064E\u0633\u0652\u062A\u064E\u0628\u0652\u062F\u0650\u0644\u0652\u0647\u064F \u0628\u0650\u0634\u064E\u064A\u0652\u0621. \u0627\u0633\u0652\u0643\u064F\u0646\u0650 \u0627\u0644\u0635\u0651\u064E\u0645\u0652\u062A.'},
    {fr:'Quelque part, des proches dorment. Chaque souffle est une amana qu\u2019Allah prot\u00e8ge.',en:'Your loved ones sleep beside you. Each breath is a trust Allah protects.',ar:'\u0623\u064E\u062D\u0650\u0628\u0651\u064E\u062A\u064F\u0643\u064E \u064A\u064E\u0646\u0627\u0645\u064F\u0648\u0646\u064E \u0628\u0650\u062C\u0627\u0646\u0650\u0628\u0650\u0643. \u0643\u064F\u0644\u0651\u064F \u0646\u064E\u0641\u064E\u0633\u064D \u0623\u064E\u0645\u0627\u0646\u064E\u0629\u064C \u064A\u064E\u062D\u0652\u0641\u064E\u0638\u064F\u0647\u0627 \u0627\u0644\u0644\u0651\u064E\u0647.'},
    {fr:'Ton c\u0153ur bat 100 000 fois par jour sans que tu le lui demandes. Qui le commande ? Dis : SubhanAllah wa bihamdihi.',en:'Your heart beats 100,000 times a day without you asking. Who commands it?',ar:'\u0642\u064E\u0644\u0652\u0628\u064F\u0643\u064E \u064A\u064E\u0646\u0652\u0628\u0650\u0636\u064F \u0661\u0660\u0660 \u0623\u064E\u0644\u0652\u0641 \u0645\u064E\u0631\u0651\u064E\u0629 \u064A\u064E\u0648\u0652\u0645\u0650\u064A\u0651\u064B\u0627 \u062F\u064F\u0648\u0646\u064E \u0623\u064E\u0646\u0652 \u062A\u064E\u0637\u0652\u0644\u064F\u0628. \u0645\u064E\u0646\u0652 \u064A\u064E\u0623\u0652\u0645\u064F\u0631\u064F\u0647\u061F'},
    {fr:'\u00c9tends-toi. Sens le poids de ton corps que le lit accueille sans se plaindre. C\u2019est une ni\u2019ma silencieuse.',en:'You have a bed. A pillow. Safety. Three invisible luxuries millions lack.',ar:'\u0644\u064E\u062F\u064E\u064A\u0652\u0643\u064E \u0641\u0650\u0631\u0627\u0634\u064C \u0648\u0648\u0650\u0633\u0627\u062F\u064E\u0629\u064C \u0648\u0623\u064E\u0645\u0627\u0646. \u062B\u064E\u0644\u0627\u062B\u064F \u0631\u064E\u0641\u0627\u0647\u0650\u064A\u0627\u062A\u064D \u062E\u064E\u0641\u0650\u064A\u0651\u064E\u0629 \u064A\u064E\u0641\u0652\u062A\u064E\u0642\u0650\u062F\u064F\u0647\u0627 \u0645\u064E\u0644\u0627\u064A\u0650\u064A\u0646.'},
    {fr:'Cette nuit, o\u00f9 que tu sois \u2014 quelqu\u2019un veille dans un h\u00f4pital, quelqu\u2019un fuit dans le noir. Alhamdulillah pour ta paix.',en:'This quiet night \u2014 someone watches in a hospital, someone flees in the dark. Alhamdulillah for your peace.',ar:'\u0647\u0630\u0650\u0647\u0650 \u0627\u0644\u0644\u0651\u064E\u064A\u0652\u0644\u064E\u0629\u064F \u0627\u0644\u0647\u0627\u062F\u0650\u0626\u064E\u0629 \u2014 \u063A\u064E\u064A\u0652\u0631\u064F\u0643\u064E \u064A\u064E\u0633\u0652\u0647\u064E\u0631\u064F \u0641\u0650\u064A \u0645\u064F\u0633\u0652\u062A\u064E\u0634\u0652\u0641\u064E\u0649\u060C \u063A\u064E\u064A\u0652\u0631\u064F\u0643\u064E \u064A\u064E\u0641\u0650\u0631\u0651\u064F \u0641\u0650\u064A \u0627\u0644\u0638\u0651\u064E\u0644\u0627\u0645. \u0627\u0644\u062D\u064E\u0645\u0652\u062F\u064F \u0644\u0650\u0644\u0651\u064E\u0647 \u0639\u064E\u0644\u064E\u0649 \u0633\u064E\u0644\u0627\u0645\u0650\u0643.'},
    {fr:'S\u2019il y a eu un petit mensonge aujourd\u2019hui \u2014 reconnais-le. Allah aime ceux qui reviennent.',en:'You lied today, even a small lie. Acknowledge it. Allah loves those who return.',ar:'\u0643\u064E\u0630\u064E\u0628\u0652\u062A\u064E \u0627\u0644\u064A\u064E\u0648\u0652\u0645\u060C \u062D\u064E\u062A\u0651\u064E\u0649 \u0643\u064E\u0630\u0650\u0628\u064E\u0629\u064B \u0635\u064E\u063A\u0650\u064A\u0631\u064E\u0629. \u0627\u0639\u0652\u062A\u064E\u0631\u0650\u0641\u0652 \u0628\u0650\u0647\u0627. \u0627\u0644\u0644\u0651\u064E\u0647\u064F \u064A\u064F\u062D\u0650\u0628\u0651\u064F \u0627\u0644\u062A\u0651\u064E\u0648\u0651\u0627\u0628\u0650\u064A\u0646.'},
    {fr:'S\u2019il y a une douleur ancienne avec tes parents \u2014 pardonne. Ils ont fait ce qu\u2019ils pouvaient avec ce qu\u2019ils avaient.',en:'Forgive your parents an old pain. They did what they could with what they had.',ar:'\u0633\u0627\u0645\u0650\u062D\u0652 \u0648\u0627\u0644\u0650\u062F\u064E\u064A\u0652\u0643\u064E \u0639\u064E\u0644\u064E\u0649 \u0623\u064E\u0644\u064E\u0645\u064D \u0642\u064E\u062F\u0650\u064A\u0645. \u0641\u064E\u0639\u064E\u0644\u0627 \u0645\u0627 \u0627\u0633\u0652\u062A\u064E\u0637\u0627\u0639\u0627 \u0628\u0650\u0645\u0627 \u0645\u064E\u0644\u064E\u0643\u0627.'},
    {fr:'Le sommeil est une petite mort, le r\u00e9veil une r\u00e9surrection. Le Proph\u00e8te \uFDFA disait au r\u00e9veil : \u00ab Alhamdulillah qui nous a rendu la vie apr\u00e8s nous avoir donn\u00e9 la mort. \u00bb',en:'Sleep is a small death, waking a resurrection. The Prophet \uFDFA was aware of this every night.',ar:'\u0627\u0644\u0646\u0651\u064E\u0648\u0652\u0645\u064F \u0645\u064E\u0648\u0652\u062A\u064C \u0635\u064E\u063A\u0650\u064A\u0631\u060C \u0648\u0627\u0644\u064A\u064E\u0642\u064E\u0638\u064E\u0629\u064F \u0628\u064E\u0639\u0652\u062B. \u0627\u0644\u0646\u0651\u064E\u0628\u0650\u064A\u0651\u064F \uFDFA \u0643\u0627\u0646\u064E \u064A\u064E\u0639\u0650\u064A\u0647\u0627 \u0643\u064F\u0644\u0651\u064E \u0644\u064E\u064A\u0652\u0644\u064E\u0629.'},
    {fr:'Si la constante cosmologique avait vari\u00e9 d\u2019une d\u00e9cimale sur 120 \u2014 l\u2019univers se serait dispers\u00e9 ou effondr\u00e9. 120 d\u00e9cimales. Le r\u00e9glage de toute chose se compte en d\u00e9cimales que l\u2019homme ne sait pas \u00e9crire.',en:'',ar:''},
    {fr:'Tu vois les \u00e9toiles ce soir. Certaines sont mortes depuis des millions d\u2019ann\u00e9es. Leur lumi\u00e8re voyage toujours. Celui qui a fait la lumi\u00e8re l\u2019a faite plus durable que les \u00e9toiles elles-m\u00eames.',en:'',ar:''},
    {fr:'Tu es litt\u00e9ralement fait de poussi\u00e8re d\u2019\u00e9toiles. Le carbone de tes os vient d\u2019une \u00e9toile qui a explos\u00e9 il y a 4 milliards d\u2019ann\u00e9es. All\u00e2h t\u2019a tiss\u00e9 avec les cendres du ciel.',en:'',ar:''},
    {fr:'Probabilit\u00e9 que les 6 constantes fondamentales de la physique aient TOUTES leurs valeurs pr\u00e9cises ensemble : moins que tirer le m\u00eame grain de sable dans tout l\u2019univers, deux fois de suite. Tu existes dans cet impossible.',en:'',ar:''},
    {fr:'L\u2019univers a 13,8 milliards d\u2019ann\u00e9es. Si tu rapportes \u00e7a \u00e0 24h, l\u2019humanit\u00e9 existe depuis 0,4 seconde. Et pourtant, c\u2019est TOI qui te demandes pourquoi tu existes. All\u00e2h t\u2019a plac\u00e9 l\u00e0 o\u00f9 la question pouvait se poser.',en:'',ar:''},
    {fr:'Le Coran dit que l\u2019univers a \u00e9t\u00e9 \u00ab d\u00e9ploy\u00e9 \u00bb \u2014 terme exact pour ce que les physiciens appellent expansion de l\u2019univers, d\u00e9couverte par Hubble en 1929. Le mot est dans le texte depuis 1400 ans. (Coran 51:47)',en:'',ar:''},
    {fr:'Le Coran d\u00e9fie depuis 14 si\u00e8cles : \u00ab Produisez une seule sourate semblable \u00e0 celle-ci. \u00bb (Coran 2:23). 14 si\u00e8cles. Aucune sourate \u00e9quivalente produite, dans aucune langue, par aucun humain. Le d\u00e9fi reste ouvert. Tu peux essayer maintenant.',en:'',ar:''},
    {fr:'Dans quelques minutes, tu vas perdre conscience volontairement \u2014 sans avoir peur. Aucune autre esp\u00e8ce ne l\u00e2che prise en confiance. All\u00e2h t\u2019a appris \u00e0 mourir un peu chaque nuit, pour que la grande mort ne te terrifie pas.',en:'',ar:''},
    {fr:'Tu vas r\u00eaver cette nuit. Tu seras quelqu\u2019un d\u2019autre, dans des lieux qui n\u2019existent pas, qui te para\u00eetront r\u00e9els. Personne ne sait pourquoi nous r\u00eavons. Mais Lui sait. Et Il t\u2019offre ce cin\u00e9ma chaque nuit.',en:'',ar:''},
    {fr:'Tu pleures cette nuit ? All\u00e2h entend ce que personne n\u2019entend. Il voit ce que personne ne voit. Et Il aime particuli\u00e8rement ceux qui pleurent dans le silence.',en:'',ar:''},
    {fr:'Tu as peur de la mort ? Le Proph\u00e8te \uFDFA a dit : \u00ab All\u00e2h est plus tendre envers Son serviteur qu\u2019une m\u00e8re envers son enfant. \u00bb Une m\u00e8re ne laisse pas mourir son enfant dans la peur. Il ne te laissera pas non plus.',en:'',ar:''},
    {fr:'All\u00e2h dit dans le Coran : \u00ab Toute \u00e2me go\u00fbtera la mort. \u00bb (3:185) GO\u00dbTERA. Pas subira. Pas affrontera. Go\u00fbtera. Comme on go\u00fbte un fruit. All\u00e2h choisit Ses mots avec une douceur que tu ne soup\u00e7onnes pas.',en:'',ar:''},
    {fr:'Tu r\u00eaves cette nuit que tu perds tout \u2014 fortune, sant\u00e9, proches. Tu te r\u00e9veilles soulag\u00e9 : ce n\u2019\u00e9tait qu\u2019un r\u00eave. Cette vie est ce r\u00eave. Le r\u00e9veil \u2014 c\u2019est la mort.',en:'',ar:''},
    {fr:'Une m\u00e8re porte son enfant 9 mois dans le ventre. L\u2019enfant ne sait rien du monde qui l\u2019attend. Il s\u2019agite, il a peur de la sortie. Tu es ce f\u0153tus. La mort est ta naissance.',en:'',ar:''},
    {fr:'Le soleil se couche tous les soirs. Personne n\u2019a jamais paniqu\u00e9 en pensant qu\u2019il ne reviendrait pas. Mais quand quelque chose dispara\u00eet de TA vie, tu doutes du retour. All\u00e2h n\u2019a pas fait deux lois diff\u00e9rentes.',en:'',ar:''},
    {fr:'Une lampe \u00e0 huile \u00e9claire une pi\u00e8ce. Quand l\u2019huile est finie, la lampe s\u2019\u00e9teint. L\u2019huile, c\u2019est ton souffle. La lampe, c\u2019est ton corps. La lumi\u00e8re, c\u2019est ce que tu auras \u00e9t\u00e9. La lumi\u00e8re survit aux deux autres.',en:'',ar:''},
    {fr:'Un homme construit une maison magnifique. Le jour de l\u2019emm\u00e9nagement, il meurt. Un autre passe sa vie \u00e0 construire son c\u0153ur. Le jour de sa mort, il emm\u00e9nage enfin. Lequel a bien investi ?',en:'',ar:''},
    {fr:'Tu doutes parfois de ta foi. Le fait m\u00eame de douter prouve que tu y tiens. Personne ne doute de ce qui ne lui importe pas.',en:'',ar:''},
    {fr:'Tu vas dormir ce soir. All\u00e2h ne dort pas. Pendant que tu disparais, Il veille sur toi. Ta s\u00e9curit\u00e9 de cette nuit est un cadeau silencieux qu\u2019Il te fait.',en:'',ar:''},
    {fr:'Un enfant musulman se couche ce soir sans toit. Toi tu as ton lit. Dis pour lui une dou\u2019a. All\u00e2h entend le dua silencieux d\u2019un fr\u00e8re pour son fr\u00e8re.',en:'',ar:''},
    {fr:'Pendant que tu vas dormir, des millions de musulmans se l\u00e8vent pour le tahajjud (pri\u00e8re de la nuit) quelque part. Ils prient pour des inconnus. L\u2019un d\u2019eux prie peut-\u00eatre pour toi sans le savoir.',en:'',ar:''},
    {fr:'\u00c0 cet instant, dans les minarets du monde, des muezzins se pr\u00e9parent au prochain adhan. Le r\u00e9veil de l\u2019oumma ne s\u2019arr\u00eate nulle part. Pendant ton sommeil, l\u2019oumma travaille.',en:'',ar:''},
    {fr:'Quelque part dans le monde, \u00e0 cet instant, une m\u00e8re musulmane berce son enfant en r\u00e9citant Ayat al-Kursi. Sa voix porte le verset le plus puissant du Coran dans une chambre que tu ne verras jamais. C\u2019est \u00e7a, l\u2019oumma.',en:'',ar:''},
    {fr:'Pendant ton sommeil cette nuit, environ 8 millions de musulmans vont mourir paisiblement quelque part dans le monde et entreront dans l\u2019au-del\u00e0. L\u2019oumma d\u00e9m\u00e9nage en continu. Toi-m\u00eame, un jour. Pas seul.',en:'',ar:''},
    {fr:'All\u00e2h dit dans le Coran : \u00ab L\u2019Heure approche, et la lune s\u2019est fendue. \u00bb (Coran 54:1) Le verset commence par \u00ab approche \u00bb au pass\u00e9. Le Coran consid\u00e8re que c\u2019est d\u00e9j\u00e0 en marche depuis 14 si\u00e8cles. Tu n\u2019attends pas un \u00e9v\u00e8nement \u2014 tu vis dedans. Que portes-tu en toi \u00e0 cet instant ?',en:'',ar:''},
    {fr:'Une \u00e9toile que tu vois ce soir, sa lumi\u00e8re a mis des ann\u00e9es \u00e0 arriver. Tu re\u00e7ois un message ancien.',en:'',ar:''},
    {fr:'Le ver de terre laboure ton sol gratuitement chaque nuit. Tu ne lui as jamais dit merci.',en:'',ar:''},
    {fr:'\u00c0 cet instant, quelque part dans le monde, c\u2019est Tahajjud. Pendant que tu lis ceci, quelqu\u2019un s\u2019est lev\u00e9 pour prier. La cha\u00eene ne dort jamais.',en:'',ar:''},
    {fr:'Le texte du Coran que tu lis ce soir \u2014 mot pour mot, lettre pour lettre \u2014 est le m\u00eame que celui qu\u2019Aisha (qu\u2019All\u00e2h l\u2019agr\u00e9e) entendait du Proph\u00e8te (paix et b\u00e9n\u00e9dictions sur lui). 14 si\u00e8cles sans variation.',en:'',ar:''},
    {fr:'Al-Ula, en Arabie, garde dans ses pierres des inscriptions de royaumes oubli\u00e9s. L\u2019oumma marche sur des civilisations enti\u00e8res \u2014 qui toutes ont eu leur temps.',en:'',ar:''}
  ]
};
/* ── Greeting murmures (chargé depuis JSON) ── */
window.GREETING_MURMURES = null;
(function _loadGreetingMurmures() {
  fetch('./data/greeting_murmures.json')
    .then(function(r) { return r.ok ? r.json() : null; })
    .then(function(d) { if (d) window.GREETING_MURMURES = d; })
    .catch(function() {});
})();
function getGreetingPhrases(dayIndex) {
  var src = window.GREETING_MURMURES;
  var entry = src && src['greeting_day_' + dayIndex];
  if (entry && entry.phrases && entry.phrases.length > 0) return entry.phrases;
  // Fallback : i18n inline
  var pool = t('greeting_day_' + dayIndex);
  return Array.isArray(pool) ? pool : [pool];
}
window.getGreetingPhrases = getGreetingPhrases;

window.WAQT_BY_PRIERE = null;
function loadWaqtData(cb) {
  if (window.WAQT_BY_PRIERE) { if (cb) cb(); return; }
  var files = {fajr:'data/waqt/waqt_fajr.json',dhuhr:'data/waqt/waqt_dhuhr.json',asr:'data/waqt/waqt_asr.json',maghrib:'data/waqt/waqt_maghrib.json',isha:'data/waqt/waqt_isha.json'};
  var keys = Object.keys(files);
  Promise.all(keys.map(function(k) { return fetch(files[k]).then(function(r) { return r.ok ? r.json() : []; }).catch(function() { return []; }); }))
    .then(function(results) {
      var obj = {};
      keys.forEach(function(k, i) {
        var d = results[i];
        if (Array.isArray(d)) {
          obj[k] = d;
        } else if (d && d.phrases) {
          // Merge phrases + categories (langue, transaction, etc.) into unified pool
          var pool = d.phrases.slice();
          if (d.categories) {
            Object.keys(d.categories).forEach(function(cat) {
              if (Array.isArray(d.categories[cat])) {
                d.categories[cat].forEach(function(h) {
                  pool.push({ fr: h.texte || h.fr || '', _story: h });
                });
              }
            });
          }
          obj[k] = pool;
        } else {
          obj[k] = [];
        }
      });
      window.WAQT_BY_PRIERE = obj;
      if (cb) cb();
    });
}

