window.NIYYAH_POOL = null;
(function _loadNiyyahPool() {
  fetch('./data/niyyah_pool.json').then(function(r) { return r.ok ? r.json() : null; })
    .then(function(data) { if (data && data.niyyahs) window.NIYYAH_POOL = data.niyyahs; })
    .catch(function() {});
})();

function _getNiyyahHistory() {
  try {
    var raw = JSON.parse(safeGetItem('niyyah_history') || '[]');
    var cutoff = Date.now() - 30 * 86400000;
    return raw.filter(function(e) { return e.ts > cutoff; });
  } catch(e) { return []; }
}

function _saveNiyyahHistory(history) {
  var cutoff = Date.now() - 30 * 86400000;
  var clean = history.filter(function(e) { return e.ts > cutoff; });
  safeSetItem('niyyah_history', JSON.stringify(clean));
}

function _addToNiyyahHistory(ids) {
  var history = _getNiyyahHistory();
  var ts = Date.now();
  ids.forEach(function(id) { history.push({ id: id, ts: ts }); });
  _saveNiyyahHistory(history);
}

function _pickFromCategory(pool, category, excludeIds, subcategory) {
  var candidates = pool.filter(function(n) {
    if (n.category !== category) return false;
    if (subcategory && n.subcategory !== subcategory) return false;
    return excludeIds.indexOf(n.id) === -1;
  });
  if (candidates.length === 0) {
    // Fallback: ignore history if pool exhausted
    candidates = pool.filter(function(n) {
      if (n.category !== category) return false;
      if (subcategory && n.subcategory !== subcategory) return false;
      return true;
    });
  }
  if (candidates.length === 0) return null;
  return candidates[Math.floor(Math.random() * candidates.length)];
}

function _detectSeasonContext(hijri) {
  var today = new Date();
  var isFriday = today.getDay() === 5;

  if (hijri) {
    var m = (hijri.month || '').toLowerCase();
    var d = hijri.day || 0;

    // Ramadan last third (nights 21-30)
    if (m === 'ramadan' || m === 'ramadhan' || m === 'ramaḍān') {
      if (d >= 21) return 'laylat_qadr';
      return 'ramadan';
    }
    // Muharram 9-10
    if ((m === 'muharram' || m === 'muḥarram') && d >= 9 && d <= 10) return 'muharram';
    // Dhul-Hijja 1-10
    if ((m === 'dhul-hijja' || m === 'dhul hijja' || m === 'dhu al-hijjah' || m === 'dhul-hijjah' || m === 'dhū al-ḥijjah') && d >= 1 && d <= 10) return 'dhul_hijja';
    // Jours blancs 13-14-15
    if (d >= 13 && d <= 15) return 'jours_blancs';
  }

  if (isFriday) return 'jumuah';
  return null;
}

function _pickTriadeNiyyah(callback) {
  if (!window.NIYYAH_POOL || window.NIYYAH_POOL.length === 0) {
    callback(null);
    return;
  }

  var history = _getNiyyahHistory();
  var excludeIds = history.map(function(e) { return e.id; });
  var pool = window.NIYYAH_POOL;

  var combat = _pickFromCategory(pool, 'combat', excludeIds);
  var devotion = _pickFromCategory(pool, 'devotion', excludeIds);
  var service = _pickFromCategory(pool, 'service', excludeIds);

  var result = [];
  if (combat) result.push(combat);
  if (devotion) result.push(devotion);
  if (service) result.push(service);

  // Season detection (async because hijri needs API)
  getCurrentHijri().then(function(hijri) {
    var ctx = _detectSeasonContext(hijri);
    if (ctx) {
      var saison = _pickFromCategory(pool, 'saison', [], ctx);
      if (saison) {
        saison._seasonLabel = ctx;
        result.push(saison);
      }
    }
    callback(result);
  }).catch(function() {
    callback(result);
  });
}

function _dateLocale() {
  var lang = (typeof V2_LANG !== 'undefined') ? V2_LANG : 'fr';
  return lang === 'en' ? 'en-US' : lang === 'ar' ? 'ar' : 'fr-FR';
}
function isSilenceDay() {
  var d = safeGetItem('niyyah_silence_day');
  if (!d || d === 'none') return false;
  return parseInt(d, 10) === new Date().getDay();
}
function updateSpiritualTitle() {
  var el = document.getElementById('v2-spiritual-title');
  if (!el) return;
  var hist = {};
  try { hist = JSON.parse(safeGetItem('spiritual_history') || '{}'); } catch(e) {}
  var streak = hist.streak || 0;
  var totalDays = hist.totalDays || 0;
  var todayDone = getLevelProgress(1) >= 100;
  var streakDisplay = streak + (todayDone ? 1 : 0);
  var totalDisplay = totalDays + (todayDone ? 1 : 0);
  var titles = [
    { min: 365, ar: '\u0627\u0644\u0631\u0651\u064E\u0627\u0633\u0650\u062E\u064F', k: 'sp_rasikh' },
    { min: 180, ar: '\u0627\u0644\u0645\u064F\u062D\u0652\u0633\u0650\u0646\u064F', k: 'sp_muhsin' },
    { min: 90,  ar: '\u0627\u0644\u0645\u064F\u062A\u0651\u064E\u0642\u0650\u064A', k: 'sp_muttaqi' },
    { min: 30,  ar: '\u0627\u0644\u0645\u064F\u0648\u0627\u0638\u0650\u0628\u064F', k: 'sp_muwadib' },
    { min: 7,   ar: '\u0627\u0644\u0645\u064F\u0628\u0652\u062A\u064E\u062F\u0650\u0626\u064F', k: 'sp_mubtadi' },
    { min: 0,   ar: '\u0627\u0644\u0637\u0651\u064E\u0627\u0644\u0650\u0628\u064F', k: 'sp_talib' }
  ];
  var title = titles.find(function(t) { return streakDisplay >= t.min; });
  el.style.display = 'block';
  el.style.marginTop = '40px';
  el.style.marginBottom = '40px';
  el.innerHTML = '<div style="font-family:\'Amiri\',serif;font-size:40px;color:#C8A84A;line-height:1.3;">' + title.ar + '</div>'
    + '<div style="font-family:\'Cormorant Garamond\',serif;font-size:18px;font-style:italic;color:rgba(200,168,75,0.7);letter-spacing:0.5px;margin-top:4px;">' + t(title.k) + '</div>';
}
function v2RefreshStats() {
  if (typeof updateSanctuaireNextPrayer === 'function') updateSanctuaireNextPrayer();
  // POINT 3 — Effet visuel Tawba persistant 24h
  try { applyTawbaGlow(); } catch(e) {}
  // Encart Découverte J1-J7
  (function() {
    var _oldDe = document.getElementById('decouverte-encart'); if (_oldDe) _oldDe.remove();
    var _inst = parseInt(safeGetItem('niyyah_install_date') || '0', 10);
    if (!_inst) return;
    var _dayN = Math.floor((Date.now() - _inst) / 86400000) + 1;
    if (_dayN < 1 || _dayN > 7) return;
    var _decTextes = {
      1:'Bienvenue. Explore ton Sanctuaire \u00e0 ton rythme.',
      2:'Ce soir apr\u00e8s Icha\u00a0: essaie \u00ab\u00a0Quand vient la nuit\u00a0\u00bb.',
      3:'D\u00e9couvre ton trait Nafs de la semaine.',
      4:'Le Scan Regarde peut arriver \u00e0 n\u2019importe quel moment aujourd\u2019hui.',
      5:'Tu as une minute\u00a0? Essaie Al-Waqt.',
      6:'Note une intention dans ton Journal.',
      7:'Tu connais maintenant ton Sanctuaire. \u00c0 toi.'
    };
    var _de = document.createElement('div');
    _de.id = 'decouverte-encart';
    _de.style.cssText = 'max-width:340px;margin:12px auto;padding:12px;border:1px solid rgba(200,168,75,0.25);border-radius:14px;background:rgba(10,10,10,0.5);text-align:center;';
    _de.innerHTML = '<div style="font-size:14px;color:#E5E0DC;line-height:1.6;margin-bottom:4px;">' + (_decTextes[_dayN] || '') + '</div>'
      + '<div style="font-size:12px;color:rgba(200,168,75,0.4);">Jour ' + _dayN + ' sur 7</div>';
    var _sanctInner = document.querySelector('#view-sanctuaire > div');
    if (_sanctInner) _sanctInner.insertBefore(_de, _sanctInner.firstChild);
  })();
  // Stats row — table layout, toujours horizontal
  (function() {
    var sr = document.getElementById('v2-stats-row');
    if (sr) {
      sr.style.display = 'table';
      sr.style.width = '100%';
    }
  })();
  // Apply current language first
  v2ApplyI18n();
  // Greeting — salutation 1×/jour puis murmure dans #v2-greeting-text
  const grEl = document.getElementById('v2-greeting-text');
  if (grEl) {
    var _lastSalam = safeGetItem('niyyah_greet_date');
    var _murmureText;
    if (safeGetItem('niyyah_murmur_date') === TODAY) {
      _murmureText = safeGetItem('niyyah_murmur_text') || t('greeting_day_' + new Date().getDay());
    } else {
      var _grPool = getGreetingPhrases(new Date().getDay());
      var _wn = Math.floor((Date.now() - new Date(new Date().getFullYear(),0,1).getTime()) / 604800000);
      var _dbgW = new URLSearchParams(window.location.search).get('debugWeek');
      if (_dbgW !== null) { _wn = parseInt(_dbgW, 10) || 0; console.log('[murmure debug] forced week=' + _wn); }
      _murmureText = _grPool[_wn % _grPool.length];
      console.log('[murmure] day=' + new Date().getDay() + ' week=' + _wn + ' pool=' + _grPool.length + ' idx=' + (_wn % _grPool.length) + ' → "' + _murmureText + '"');
      if (!safeGetItem('niyyah_welcome_shown')) {
        var _motiv = safeGetItem('niyyah_motivation');
        if (_motiv === 'routine' || _motiv === 'reconnecter' || _motiv === 'sacraliser') {
          _murmureText = t('welcome_' + _motiv);
          safeSetItem('niyyah_welcome_shown', '1');
        }
      }
      var _inst = parseInt(safeGetItem('niyyah_install_date') || '0', 10);
      var _daysSinceInstall = _inst ? Math.floor((Date.now() - _inst) / 86400000) : 0;
      if (_daysSinceInstall >= 30 && !safeGetItem('niyyah_j30_shown')) {
        _murmureText = t('evolution_invite_30');
        safeSetItem('niyyah_j30_shown', '1');
      }
      safeSetItem('niyyah_murmur_date', TODAY);
      safeSetItem('niyyah_murmur_text', _murmureText);
    }
    if (_lastSalam !== TODAY) {
      // Salutation fade-in 2s → visible 7s → fade-out 2s → murmure 1.5s
      var _prenom = _getPrenom();
      var _salamText = _prenom ? (t('greet_salam') + ', ' + _prenom) : t('greet_salam');
      grEl.textContent = _salamText;
      grEl.style.animation = 'none';
      grEl.offsetHeight;
      grEl.style.animation = 'greetingFadeIn 2s ease-out both';
      safeSetItem('niyyah_greet_date', TODAY);
      // Après 9s (2s fade-in + 7s visible) : fade-out → murmure
      setTimeout(function() {
        grEl.style.transition = 'opacity 2s ease';
        grEl.style.opacity = '0';
        setTimeout(function() {
          grEl.textContent = _murmureText;
          grEl.style.transition = 'opacity 1.5s ease';
          grEl.offsetHeight;
          grEl.style.opacity = '1';
        }, 2000);
      }, 9000);
    } else {
      // Flag déjà posé : murmure direct
      grEl.textContent = _murmureText;
      grEl.style.animation = 'none';
      grEl.offsetHeight;
      grEl.style.animation = 'greetingFadeIn 1.5s ease-out 0.3s both';
    }
  }
  // Titres spirituels évolutifs (premium only)
  updateSpiritualTitle();

  // Midnight reset intention
  const s = v2GetState();
  const today = new Date().toDateString();
  if (s.intentionDate && s.intentionDate !== today) {
    s.intention = null; s.intentionDate = null;
    v2SaveState(s);
  }
  // Masquer "Commencer ma journée" — sobriété
  var eyebrow = document.getElementById('v2-greeting-eyebrow');
  if (eyebrow) eyebrow.style.display = 'none';

  // Tawba mode (2+ jours absence)
  if (s.lastOpenDate) {
    const diff = Math.floor((Date.now() - new Date(s.lastOpenDate)) / 86400000);
    if (diff >= 2) {
      const card = document.getElementById('tawba-card-v2');
      if (card) card.style.display = 'block';
    }
  }
  s.lastOpenDate = today;
  v2SaveState(s);

  v2UpdateOrbState();

  // Appliquer l'infusion si intention déjà enregistrée
  const _s = v2GetState();
  if (_s.intention) applyInfusion(_s.intention);

  // Cleanup deprecated Night Companion localStorage
  safeRemoveItem('niyyah_compagnon_date');
  safeRemoveItem('niyyah_sagesse_nuit');
  safeRemoveItem('niyyah_morning_wisdom_shown_date');
  updateFinJourneeCard();
  updateFajrChallenge();
  updateSanctuaireMoment();
  var disclaimerEl = document.getElementById('app-disclaimer');
  if (disclaimerEl) disclaimerEl.textContent = t('disclaimer');
}

function updateFinJourneeCard() {
  var card = document.getElementById('finjournee-card');
  if (!card) return;
  // Determine visibility: Maghrib+1h to Fajr
  var now = new Date();
  var nowMin = now.getHours() * 60 + now.getMinutes();
  var show = false;
  if (_prayerTimes) {
    var _toMin = function(s) { if (!s) return null; var p = s.replace(/ *\(.*\)/,'').split(':'); return parseInt(p[0],10)*60+parseInt(p[1],10); };
    var maghrib = _toMin(_prayerTimes['Maghrib']);
    var fajr = _toMin(_prayerTimes['Fajr']);
    if (maghrib != null && fajr != null) {
      show = (nowMin >= maghrib + 60) || (nowMin < fajr);
    }
  } else {
    // Fallback: 20h-5h if no prayer times
    show = (nowMin >= 1200) || (nowMin < 300);
  }
  if (!show) { card.style.display = 'none'; return; }
  var _todayStr = dateToKey(now);
  var done = safeGetItem('niyyah_finjournee_date') === _todayStr;
  if (done) { card.style.display = 'none'; return; }
  card.style.display = 'block';
  card.innerHTML = '<img class="finjournee-img" loading="lazy" src="assets/cards/card-findejour.webp" alt="Fin de journée" onclick="openFinJournee()">';
}
