function checkHijriBanner() {
  getCurrentHijri().then(function(h) {
    if (!h) return;
    var today = todayKey();
    if (safeGetItem('hijri_banner_dismissed_' + today)) return;
    var _monthNorm = h.month ? h.month.normalize('NFD').replace(/[\u0300-\u036f]/g, '') : '';
    var _isDhulHijjah = _monthNorm.indexOf('Hijjah') !== -1;
    var _isMuharram = _monthNorm.indexOf('Muharram') !== -1;
    var _isRajab = _monthNorm.indexOf('Rajab') !== -1;
    var _isShaban = _monthNorm.indexOf('Sha') !== -1 && _monthNorm.indexOf('ban') !== -1;
    var sanct = document.getElementById('view-sanctuaire');
    if (!sanct) return;
    var msg = null, btnLabel = null, action = null, _showLater = true;
    if (h.month === 'Ramadan' && (!ramadanState || !ramadanState.active)) {
      msg = '\u2726 Nous sommes en Ramadan. Activer le Mode Ramadan\u00a0?';
      btnLabel = 'Activer';
      action = 'toggleRamadanMode()';
    } else if (h.month === 'Shawwal' && h.day <= 3 && ramadanState && ramadanState.active) {
      msg = '\u2726 Eid Mubarak. D\u00e9sactiver le Mode Ramadan\u00a0?';
      btnLabel = 'D\u00e9sactiver';
      action = 'toggleRamadanMode()';
    } else if (h.month === 'Ramadan' && h.day === 21 && ramadanState && ramadanState.active) {
      var _10key = 'hijri_banner_10jours_' + h.year;
      if (safeGetItem(_10key)) return;
      msg = '\u2726 Les 10 derniers jours ont commenc\u00e9. C\u2019est le moment de l\u2019intensification.';
      btnLabel = 'J\u2019ai compris';
      action = 'safeSetItem(\'' + _10key + '\',\'1\')';
    } else if (h.month === 'Ramadan' && [21,23,25,27,29].includes(h.day) && ramadanState && ramadanState.active) {
      var _qadrKey = 'hijri_banner_qadr_' + h.day + '_' + h.year;
      if (safeGetItem(_qadrKey)) return;
      msg = '\u2726 Cette nuit pourrait \u00eatre Laylat al-Qadr. Cherche-la dans les nuits impaires des 10 derni\u00e8res.';
      btnLabel = 'Bismill\u0101h';
      action = 'safeSetItem(\'' + _qadrKey + '\',\'1\')';
      _showLater = false;
    } else if (_isDhulHijjah && h.day === 1) {
      var _dhKey1 = 'hijri_banner_dh_10jours_' + h.year;
      if (safeGetItem(_dhKey1)) return;
      msg = '\u2726 Les 10 premiers jours de Dhul-Hijjah ont commenc\u00e9. Les actions les plus aim\u00e9es d\u2019All\u00e2h dans l\u2019ann\u00e9e.';
      btnLabel = 'Bismill\u0101h';
      action = 'safeSetItem(\'' + _dhKey1 + '\',\'1\')';
    } else if (_isDhulHijjah && h.day === 8) {
      var _dhKey8 = 'hijri_banner_dh_veille_arafat_' + h.year;
      if (safeGetItem(_dhKey8)) return;
      msg = '\u2726 Demain c\u2019est Arafat. Je\u00fbner expie 2 ann\u00e9es (Muslim).';
      btnLabel = 'Bismill\u0101h';
      action = 'safeSetItem(\'' + _dhKey8 + '\',\'1\')';
      _showLater = false;
    } else if (_isMuharram && h.day === 1) {
      var _muhKey1 = 'hijri_banner_muh_new_' + h.year;
      if (safeGetItem(_muhKey1)) return;
      msg = '\u2726 Bonne ann\u00e9e hijri. Le mois d\u2019All\u00e2h a commenc\u00e9 \u2014 je\u00fbne recommand\u00e9.';
      btnLabel = 'J\u2019ai compris';
      action = 'safeSetItem(\'' + _muhKey1 + '\',\'1\')';
    } else if (_isMuharram && h.day === 9) {
      var _muhKey9 = 'hijri_banner_muh_veille_' + h.year;
      if (safeGetItem(_muhKey9)) return;
      msg = '\u2726 Demain c\u2019est Achoura. Le Proph\u00e8te \uFDFA recommandait de je\u00fbner le 9 et le 10.';
      btnLabel = 'J\u2019ai compris';
      action = 'safeSetItem(\'' + _muhKey9 + '\',\'1\')';
      _showLater = false;
    } else if (_isRajab && h.day === 1) {
      var _rajKey = 'hijri_banner_rajab_' + h.year;
      if (safeGetItem(_rajKey)) return;
      msg = '\u2726 Le mois sacr\u00e9 de Rajab a commenc\u00e9. All\u00e2humma b\u00e2rik lan\u00e2 f\u00ee Rajab wa Sha\u02bfb\u00e2n wa balli\u03b3n\u00e2 Ramad\u00e2n.';
      btnLabel = 'J\u2019ai compris';
      action = 'safeSetItem(\'' + _rajKey + '\',\'1\')';
    } else if (_isShaban && h.day === 1) {
      var _shaKey = 'hijri_banner_shaban_' + h.year;
      if (safeGetItem(_shaKey)) return;
      msg = '\u2726 Sha\u2019ban a commenc\u00e9. Le Proph\u00e8te \uFDFA je\u00fbnait beaucoup ce mois \u2014 pr\u00e9paration \u00e0 Ramadan.';
      btnLabel = 'J\u2019ai compris';
      action = 'safeSetItem(\'' + _shaKey + '\',\'1\')';
    }
    if (!msg) return;
    var banner = document.createElement('div');
    banner.className = 'hijri-banner';
    var _laterBtn = _showLater ? '<button class="hijri-banner-dismiss" onclick="safeSetItem(\'hijri_banner_dismissed_' + today + '\',\'1\');this.closest(\'.hijri-banner\').remove();">Plus tard</button>' : '';
    banner.innerHTML = '<div class="hijri-banner-text">' + msg + '</div>'
      + '<div class="hijri-banner-actions">'
      + '<button class="hijri-banner-btn" onclick="' + action + ';this.closest(\'.hijri-banner\').remove();">' + btnLabel + '</button>'
      + _laterBtn
      + '</div>';
    sanct.insertBefore(banner, sanct.firstChild);
    window._spontaneousUIShown = true;
  });
}

/* ═══════════════════════════════════════════════════
   MODULE AÏD — 5 événements islamiques majeurs
   Aïd al-Adha, Aïd al-Fitr, Arafat, Lailat al-Qadr, Ashura
   ═══════════════════════════════════════════════════ */

// ── Helper : extraire FR d'un champ string ou {fr,en,ar} ──
function _aidT(val) { return (val && typeof val === 'object') ? (val.fr || val.en || '') : (val || ''); }

// ── Détection de l'événement actif via date Hijri ──
function _aidDetectEvent(hijri) {
  if (!hijri || !window._AID_DATA) return null;
  var m = (hijri.month || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase();
  var d = hijri.day;
  var ev = window._AID_DATA.events;
  var isDH = m.indexOf('hijjah') !== -1 || m.indexOf('hijja') !== -1;
  if (isDH && d === 9) return { key: 'JOUR_ARAFAT', data: ev.JOUR_ARAFAT, dayNum: 1 };
  if (isDH && d >= 10 && d <= 13) return { key: 'AID_AL_ADHA', data: ev.AID_AL_ADHA, dayNum: d - 9 };
  var isSh = m.indexOf('shawwal') !== -1 || m.indexOf('shaww') !== -1;
  if (isSh && d === 1) return { key: 'AID_AL_FITR', data: ev.AID_AL_FITR, dayNum: 1 };
  var isRam = m.indexOf('ramad') !== -1;
  if (isRam && [21,23,25,27,29].indexOf(d) !== -1) return { key: 'LAILAT_AL_QADR', data: ev.LAILAT_AL_QADR, dayNum: 1 };
  var isMuh = m.indexOf('muharram') !== -1;
  if (isMuh && d === 10) return { key: 'ASHURA', data: ev.ASHURA, dayNum: 1 };
  return null;
}

// ── Overlay d'ouverture plein écran (1×/jour) ──
function _aidShowOverlay(evt) {
  var key = 'aid_overlay_' + todayKey();
  if (safeGetItem(key)) return;
  safeSetItem(key, '1');
  var ov = evt.data.overlay_opening;
  if (!ov) return;
  var el = document.createElement('div');
  el.id = 'aid-overlay';
  el.style.cssText = 'position:fixed;inset:0;z-index:99999;background:radial-gradient(ellipse at center,#2a1f0a 0%,#0d0a04 100%);display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;opacity:0;transition:opacity 0.6s;cursor:pointer;padding:40px 24px;';
  el.innerHTML =
    '<div style="font-family:\'Scheherazade New\',Amiri,serif;font-size:44px;color:#C8A84A;margin-bottom:14px;">' + (ov.title_ar || '') + '</div>' +
    '<div style="font-family:\'Cormorant Garamond\',serif;font-size:26px;color:#E5DCC8;font-weight:300;margin-bottom:22px;">' + (ov.title_fr || '') + '</div>' +
    '<div style="font-family:\'Cormorant Garamond\',serif;font-size:15px;color:rgba(200,168,74,0.7);line-height:1.7;max-width:300px;margin-bottom:32px;">' + _aidT(ov.subtitle) + '</div>' +
    '<div style="font-family:Inter,sans-serif;font-size:12px;color:rgba(255,255,255,0.2);letter-spacing:2px;text-transform:uppercase;">' + (_aidT(ov.instruction) || 'Tap pour entrer') + '</div>';
  el.onclick = function() { _aidDismissOverlay(el); };
  document.body.appendChild(el);
  requestAnimationFrame(function() { el.style.opacity = '1'; });
  setTimeout(function() { _aidDismissOverlay(el); }, 4000);
}
function _aidDismissOverlay(el) {
  if (!el || el._gone) return;
  el._gone = true;
  el.style.opacity = '0';
  setTimeout(function() { if (el.parentNode) el.remove(); }, 600);
}

// ── Bandeau permanent cliquable ──
// ── Render helpers ──
function _aidHtml(item) {
  var h = '<div class="aid-story">';
  if (item.titre) h += '<div class="aid-story-titre">' + item.titre + '</div>';
  h += '<div class="aid-story-text">' + (item.texte || '').replace(/\n/g, '<br>') + '</div>';
  if (item.morale) h += '<div class="aid-story-morale">' + item.morale + '</div>';
  return h + '</div>';
}

function _aidBuildTabs(ev) {
  var tabs = [];
  var rc = '';
  if (ev.histoire_ibrahim) rc += _aidHtml(ev.histoire_ibrahim);
  if (ev.sens_du_jeune) rc += _aidHtml(typeof ev.sens_du_jeune === 'string' ? { texte: ev.sens_du_jeune } : ev.sens_du_jeune);
  if (ev.concept) rc += '<div class="aid-story"><div class="aid-story-text">' + (typeof ev.concept === 'string' ? ev.concept : ev.concept.texte || '').replace(/\n/g, '<br>') + '</div></div>';
  if (ev.hajj_jour_par_jour) ev.hajj_jour_par_jour.forEach(function(h) { rc += _aidHtml(h); });
  if (ev.sens_du_qurbani) { rc += '<div class="aid-subtitle">Le sens du Qurb\u00e2ni</div>'; ev.sens_du_qurbani.forEach(function(h) { rc += _aidHtml(h); }); }
  if (ev.bilan_ramadan) { rc += '<div class="aid-subtitle">Bilan Ramadan</div>'; ev.bilan_ramadan.forEach(function(b) { rc += '<div class="aid-question">\u2192 ' + b.question + '</div>'; }); }
  if (ev.zakat_al_fitr) { rc += '<div class="aid-subtitle">Zak\u00e2t al-Fitr</div>'; ev.zakat_al_fitr.forEach(function(z) { rc += _aidHtml(z); }); }
  if (rc) tabs.push({ id: 'recit', label: 'R\u00e9cit', html: rc });
  if (ev.duas && ev.duas.length) {
    var dh = '';
    ev.duas.forEach(function(d) { dh += '<div class="aid-dua">' + (d.occasion ? '<div class="aid-dua-occasion">' + d.occasion + '</div>' : '') + (d.texte_ar ? '<div class="aid-dua-ar">' + d.texte_ar + '</div>' : '') + (d.texte_fr ? '<div class="aid-dua-fr">' + d.texte_fr + '</div>' : '') + (d.source ? '<div class="aid-source">' + d.source + '</div>' : '') + '</div>'; });
    tabs.push({ id: 'duas', label: 'Du\u2019\u00e2s', html: dh });
  }
  if (ev.meditations && ev.meditations.length) {
    var mh = '';
    ev.meditations.forEach(function(m) { mh += '<div class="aid-med">' + (m.texte || '').replace(/\n/g, '<br>') + '</div>'; });
    tabs.push({ id: 'med', label: 'M\u00e9ditations', html: mh });
  }
  var va = ev.versets_cles || (ev.verset_cle ? (Array.isArray(ev.verset_cle) ? ev.verset_cle : [ev.verset_cle]) : []);
  if (va.length) {
    var vh = '';
    va.forEach(function(v) { vh += '<div class="aid-verset"><div class="aid-verset-ref">' + (v.reference || '') + '</div><div class="aid-verset-text">' + (v.texte || '') + '</div>' + (v.commentaire ? '<div class="aid-verset-comment">' + v.commentaire + '</div>' : '') + '</div>'; });
    tabs.push({ id: 'versets', label: 'Versets', html: vh });
  }
  if (ev.takbirat && ev.takbirat.length) {
    var th = '';
    ev.takbirat.forEach(function(t) { th += '<div class="aid-takbir">' + (t.titre ? '<div class="aid-takbir-titre">' + t.titre + '</div>' : '') + (t.texte_ar ? '<div class="aid-takbir-ar">' + t.texte_ar + '</div>' : '') + (t.transliteration ? '<div class="aid-takbir-trans">' + t.transliteration + '</div>' : '') + (t.traduction ? '<div class="aid-takbir-trad">' + t.traduction + '</div>' : '') + '</div>'; });
    tabs.push({ id: 'takbirat', label: 'Takb\u00eer\u00e2t', html: th });
  }
  return tabs;
}

// ── Mode immersif : remplace le sanctuaire entier ──
function _aidTakeoverSanctuaire(evt) {
  var sanct = document.getElementById('view-sanctuaire');
  if (!sanct) return;
  // Already taken over?
  if (document.getElementById('aid-immersive')) return;

  var ev = evt.data;
  var tabs = _aidBuildTabs(ev);
  if (tabs.length === 0) return;

  // Hide all existing sanctuaire children
  Array.from(sanct.children).forEach(function(child) {
    child._aidWasDisplay = child.style.display;
    child.style.display = 'none';
  });

  // Build immersive section
  var wrap = document.createElement('div');
  wrap.id = 'aid-immersive';
  wrap.style.cssText = 'width:100%;min-height:80vh;';

  // Banner text
  var bt = ev.banner_text;
  var bannerText = '';
  if (bt) bannerText = _aidT(bt['day_' + evt.dayNum]) || _aidT(bt['day_1']) || '';
  var fallbacks = { JOUR_ARAFAT: 'Yawm Arafat \u2014 Le plus grand jour du Hajj', LAILAT_AL_QADR: 'Lailat al-Qadr \u2014 La nuit qui vaut mille mois', ASHURA: '\u2018\u00c2sh\u00fbr\u00e2\u2019 \u2014 Je\u00fbne et repentance' };
  if (!bannerText) bannerText = fallbacks[evt.key] || '';

  // Header
  var hdr = '<div style="padding:20px 20px 0;text-align:center;">';
  if (ev.name_ar) hdr += '<div style="font-family:\'Scheherazade New\',Amiri,serif;font-size:36px;color:#C8A84A;margin-bottom:6px;">' + ev.name_ar + '</div>';
  hdr += '<div style="font-family:\'Cormorant Garamond\',serif;font-size:22px;color:#E5DCC8;font-weight:300;margin-bottom:6px;">' + (ev.name_fr || evt.key) + '</div>';
  if (bannerText) hdr += '<div style="font-family:\'Cormorant Garamond\',serif;font-size:13px;color:rgba(200,168,74,0.6);margin-bottom:16px;">' + bannerText + '</div>';
  hdr += '</div>';

  // Tabs bar
  hdr += '<div id="aid-tabs-bar" style="display:flex;gap:6px;overflow-x:auto;padding:0 20px 12px;border-bottom:1px solid rgba(200,168,74,0.15);scrollbar-width:none;">';
  tabs.forEach(function(t, i) {
    var ac = i === 0;
    hdr += '<button class="aid-tab-btn' + (ac ? ' aid-tab-active' : '') + '" data-tab="' + t.id + '" onclick="_aidSwitchTab(\'' + t.id + '\')" style="flex-shrink:0;white-space:nowrap;padding:8px 14px;border-radius:20px;border:1px solid ' + (ac ? 'rgba(200,168,74,0.5)' : 'rgba(200,168,74,0.15)') + ';background:' + (ac ? 'rgba(200,168,74,0.12)' : 'transparent') + ';color:' + (ac ? '#C8A84A' : 'rgba(200,168,74,0.5)') + ';font-family:\'Cormorant Garamond\',serif;font-size:13px;cursor:pointer;">' + t.label + '</button>';
  });
  hdr += '</div>';

  // Tab contents
  var cnt = '';
  tabs.forEach(function(t, i) {
    cnt += '<div id="aid-tab-' + t.id + '" class="aid-tab-content" style="padding:20px;display:' + (i === 0 ? 'block' : 'none') + ';">' + t.html + '</div>';
  });

  // Bouton cartes voeux (Adha + Fitr only)
  var voeuxBtn = '';
  if (evt.key === 'AID_AL_ADHA' || evt.key === 'AID_AL_FITR') {
    voeuxBtn = '<div style="text-align:center;padding:16px 20px 8px;">'
      + '<button onclick="_aidOpenVoeux()" style="background:linear-gradient(135deg,rgba(200,168,74,0.15),rgba(200,168,74,0.05));border:1px solid rgba(200,168,74,0.3);border-radius:14px;padding:12px 24px;color:#C8A84A;font-family:\'Cormorant Garamond\',serif;font-size:15px;cursor:pointer;letter-spacing:0.5px;">\u2726 Envoyer un A\u00efd Moubarak</button>'
      + '</div>';
  }

  wrap.innerHTML = hdr + voeuxBtn + cnt;
  sanct.appendChild(wrap);

  // Hide nav bar + topbar (oeil, burger) via body class
  document.body.classList.add('aid-immersive-mode');
  var nav = document.getElementById('nav-bar-v2');
  if (nav) nav.classList.add('hidden-immersion');
  var topbar = document.getElementById('topbar-v2');
  if (topbar) topbar.classList.add('hidden-immersion');

  // Floating prayer times pill
  _aidShowPrayerPill();
}

function _aidRestoreSanctuaire() {
  var sanct = document.getElementById('view-sanctuaire');
  if (!sanct) return;
  var immersive = document.getElementById('aid-immersive');
  if (immersive) immersive.remove();
  // Restore hidden children
  Array.from(sanct.children).forEach(function(child) {
    if (child._aidWasDisplay !== undefined) {
      child.style.display = child._aidWasDisplay;
      delete child._aidWasDisplay;
    }
  });
  // Restore nav bar + topbar
  document.body.classList.remove('aid-immersive-mode');
  var nav = document.getElementById('nav-bar-v2');
  if (nav) nav.classList.remove('hidden-immersion');
  var topbar = document.getElementById('topbar-v2');
  if (topbar) topbar.classList.remove('hidden-immersion');
  // Remove prayer pill
  var pill = document.getElementById('aid-prayer-pill');
  if (pill) pill.remove();
  // Reveal sanctuaire
  _aidRevealSanctuaire();
}

// ── Floating prayer times pill ──
function _aidShowPrayerPill() {
  if (document.getElementById('aid-prayer-pill')) return;
  if (!_prayerTimes) return;
  var names = ['Fajr','Dhuhr','Asr','Maghrib','Isha'];
  var now = new Date();
  var nowMin = now.getHours() * 60 + now.getMinutes();
  var rows = '';
  names.forEach(function(p) {
    var t = _prayerTimes[p];
    if (!t) return;
    var parts = t.split(':');
    var pMin = parseInt(parts[0],10) * 60 + parseInt(parts[1],10);
    var isNext = false;
    if (!rows._foundNext && pMin > nowMin) { isNext = true; rows._foundNext = true; }
    var style = isNext ? 'color:#C8A84A;font-weight:700;' : 'color:rgba(200,168,74,0.5);';
    rows += '<div style="display:flex;justify-content:space-between;gap:12px;' + style + '"><span>' + p + '</span><span>' + t + '</span></div>';
  });
  var pill = document.createElement('div');
  pill.id = 'aid-prayer-pill';
  pill.style.cssText = 'position:fixed;bottom:16px;right:12px;z-index:9990;background:rgba(26,22,16,0.92);border:1px solid rgba(200,168,74,0.2);border-radius:14px;padding:10px 14px;font-family:Inter,sans-serif;font-size:12px;line-height:1.6;backdrop-filter:blur(8px);-webkit-backdrop-filter:blur(8px);cursor:pointer;transition:transform 0.3s,opacity 0.3s;';
  pill.innerHTML = rows;
  pill._expanded = true;
  pill.onclick = function() {
    pill._expanded = !pill._expanded;
    if (pill._expanded) {
      pill.innerHTML = rows;
      pill.style.padding = '10px 14px';
    } else {
      pill.innerHTML = '<div style="color:rgba(200,168,74,0.6);font-size:12px;">\u2726</div>';
      pill.style.padding = '8px 10px';
    }
  };
  document.body.appendChild(pill);
}

// ── Legacy: _aidOpenSection redirects to takeover ──
function _aidOpenSection(evt) {
  var sanct = document.getElementById('view-sanctuaire');
  if (sanct) {
    // If not on sanctuaire view, navigate there first
    if (typeof v2GoSanctuaire === 'function') v2GoSanctuaire();
  }
  // Remove existing then re-takeover
  _aidRestoreSanctuaire();
  _aidTakeoverSanctuaire(evt || window._AID_ACTIVE);
}

function _aidSwitchTab(tabId) {
  document.querySelectorAll('.aid-tab-content').forEach(function(el) { el.style.display = 'none'; });
  document.querySelectorAll('.aid-tab-btn').forEach(function(btn) {
    var ac = btn.getAttribute('data-tab') === tabId;
    btn.style.border = '1px solid ' + (ac ? 'rgba(200,168,74,0.5)' : 'rgba(200,168,74,0.15)');
    btn.style.background = ac ? 'rgba(200,168,74,0.12)' : 'transparent';
    btn.style.color = ac ? '#C8A84A' : 'rgba(200,168,74,0.5)';
  });
  var tab = document.getElementById('aid-tab-' + tabId);
  if (tab) tab.style.display = 'block';
  var overlay = document.getElementById('aid-section-overlay');
  if (overlay) overlay.scrollTop = 0;
}

// ── Message Waqt spécial (3s intro) ──
function _aidGetWaqtMessage(evt, priere) {
  if (!evt || !evt.data || !evt.data.messages_waqts) return null;
  var key = priere.toUpperCase() + '_jour_' + evt.dayNum;
  var msg = evt.data.messages_waqts[key] || null;
  return msg ? _aidT(msg) : null;
}

// ── CSS du module Aïd ──
function _aidInjectStyles() {
  if (document.getElementById('aid-styles')) return;
  var s = document.createElement('style');
  s.id = 'aid-styles';
  s.textContent =
    'body.aid-immersive-mode #topbar-v2,body.aid-immersive-mode #nav-bar-v2{display:none !important}' +
    '.aid-subtitle{font-family:"Cormorant Garamond",serif;font-size:17px;font-weight:700;color:#C8A84A;margin:24px 0 12px;letter-spacing:.5px}' +
    '.aid-question{font-family:"Cormorant Garamond",serif;font-size:15px;color:rgba(240,234,214,.8);line-height:1.7;margin-bottom:10px;padding-left:8px}' +
    '.aid-story{margin-bottom:28px;padding-bottom:20px;border-bottom:1px solid rgba(200,168,74,.1)}' +
    '.aid-story-titre{font-family:"Cormorant Garamond",serif;font-size:17px;font-weight:700;color:#C8A84A;margin-bottom:10px}' +
    '.aid-story-text{font-family:"Cormorant Garamond",serif;font-size:15px;color:rgba(240,234,214,.85);line-height:1.8}' +
    '.aid-story-morale{font-family:"Cormorant Garamond",serif;font-size:15px;font-weight:700;color:rgba(240,234,214,.95);line-height:1.6;margin-top:14px;padding-top:10px;border-top:1px solid rgba(200,168,74,.12)}' +
    '.aid-dua{margin-bottom:24px;padding-bottom:18px;border-bottom:1px solid rgba(200,168,74,.08)}' +
    '.aid-dua-occasion{font-family:Inter,sans-serif;font-size:12px;color:rgba(200,168,74,.6);letter-spacing:1px;text-transform:uppercase;margin-bottom:8px}' +
    '.aid-dua-ar{font-family:"Scheherazade New",Amiri,serif;font-size:22px;color:#C8A84A;direction:rtl;text-align:right;line-height:1.8;margin-bottom:8px}' +
    '.aid-dua-fr{font-family:"Cormorant Garamond",serif;font-size:15px;font-style:italic;color:rgba(240,234,214,.8);line-height:1.6;margin-bottom:6px}' +
    '.aid-source{font-family:Inter,sans-serif;font-size:12px;color:rgba(200,168,74,.35)}' +
    '.aid-med{font-family:"Cormorant Garamond",serif;font-size:16px;color:rgba(240,234,214,.85);line-height:1.8;margin-bottom:24px;padding-bottom:18px;border-bottom:1px solid rgba(200,168,74,.08)}' +
    '.aid-verset{margin-bottom:24px;padding-bottom:18px;border-bottom:1px solid rgba(200,168,74,.08)}' +
    '.aid-verset-ref{font-family:Inter,sans-serif;font-size:12px;color:rgba(200,168,74,.6);letter-spacing:.5px;margin-bottom:8px}' +
    '.aid-verset-text{font-family:"Cormorant Garamond",serif;font-size:16px;font-style:italic;color:rgba(240,234,214,.9);line-height:1.8;margin-bottom:8px}' +
    '.aid-verset-comment{font-family:"Cormorant Garamond",serif;font-size:14px;color:rgba(200,168,74,.5);line-height:1.6}' +
    '.aid-takbir{margin-bottom:28px;padding-bottom:20px;border-bottom:1px solid rgba(200,168,74,.08)}' +
    '.aid-takbir-titre{font-family:"Cormorant Garamond",serif;font-size:14px;color:rgba(200,168,74,.6);margin-bottom:12px}' +
    '.aid-takbir-ar{font-family:"Scheherazade New",Amiri,serif;font-size:24px;color:#C8A84A;direction:rtl;text-align:right;line-height:1.8;margin-bottom:10px}' +
    '.aid-takbir-trans{font-family:"Cormorant Garamond",serif;font-size:14px;font-style:italic;color:rgba(240,234,214,.6);line-height:1.6;margin-bottom:8px}' +
    '.aid-takbir-trad{font-family:"Cormorant Garamond",serif;font-size:15px;color:rgba(240,234,214,.8);line-height:1.7}';
  document.head.appendChild(s);
}

// ── Boot module Aïd ──
// Sanctuaire hidden by inline <style> in <head>.
// _aidRevealSanctuaire() is the ONLY way to make it visible.
function _aidRevealSanctuaire() {
  var sanct = document.getElementById('view-sanctuaire');
  if (sanct) sanct.style.visibility = 'visible';
}
function _aidBoot() {
  console.log('[Aid] _aidBoot called, onboard:', _onboardDone, 'data:', !!window._AID_DATA);
  setTimeout(function(){ try { _aidRevealSanctuaire(); } catch(e){} }, 3000);
  if (!_onboardDone) { _aidRevealSanctuaire(); return; }
  _aidInjectStyles();
  if (!window._AID_DATA) {
    setTimeout(function() {
      console.log('[Aid] retry, data:', !!window._AID_DATA);
      if (window._AID_DATA) { _aidBootInner(); } else { _aidRevealSanctuaire(); }
    }, 1500);
    return;
  }
  _aidBootInner();
}
function _aidBootInner() {
  getCurrentHijri().then(function(hijri) {
    console.log('[Aid] hijri:', JSON.stringify(hijri));
    var evt = _aidDetectEvent(hijri);

    /* ── Garde-fou Grégorien (sunset/API lag fix) ──
       L'API Aladhan peut retourner le même jour Hijri pour 2 jours
       Grégoriens consécutifs (car le jour islamique change à Maghrib,
       pas à minuit). On déduit la date Grégorienne du jour 1 de
       l'événement via dayNum, et on coupe si on dépasse duration_days. */
    if (evt) {
      var maxDays = (evt.data && evt.data.duration_days) || 1;
      var gKey = 'aid_greg_day1_' + evt.key;
      var today = new Date(todayKey());
      // Déduire le jour Grégorien du 1er jour de l'événement
      var gregDay1Str = safeGetItem(gKey);
      if (!gregDay1Str) {
        // 1re détection : jour 1 = aujourd'hui - (dayNum - 1) jours
        var d1 = new Date(today);
        d1.setDate(d1.getDate() - (evt.dayNum - 1));
        gregDay1Str = d1.getFullYear() + '-' + String(d1.getMonth() + 1).padStart(2, '0') + '-' + String(d1.getDate()).padStart(2, '0');
        safeSetItem(gKey, gregDay1Str);
      }
      var elapsed = Math.round((today - new Date(gregDay1Str)) / 86400000);
      console.log('[Aid] greg guard:', evt.key, 'day1=' + gregDay1Str, 'elapsed=' + elapsed, 'max=' + maxDays);
      if (elapsed >= maxDays) {
        console.log('[Aid] event expired (greg guard) — cutting off');
        try { safeRemoveItem(gKey); } catch(e) {}
        evt = null;
      }
    }

    if (!evt) {
      console.log('[Aid] no active event');
      _aidRevealSanctuaire();
      return;
    }
    window._AID_ACTIVE = evt;
    console.log('[Aid] active:', evt.key, 'day:', evt.dayNum);

    /* ── Adha jour 1 vs jours 2-4 (Tachrîq) ──
       Jour 1 : takeover complet + overlay (comme avant).
       Jours 2-4 : app normale + carte discrète Tachrîq dans le sanctuaire.
       Les messages waqt spéciaux continuent les 4 jours. */
    if (evt.key === 'AID_AL_ADHA' && evt.dayNum >= 2) {
      console.log('[Aid] Tachr\u00eeq mode (jour', evt.dayNum + ') \u2014 carte discr\u00e8te');
      _aidRevealSanctuaire();
      _aidInjectTachriqCard(evt);
    } else {
      _aidTakeoverSanctuaire(evt);
      _aidRevealSanctuaire();
      _aidShowOverlay(evt);
    }
  }).catch(function(e) { console.warn('[Aid] hijri error:', e); _aidRevealSanctuaire(); });
}

/* ═══════════════════════════════════════════════════
   TACHRÎQ — Carte discrète jours 2-4 Aïd al-Adha
   ═══════════════════════════════════════════════════ */
function _aidInjectTachriqCard(evt) {
  var sanct = document.getElementById('view-sanctuaire');
  if (!sanct || document.getElementById('aid-tachriq-card')) return;
  var bt = evt.data.banner_text;
  var bannerText = bt ? (_aidT(bt['day_' + evt.dayNum]) || '') : '';
  var card = document.createElement('div');
  card.id = 'aid-tachriq-card';
  card.onclick = function() { _aidOpenFromCard(evt); };
  card.style.cssText = 'width:100%;box-sizing:border-box;margin:0 auto 12px;padding:28px 20px;border-radius:14px;border:1px solid rgba(200,168,74,0.45);background:url(assets/tachriq-bg.webp) center/cover no-repeat,#1a1610;cursor:pointer;text-align:center;box-shadow:0 0 28px rgba(200,168,74,0.18),0 2px 8px rgba(0,0,0,0.3);overflow:hidden;position:relative;';
  card.innerHTML =
    '<div style="position:absolute;inset:0;background:rgba(15,12,8,0.45);border-radius:14px;"></div>' +
    '<div style="position:relative;z-index:1;">' +
    '<div style="font-family:\'Scheherazade New\',Amiri,serif;font-size:28px;color:#C8A84A;margin-bottom:8px;text-shadow:0 1px 6px rgba(0,0,0,0.5);">\u0639\u064A\u062F \u0645\u0628\u0627\u0631\u0643</div>' +
    '<div style="font-family:\'Cormorant Garamond\',serif;font-size:16px;color:#E5DCC8;font-weight:400;margin-bottom:8px;letter-spacing:0.3px;text-shadow:0 1px 4px rgba(0,0,0,0.4);">' + (bannerText || ('A\u00efd al-Adha \u00b7 Jour ' + evt.dayNum + '/4')) + '</div>' +
    '<div style="font-family:\'Cormorant Garamond\',serif;font-size:12px;color:#C8A84A;letter-spacing:0.4px;">Les takb\u00eer\u00e2t continuent \u00b7 Tap pour ouvrir \u2726</div>' +
    '</div>';
  // Insert inside the centered wrapper, just above .quick-actions-v2
  var quickGrid = sanct.querySelector('.quick-actions-v2');
  if (quickGrid && quickGrid.parentNode) {
    quickGrid.parentNode.insertBefore(card, quickGrid);
  } else {
    sanct.appendChild(card);
  }
}

function _aidOpenFromCard(evt) {
  // Build the full immersive Aid view, then switch to Takbîrât tab
  _aidTakeoverSanctuaire(evt);
  // Inject close button (Tachrîq only — not day 1 full takeover)
  var immersive = document.getElementById('aid-immersive');
  if (immersive && !immersive.querySelector('.aid-close-card')) {
    var btn = document.createElement('button');
    btn.className = 'aid-close-card';
    btn.setAttribute('aria-label', 'Retour');
    btn.style.cssText = 'position:absolute;top:14px;left:16px;z-index:10;background:rgba(200,168,74,0.12);border:1px solid rgba(200,168,74,0.3);border-radius:10px;padding:6px 14px;color:#C8A84A;font-family:\'Cormorant Garamond\',serif;font-size:13px;cursor:pointer;display:flex;align-items:center;gap:6px;';
    btn.innerHTML = '<svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="#C8A84A" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="15 18 9 12 15 6"/></svg>Retour';
    btn.onclick = function() { _aidRestoreSanctuaire(); };
    immersive.style.position = 'relative';
    immersive.insertBefore(btn, immersive.firstChild);
  }
  // Switch to takbirat tab if it exists
  setTimeout(function() {
    if (typeof _aidSwitchTab === 'function') _aidSwitchTab('takbirat');
  }, 100);
}
