function _aidOpenVoeux() {
  var evt = window._AID_ACTIVE;
  var voeux = window._AID_VOEUX;
  if (!evt || !voeux) { showToast('Chargement en cours...'); return; }
  var templates = evt.key === 'AID_AL_FITR' ? voeux.templates_aid_al_fitr : voeux.templates_aid_al_adha;
  if (!templates || !templates.length) return;
  var userPrenom = safeGetItem('niyyah_prenom') || '';

  var ex = document.getElementById('aid-voeux-modal');
  if (ex) ex.remove();

  var modal = document.createElement('div');
  modal.id = 'aid-voeux-modal';
  modal.style.cssText = 'position:fixed;inset:0;z-index:9999;background:#0d0a04;overflow-y:auto;-webkit-overflow-scrolling:touch;';

  // Template options
  var opts = '';
  templates.forEach(function(t, i) { opts += '<option value="' + i + '">' + t.style + '</option>'; });

  modal.innerHTML =
    '<div style="max-width:420px;margin:0 auto;padding:20px;">'
    + '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:20px;">'
    + '<div style="font-family:\'Cormorant Garamond\',serif;font-size:20px;color:#C8A84A;">\u2726 Carte de v\u0153ux</div>'
    + '<button onclick="document.getElementById(\'aid-voeux-modal\').remove()" style="background:none;border:none;color:rgba(255,255,255,0.4);font-size:20px;cursor:pointer;padding:8px;">\u2715</button>'
    + '</div>'
    // Champ destinataire
    + '<div style="margin-bottom:14px;">'
    + '<label style="font-family:Inter,sans-serif;font-size:12px;color:rgba(200,168,74,0.5);letter-spacing:1px;text-transform:uppercase;display:block;margin-bottom:6px;">\u00c0 qui ?</label>'
    + '<input id="aid-voeux-prenom" type="text" maxlength="30" placeholder="Laisse vide pour message g\u00e9n\u00e9ral" style="width:100%;box-sizing:border-box;padding:10px 14px;background:rgba(200,168,74,0.04);border:1px solid rgba(200,168,74,0.2);border-radius:12px;color:#E5DCC8;font-size:14px;font-family:Inter,sans-serif;outline:none;" oninput="_aidVoeuxPreview()">'
    + '</div>'
    // Choix template
    + '<div style="margin-bottom:14px;">'
    + '<label style="font-family:Inter,sans-serif;font-size:12px;color:rgba(200,168,74,0.5);letter-spacing:1px;text-transform:uppercase;display:block;margin-bottom:6px;">Style</label>'
    + '<select id="aid-voeux-style" onchange="_aidVoeuxPreview()" style="width:100%;box-sizing:border-box;padding:10px 14px;background:#1a1610;border:1px solid rgba(200,168,74,0.2);border-radius:12px;color:#E5DCC8;font-size:14px;font-family:Inter,sans-serif;outline:none;">' + opts + '</select>'
    + '</div>'
    // Preview
    + '<div id="aid-voeux-preview" style="position:relative;border-radius:16px;overflow:hidden;margin-bottom:16px;aspect-ratio:9/16;background:#0a0a0a;"><img src="assets/aid_card_bg.webp" style="position:absolute;inset:0;width:100%;height:100%;object-fit:cover;"><div id="aid-voeux-preview-text" style="position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:20px 16px;text-align:center;"></div></div>'
    // Actions
    + '<div style="display:flex;gap:10px;">'
    + '<button onclick="_aidVoeuxGenerate()" style="flex:1;padding:14px;border-radius:14px;border:none;background:linear-gradient(135deg,#c8a84b,#e8cc6a);color:#1a0f00;font-size:14px;font-weight:700;font-family:\'Cormorant Garamond\',serif;cursor:pointer;">G\u00e9n\u00e9rer la carte</button>'
    + '</div>'
    + '</div>';

  document.body.appendChild(modal);
  _aidVoeuxPreview();
}

function _aidVoeuxGetMsg() {
  var evt = window._AID_ACTIVE;
  var voeux = window._AID_VOEUX;
  if (!evt || !voeux) return { msg: '', sig: '' };
  var templates = evt.key === 'AID_AL_FITR' ? voeux.templates_aid_al_fitr : voeux.templates_aid_al_adha;
  var sel = document.getElementById('aid-voeux-style');
  var idx = sel ? parseInt(sel.value, 10) : 0;
  var t = templates[idx] || templates[0];
  var prenom = (document.getElementById('aid-voeux-prenom') || {}).value || '';
  prenom = prenom.trim();
  var msg = prenom ? t.message.replace(/\{prenom\}/g, prenom) : t.message_generique;
  var sig = safeGetItem('niyyah_prenom') || '';
  return { msg: msg, sig: sig };
}

function _aidVoeuxPreview() {
  var el = document.getElementById('aid-voeux-preview-text');
  if (!el) return;
  var d = _aidVoeuxGetMsg();
  var html = '<div style="font-family:\'Scheherazade New\',Amiri,serif;font-size:24px;color:#E8D9A8;margin-bottom:8px;">\u0639\u064a\u062f \u0645\u0628\u0627\u0631\u0643</div>';
  html += '<div style="font-family:\'Cormorant Garamond\',serif;font-size:13px;color:#E8D9A8;line-height:1.7;white-space:pre-line;max-width:90%;">' + d.msg + '</div>';
  if (d.sig) html += '<div style="font-family:\'Cormorant Garamond\',serif;font-style:italic;font-size:12px;color:rgba(232,217,168,0.6);margin-top:10px;">\u2014 ' + d.sig + '</div>';
  el.innerHTML = html;
}

function _aidVoeuxGenerate() {
  var d = _aidVoeuxGetMsg();
  var W = 1080, H = 1920;
  var canvas = document.createElement('canvas');
  canvas.width = W; canvas.height = H;
  var ctx = canvas.getContext('2d');

  // Load background image first
  var bg = new Image();
  bg.onload = function() {
    ctx.drawImage(bg, 0, 0, W, H);
    _aidVoeuxDrawText(ctx, d, W, H);
    _aidVoeuxExport(canvas);
  };
  bg.onerror = function() {
    // Fallback: dark gradient if image fails
    var grad = ctx.createLinearGradient(0, 0, 0, H);
    grad.addColorStop(0, '#0a0a0a'); grad.addColorStop(1, '#1a1410');
    ctx.fillStyle = grad; ctx.fillRect(0, 0, W, H);
    _aidVoeuxDrawText(ctx, d, W, H);
    _aidVoeuxExport(canvas);
  };
  bg.src = 'assets/aid_card_bg.webp';
}

function _aidVoeuxDrawText(ctx, d, W, H) {
  ctx.textAlign = 'center';

  // Arabic title — top of halo zone
  ctx.fillStyle = '#E8D9A8';
  ctx.font = '80px Amiri, Scheherazade New, serif';
  ctx.fillText('\u0639\u064a\u062f \u0645\u0628\u0627\u0631\u0643', W/2, 560);

  // Message — adaptive font size, centered in halo
  var msgLines = [];
  var fontSize = 52;
  ctx.font = fontSize + 'px Cormorant Garamond, Georgia, serif';
  var maxW = W - 200;
  d.msg.split('\n').forEach(function(para) {
    if (para.trim() === '') { msgLines.push(''); return; }
    var words = para.split(' ');
    var line = '';
    words.forEach(function(w) {
      var test = line ? line + ' ' + w : w;
      if (ctx.measureText(test).width > maxW) { msgLines.push(line); line = w; }
      else line = test;
    });
    if (line) msgLines.push(line);
  });

  // Shrink font if too many lines
  if (msgLines.length > 12) { fontSize = 40; }
  else if (msgLines.length > 8) { fontSize = 44; }
  var lineH = Math.round(fontSize * 1.45);
  ctx.font = fontSize + 'px Cormorant Garamond, Georgia, serif';

  // Re-wrap with final font size
  if (fontSize !== 52) {
    msgLines = [];
    ctx.font = fontSize + 'px Cormorant Garamond, Georgia, serif';
    d.msg.split('\n').forEach(function(para) {
      if (para.trim() === '') { msgLines.push(''); return; }
      var words = para.split(' ');
      var line = '';
      words.forEach(function(w) {
        var test = line ? line + ' ' + w : w;
        if (ctx.measureText(test).width > maxW) { msgLines.push(line); line = w; }
        else line = test;
      });
      if (line) msgLines.push(line);
    });
  }

  var totalTextH = msgLines.length * lineH;
  var startY = 660;
  ctx.fillStyle = '#E8D9A8';
  ctx.font = fontSize + 'px Cormorant Garamond, Georgia, serif';
  msgLines.forEach(function(l, i) { ctx.fillText(l, W/2, startY + i * lineH); });

  // Signature — italic, bottom of halo
  if (d.sig) {
    ctx.fillStyle = 'rgba(232,217,168,0.6)';
    ctx.font = 'italic 36px Cormorant Garamond, Georgia, serif';
    ctx.fillText('\u2014 ' + d.sig, W/2, startY + totalTextH + 50);
  }
}

function _aidVoeuxExport(canvas) {
  canvas.toBlob(function(blob) {
    if (!blob) { showToast('Erreur g\u00e9n\u00e9ration'); return; }
    var file = new File([blob], 'aid-moubarak.png', { type: 'image/png' });
    if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
      navigator.share({ files: [file], title: 'A\u00efd Moubarak', text: 'A\u00efd Moubarak' }).catch(function() {});
    } else {
      var a = document.createElement('a');
      a.href = URL.createObjectURL(blob);
      a.download = 'aid-moubarak.png';
      a.click();
      setTimeout(function() { URL.revokeObjectURL(a.href); }, 5000);
    }
    showToast('Carte g\u00e9n\u00e9r\u00e9e \u2726');
  }, 'image/png');
}

