/* ── SIRA MODULE ── */
const SIRA = {
  data: null,
  loading: false,
  async load() {
    if (this.data || this.loading) return this.data;
    this.loading = true;
    try {
      const res = await fetch('./data/sira.min.json');
      this.data = await res.json();
    } catch(e) { console.warn('SIRA load error:', e); }
    this.loading = false;
    return this.data;
  },
  getCurrentRdvNum() {
    var start = safeGetItem('niyyah_sira_start');
    if (!start) {
      start = String(Date.now());
      safeSetItem('niyyah_sira_start', start);
    }
    var daysSince = Math.floor((Date.now() - parseInt(start, 10)) / 86400000);
    var max = (this.data && this.data.rdv) ? this.data.rdv.length : 365;
    return (daysSince % max) + 1;
  },
  getRdv(num) {
    if (!this.data || !this.data.rdv) return null;
    return this.data.rdv.find(function(r) { return r.num === num; }) || null;
  },
  markTissue(num) {
    var arr = [];
    try { arr = JSON.parse(safeGetItem('sira_tissues') || '[]'); } catch(e) {}
    if (arr.indexOf(num) === -1) arr.push(num);
    safeSetItem('sira_tissues', JSON.stringify(arr));
    if (!state['sira']) {
      state['sira'] = true;
      saveState();
    }
  },
  getTissuesCount() {
    try { return JSON.parse(safeGetItem('sira_tissues') || '[]').length; } catch(e) { return 0; }
  },
  isRdvOfDayRead() {
    var num = this.getCurrentRdvNum();
    try { return JSON.parse(safeGetItem('sira_tissues') || '[]').indexOf(num) !== -1; } catch(e) { return false; }
  },
  _ensureOverlay() {
    var ov = document.getElementById('sira-overlay');
    if (!ov) {
      ov = document.createElement('div');
      ov.id = 'sira-overlay';
      ov.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;z-index:9999;background:#2C2E32;color:#FAF7EE;overflow:auto;opacity:0;transition:opacity 400ms ease;';
      document.body.appendChild(ov);
      setTimeout(function() { ov.style.opacity = '1'; }, 10);
    }
    return ov;
  },
  _closeBtn: '<button onclick="document.getElementById(\'sira-overlay\').remove();_restoreScroll();a11yOnOverlayClose();" style="position:fixed;top:16px;right:16px;z-index:10000;background:none;border:none;color:#C8A84A;font-size:32px;width:32px;height:32px;cursor:pointer;line-height:1;">\u2715</button>',
  async openDetail() {
    _saveScroll();
  a11yOnOverlayOpen();
    await this.load();
    var ov = this._ensureOverlay();
    ov.innerHTML = this._closeBtn
      + '<div id="sira-content" style="max-width:720px;margin:0 auto;padding:80px 20px;">' + this.renderHome() + '</div>';
    ov.scrollTop = 0;
  },
  async openNav(num) {
    await this.load();
    this.currentNum = num;
    var ov = this._ensureOverlay();
    var self = this;
    function _inject() {
      ov.innerHTML = self._closeBtn
        + '<div id="sira-content" style="max-width:720px;margin:0 auto;padding:80px 20px;opacity:0;transition:opacity 300ms ease;">' + self.renderRdv(num) + '</div>';
      ov.scrollTop = 0;
      setTimeout(function() {
        var ct = document.getElementById('sira-content'); if (ct) ct.style.opacity = '1';
        var el = document.getElementById('sira-salawat-open'); if (el) { el.style.opacity = '1'; el.style.transform = 'translateY(0)'; }
      }, 30);
      setTimeout(function() {
        var badge = document.getElementById('sira-tissue-badge'); if (badge) { badge.style.opacity = '1'; badge.style.transform = 'translateY(0)'; }
      }, 1200);
    }
    var ct = document.getElementById('sira-content');
    if (ct) {
      ct.style.opacity = '0';
      setTimeout(function() { _inject(); }, 200);
    } else {
      _inject();
    }
  },
  renderList() {
    var max = this.getCurrentRdvNum();
    var tissues = [];
    try { tissues = JSON.parse(safeGetItem('sira_tissues') || '[]'); } catch(e) {}
    var h = '';
    h += '<div onclick="SIRA.openDetail()" style="position:absolute;top:16px;left:16px;font-size:28px;font-weight:300;color:#C8A84A;cursor:pointer;">\u2039</div>';
    h += '<div style="text-align:center;font-family:Cormorant Garamond,serif;font-size:24px;font-style:italic;color:#FAF7EE;margin:20px 0 8px;">Tous les rendez-vous tiss\u00e9s</div>';
    h += '<div style="text-align:center;font-style:italic;color:#999;font-size:13px;margin-bottom:40px;">Tous tes rendez-vous avec lui \uFDFA</div>';
    for (var i = 1; i <= max; i++) {
      var rdv = this.getRdv(i);
      var titre = (rdv && rdv.titre && rdv.titre.fr) ? rdv.titre.fr : '';
      var read = tissues.indexOf(i) !== -1;
      h += '<div onclick="SIRA.openNav(' + i + ')" style="display:flex;justify-content:space-between;align-items:center;padding:22px 24px;border-bottom:1px solid rgba(200,168,74,0.12);cursor:pointer;" onmouseover="this.style.background=\'rgba(200,168,74,0.04)\'" onmouseout="this.style.background=\'none\'">'
        + '<div><div style="font-size:12px;letter-spacing:3px;font-weight:700;color:#C8A84A;margin-bottom:4px;">RENDEZ-VOUS ' + i + '</div>'
        + '<div style="font-family:Cormorant Garamond,serif;font-style:italic;font-size:19px;color:#FAF7EE;">' + titre + '</div></div>'
        + (read ? '<span style="font-size:14px;color:#C8A84A;">\u2713</span>' : '')
        + '</div>';
    }
    return h;
  },
  openList() {
    var ov = this._ensureOverlay();
    var self = this;
    var ct = document.getElementById('sira-content');
    function _inject() {
      ov.innerHTML = self._closeBtn
        + '<div id="sira-content" style="max-width:720px;margin:0 auto;padding:80px 20px;opacity:0;transition:opacity 300ms ease;">' + self.renderList() + '</div>';
      ov.scrollTop = 0;
      setTimeout(function() { var c = document.getElementById('sira-content'); if (c) c.style.opacity = '1'; }, 30);
    }
    if (ct) {
      ct.style.opacity = '0';
      setTimeout(function() { _inject(); }, 200);
    } else {
      _inject();
    }
  },
  openRdv() {
    this.openNav(this.getCurrentRdvNum());
  },
  renderHome() {
    var num = this.getCurrentRdvNum();
    var rdv = this.getRdv(num);
    var tissues = this.getTissuesCount();
    var titre = (rdv && rdv.titre && rdv.titre.fr) ? rdv.titre.fr : ('RDV #' + num);
    var h = '';
    h += '<svg width="22" height="22" viewBox="0 0 22 22" style="position:absolute;top:18px;right:60px;cursor:pointer;opacity:0.85;" onclick="SIRA.openList()" onmouseover="this.style.opacity=1" onmouseout="this.style.opacity=0.85"><line x1="3" y1="6" x2="19" y2="6" stroke="#C8A84A" stroke-width="1.2" stroke-linecap="round"/><line x1="3" y1="11" x2="19" y2="11" stroke="#C8A84A" stroke-width="1.2" stroke-linecap="round"/><line x1="3" y1="16" x2="19" y2="16" stroke="#C8A84A" stroke-width="1.2" stroke-linecap="round"/></svg>';
    h += '<div style="text-align:center;font-size:80px;color:#C8A84A;margin:40px 0 20px;">\uFDFA</div>';
    h += '<div style="text-align:center;font-family:Cormorant Garamond,serif;font-size:32px;font-style:italic;color:#FAF7EE;margin-bottom:0;">Avec le Messager \uFDFA</div>';
    h += '<div style="text-align:center;font-family:Scheherazade New,Amiri,serif;font-size:28px;color:#C8A84A;direction:rtl;margin:12px 0 8px;">\u0627\u0644\u0633\u0651\u0650\u064A\u0631\u064E\u0629\u064F \u0627\u0644\u0646\u0651\u064E\u0628\u064E\u0648\u0650\u064A\u0651\u064E\u0629\u064F</div>';
    if (tissues === 0) {
      h += '<div style="text-align:center;font-style:italic;color:#999;font-size:14px;line-height:1.5;max-width:280px;margin:0 auto 32px;">Aujourd\u2019hui commence ta premi\u00e8re rencontre avec lui \uFDFA</div>';
    } else if (tissues === 1) {
      h += '<div style="text-align:center;font-style:italic;color:#888;font-size:13px;margin-bottom:32px;">1 rendez-vous tiss\u00e9</div>';
    } else {
      h += '<div style="text-align:center;font-style:italic;color:#888;font-size:13px;margin-bottom:32px;">' + tissues + ' rendez-vous tiss\u00e9s</div>';
    }
    h += '<div class="sira-ornament"></div>';
    h += '<div style="text-align:center;font-size:12px;letter-spacing:4px;font-weight:700;color:#C8A84A;margin-bottom:14px;">AUJOURD\u2019HUI</div>';
    h += '<div style="text-align:center;font-family:Cormorant Garamond,serif;font-size:24px;font-style:italic;color:#FAF7EE;margin-bottom:8px;">Rendez-vous ' + num + ' \u2014 ' + titre + '</div>';
    var _partie = (rdv && rdv.partie && this.data && this.data.meta && this.data.meta.parties && this.data.meta.parties[rdv.partie]) ? this.data.meta.parties[rdv.partie] : null;
    var _partieTitre = (_partie && _partie.titre && _partie.titre.fr) ? _partie.titre.fr : '';
    if (rdv && rdv.partie && _partieTitre) h += '<div style="text-align:center;font-style:italic;color:#999;font-size:12px;letter-spacing:1px;margin-bottom:36px;">Partie ' + rdv.partie + ' \u00b7 ' + _partieTitre + '</div>';
    h += '<div style="text-align:center;"><button class="sira-breath" onclick="SIRA.openRdv()" style="background:#C8A84A;color:#2C2E32;padding:14px 28px;border:none;border-radius:24px;font-family:Cormorant Garamond,serif;font-style:italic;font-size:16px;cursor:pointer;">Entrer dans la rencontre</button></div>';
    h += '<div style="margin-top:60px;padding:24px;max-width:480px;margin-left:auto;margin-right:auto;text-align:center;font-style:italic;color:#999;font-size:13px;line-height:1.7;">Un rendez-vous quotidien avec le Messager d\u2019All\u00e2h \uFDFA \u2014 trois cent soixante-cinq rencontres pour le d\u00e9couvrir, l\u2019aimer, marcher avec lui.<br><br>Ces pages sont un r\u00e9cit : la vie du Proph\u00e8te \uFDFA tiss\u00e9e \u00e0 partir des sources classiques \u2014 le Coran, les \u1e62a\u1e25\u00ee\u1e25 d\u2019al-Bukh\u00e2r\u00ee et de Muslim, et les grands livres de S\u00eera. Les dialogues et les sc\u00e8nes y sont reconstitu\u00e9s pour rendre cette vie vivante, non transcrits mot \u00e0 mot. La S\u00eera n\u2019est pas, par nature, enti\u00e8rement sahih : on n\u2019invente rien ici, et tout d\u00e9tail tir\u00e9 d\u2019une tradition plus faible ou d\u00e9battue est signal\u00e9 dans sa source. Pour ce qui touche au licite, \u00e0 l\u2019illicite et au dogme, reviens toujours au hadith authentifi\u00e9 et aux savants.<br><br>Ces r\u00e9cits ne remplacent pas l\u2019\u00e9tude rigoureuse de la S\u00eera \u2014 ils ouvrent la porte de l\u2019amour qui rend l\u2019\u00e9tude d\u00e9sirable.</div>';
    return h;
  },
  renderRdv(num) {
    var rdv = this.getRdv(num);
    if (!rdv) return '<div></div>';
    function T(field) { return (field && field.fr) ? field.fr : ''; }
    function escape(s) { return String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
    var h = '';
    var _siraMax = (this.data && this.data.rdv) ? this.data.rdv.length : 365;
    h += '<div id="sira-salawat-open" style="text-align:center;font-size:64px;color:#C8A84A;margin-bottom:12px;opacity:0;transform:translateY(20px);transition:opacity 800ms ease-out,transform 800ms ease-out;">\uFDFA</div>';
    h += '<div style="text-align:center;font-family:Cormorant Garamond,serif;font-size:28px;font-style:italic;font-weight:400;color:#FAF7EE;margin:16px 0 8px;">' + escape(T(rdv.titre)) + '</div>';
    var _rp = (rdv.partie && this.data && this.data.meta && this.data.meta.parties && this.data.meta.parties[rdv.partie]) ? this.data.meta.parties[rdv.partie] : null;
    var _rpt = (_rp && _rp.titre && _rp.titre.fr) ? _rp.titre.fr : '';
    if (rdv.partie && _rpt) h += '<div style="text-align:center;font-style:italic;color:#999;font-size:12px;letter-spacing:1px;margin-bottom:8px;">Partie ' + rdv.partie + ' \u00b7 ' + _rpt + '</div>';
    h += '<div style="text-align:center;margin-bottom:32px;"><span onclick="SIRA.openList()" style="display:inline-block;cursor:pointer;font-family:Cormorant Garamond,serif;font-size:13px;font-style:italic;color:rgba(200,168,75,0.6);border-bottom:1px solid rgba(200,168,75,0.25);padding-bottom:2px;">Jour ' + num + ' sur ' + _siraMax + ' \u2014 voir les pr\u00e9c\u00e9dents</span></div>';
    if (rdv.quiz_type) {
      // Quiz mode
      h += '<div style="font-family:Cormorant Garamond,serif;font-size:22px;font-style:italic;color:#FAF7EE;line-height:1.7;text-align:center;margin:24px 0 32px;">' + escape(rdv.quiz_question || '') + '</div>';
      if (rdv.quiz_type === 'qcm' && rdv.quiz_options) {
        rdv.quiz_options.forEach(function(opt, i) {
          h += '<button onclick="_siraQuizReveal(this)" style="display:block;width:100%;padding:14px 20px;margin-bottom:10px;border:1px solid rgba(200,168,75,0.3);border-radius:12px;background:rgba(200,168,75,0.05);color:#E8E6DD;font-family:Cormorant Garamond,serif;font-size:16px;text-align:left;cursor:pointer;transition:border-color 0.2s;">' + escape(opt) + '</button>';
        });
      } else {
        h += '<div style="text-align:center;margin:16px 0;"><button onclick="_siraQuizReveal(this)" style="padding:14px 28px;border:1px solid rgba(200,168,75,0.4);border-radius:24px;background:rgba(200,168,75,0.05);color:#C8A84A;font-family:Cormorant Garamond,serif;font-style:italic;font-size:16px;cursor:pointer;">Voir la r\u00e9ponse</button></div>';
      }
      h += '<div id="sira-quiz-reveal" style="opacity:0;max-height:0;overflow:hidden;transition:opacity 300ms ease,max-height 300ms ease;">';
      h += '<div class="sira-ornament"></div>';
      h += '<div style="font-family:Cormorant Garamond,serif;font-size:20px;font-weight:600;color:#C8A84A;text-align:center;margin:24px 0 12px;">' + escape(rdv.quiz_reponse_courte || '') + '</div>';
      h += '<div style="font-family:Georgia,serif;font-size:17px;line-height:1.75;color:#E8E6DD;margin-bottom:24px;">' + escape(rdv.quiz_reponse_developpee || '').replace(/\n/g, '<br>') + '</div>';
      if (rdv.meditation) h += '<div style="background:rgba(250,247,238,0.04);border-radius:12px;padding:20px 24px;margin:32px 8px;font-style:italic;text-align:center;color:#D4C9A0;font-size:17px;line-height:1.6;">' + escape(T(rdv.meditation)) + '</div>';
      if (rdv.source) h += '<div style="text-align:center;font-style:italic;color:#888;font-size:13px;margin:16px 0 32px;">\u2014 ' + escape(T(rdv.source)) + '</div>';
      h += '</div>';
    } else {
      // Classic mode
      if (rdv.paragraphes && Array.isArray(rdv.paragraphes)) {
        rdv.paragraphes.forEach(function(para) {
          var txt = escape(T(para.content));
          if (para.type === 'verset') {
            h += '<blockquote style="background:rgba(250,247,238,0.05);border-left:2px solid #C8A84A;padding:16px 20px;margin:24px 0;font-style:italic;color:#D4C9A0;font-size:17px;text-align:left;"><span style="color:#C8A84A;">\u2726\u00a0\u00a0</span>' + txt + '</blockquote>';
          } else if (para.type === 'italic') {
            h += '<p style="font-family:Georgia,serif;font-size:17px;line-height:1.75;margin-bottom:18px;color:#C8A84A;font-style:italic;text-align:center;margin:24px 16px;">' + txt + '</p>';
          } else {
            h += '<p style="font-family:Georgia,serif;font-size:17px;line-height:1.75;margin-bottom:18px;color:#E8E6DD;">' + txt + '</p>';
          }
        });
      }
      h += '<div class="sira-ornament"></div>';
      if (rdv.meditation) h += '<div style="background:rgba(250,247,238,0.04);border-radius:12px;padding:20px 24px;margin:32px 8px;font-style:italic;text-align:center;color:#D4C9A0;font-size:17px;line-height:1.6;">' + escape(T(rdv.meditation)) + '</div>';
      if (rdv.source) h += '<div style="text-align:center;font-style:italic;color:#888;font-size:13px;margin:16px 0 32px;">\u2014 ' + escape(T(rdv.source)) + '</div>';
    }
    if (rdv.fiabilite) {
      var _fb = {
        authentique: ['\u2726', 'Authentique', '#C8A84A'],
        sira:        ['\u2756', 'S\u00eera', 'rgba(200,168,74,0.75)'],
        tradition:   ['\u25CC', 'Tradition signal\u00e9e', 'rgba(200,168,74,0.55)'],
        contexte:    ['\u00B7', 'Contexte', '#888']
      }[rdv.fiabilite];
      if (_fb) h += '<div style="text-align:center;font-size:11px;letter-spacing:2px;color:' + _fb[2] + ';margin:-18px 0 30px;opacity:0.85;">' + _fb[0] + ' ' + _fb[1] + '</div>';
    }
    var maxNum = this.getCurrentRdvNum();
    var _bs = 'padding:10px 22px;border:1px solid rgba(200,168,74,0.4);border-radius:24px;background:rgba(200,168,74,0.05);color:#C8A84A;font-family:Cormorant Garamond,serif;font-style:italic;font-size:15px;cursor:pointer;transition:all 300ms ease;';
    h += '<div style="display:flex;justify-content:space-between;align-items:center;padding-top:32px;">';
    h += (num > 1) ? '<span style="' + _bs + '" onclick="SIRA.openNav(' + (num - 1) + ')" onmouseover="this.style.background=\'rgba(200,168,74,0.15)\';this.style.borderColor=\'#C8A84A\'" onmouseout="this.style.background=\'rgba(200,168,74,0.05)\';this.style.borderColor=\'rgba(200,168,74,0.4)\'">Pr\u00e9c\u00e9dent</span>' : '<span></span>';
    h += (num < maxNum) ? '<span style="' + _bs + '" onclick="SIRA.openNav(' + (num + 1) + ')" onmouseover="this.style.background=\'rgba(200,168,74,0.15)\';this.style.borderColor=\'#C8A84A\'" onmouseout="this.style.background=\'rgba(200,168,74,0.05)\';this.style.borderColor=\'rgba(200,168,74,0.4)\'">Suivant</span>' : '<span></span>';
    h += '</div>';
    h += '<div id="sira-tissue-badge" class="sira-tissue-mark"><div class="sira-tissue-circle">\u2713</div><div class="sira-tissue-label">Rendez-vous tiss\u00e9</div></div>';
    h += '<div style="text-align:center;font-size:48px;color:#C8A84A;margin:28px 0 12px;">\uFDFA</div>';
    h += '<div style="text-align:center;font-size:12px;letter-spacing:3px;font-weight:700;color:#C8A84A;margin:32px 0 8px;">FIL ROUGE</div>';
    if (rdv.fil_rouge) h += '<div style="text-align:center;font-style:italic;color:#999;font-size:14px;line-height:1.5;margin-bottom:24px;">' + escape(T(rdv.fil_rouge)) + '</div>';
    h += '<div style="text-align:center;margin:32px 0;"><button onclick="validerLectureSira()" style="padding:14px 28px;border:none;border-radius:24px;background:#C8A84A;color:#2C2E32;font-family:Cormorant Garamond,serif;font-size:15px;font-weight:700;cursor:pointer;">J\u2019ai termin\u00e9 ma lecture</button></div>';
    this.markTissue(num);
    return h;
  }
};
window.SIRA = SIRA;
function _siraQuizReveal(btn) {
  var el = document.getElementById('sira-quiz-reveal');
  if (!el || el.style.opacity === '1') return;
  el.style.maxHeight = '2000px';
  el.style.opacity = '1';
  btn.style.borderColor = '#C8A84A';
  btn.style.background = 'rgba(200,168,75,0.15)';
}
window._siraQuizReveal = _siraQuizReveal;

/* ── DHIKR COUNTER ── */
var _dhikrState = { count: 0, config: null, touchStartY: 0, prayer: null };
function openDhikrCounter(config) {
  var ov = document.getElementById('dhikr-counter-overlay');
  if (!ov) return;
  _dhikrState.config = config;
  // Restore today's count
  var saved = 0;
  try {
    var raw = safeParseJSON(config.saveKey, {});
    if (raw.date === todayKey()) saved = raw.count || 0;
  } catch(e) {}
  _dhikrState.count = Math.min(saved, config.target);
  _dhikrBuildDOM();
  _dhikrUpdate();
  ov.style.display = 'flex';
  // Tap anywhere = +1
  ov.onclick = function(e) {
    if (e.target.closest('.dhikr-close')) return;
    _dhikrIncrement();
  };
  // Swipe down to close
  ov.ontouchstart = function(e) { _dhikrState.touchStartY = e.touches[0].clientY; };
  ov.ontouchend = function(e) {
    var dy = e.changedTouches[0].clientY - _dhikrState.touchStartY;
    if (dy > 120) closeDhikrCounter();
  };
}
function closeDhikrCounter() {
  var ov = document.getElementById('dhikr-counter-overlay');
  if (ov) ov.style.display = 'none';
  var vr = document.getElementById('vue-rituel');
  if (vr && !vr.classList.contains('hidden') && _dhikrState.prayer) {
    openVueRituel(_dhikrState.prayer);
  }
}
function _dhikrGetPhase() {
  var c = _dhikrState.config;
  if (!c || !c.phases) return c ? { arabic: '', translit: '', fr: '', color: '#C8A84A' } : null;
  for (var i = c.phases.length - 1; i >= 0; i--) {
    if (_dhikrState.count >= c.phases[i].from) return c.phases[i];
  }
  return c.phases[0];
}
function _dhikrIncrement() {
  var c = _dhikrState.config;
  if (!c) return;
  if (_dhikrState.count >= 100) return;
  var prevPhase = _dhikrGetPhase();
  var wasComplete = _dhikrState.count >= c.target;
  _dhikrState.count++;
  // Save
  safeSetItem(c.saveKey, JSON.stringify({ date: todayKey(), count: _dhikrState.count }));
  if (c.id && typeof state !== 'undefined' && typeof saveState === 'function') {
    state[c.id] = _dhikrState.count;
    saveState();
  }
  // Haptic
  if (navigator.vibrate) navigator.vibrate(8);
  // Phase transition sound (only if phase actually changed and multiple phases exist)
  var newPhase = _dhikrGetPhase();
  if (c.phases && c.phases.length > 1 && prevPhase !== newPhase && typeof playCheckSound === 'function') playCheckSound();
  // Complete (only once)
  if (!wasComplete && _dhikrState.count >= c.target) {
    if (navigator.vibrate) navigator.vibrate([30, 50, 100]);
    if (typeof playCheckSound === 'function') playCheckSound();
    if (c.onComplete) c.onComplete();
  }
  _dhikrUpdate();
}
function _dhikrBuildDOM() {
  var ov = document.getElementById('dhikr-counter-overlay');
  if (!ov) return;
  var r = 130;
  var circ = 2 * Math.PI * r;
  ov.innerHTML = '<button style="position:absolute;top:16px;left:16px;background:none;border:none;color:#C8A84A;font-size:24px;cursor:pointer;z-index:2;" onclick="event.stopPropagation();_dhikrReset();">\u21BB</button>'
    + '<button class="dhikr-close" onclick="event.stopPropagation();closeDhikrCounter();">\u2715</button>'
    + '<div class="dhikr-info">'
    + '<div class="arabic" id="dhikr-arabic"></div>'
    + '<div class="translit" id="dhikr-translit"></div>'
    + '<div class="trad" id="dhikr-trad"></div>'
    + '</div>'
    + '<div class="dhikr-ring">'
    + '<svg viewBox="0 0 280 280"><circle class="track" cx="140" cy="140" r="' + r + '"/><circle class="progress" id="dhikr-progress" cx="140" cy="140" r="' + r + '" stroke-dasharray="' + circ + '" stroke-dashoffset="' + circ + '"/></svg>'
    + '<div class="dhikr-count" id="dhikr-num">0</div>'
    + '</div>'
    + '<button class="dhikr-btn" onclick="event.stopPropagation();_dhikrIncrement();">+</button>'
    + '<div class="dhikr-phase" id="dhikr-phase-label"></div>';
}
function _dhikrUpdate() {
  var c = _dhikrState.config;
  if (!c) return;
  var count = _dhikrState.count;
  var phase = _dhikrGetPhase();
  var localCount = phase ? count - phase.from : count;
  var localTarget = phase ? phase.to - phase.from : c.target;
  var pct = Math.min(count / c.target, 1);
  var r = 130;
  var circ = 2 * Math.PI * r;
  var offset = circ * (1 - pct);
  var color = (phase && phase.color) ? phase.color : '#C8A84A';
  var done = count >= c.target;
  var prog = document.getElementById('dhikr-progress');
  var ring = prog ? prog.closest('.dhikr-ring') : null;
  if (prog) prog.style.strokeDashoffset = offset;
  if (ring) { ring.style.setProperty('--ring-color', color); ring.style.setProperty('--num-color', color); }
  var num = document.getElementById('dhikr-num');
  if (num) num.textContent = localCount;
  var arEl = document.getElementById('dhikr-arabic');
  if (arEl) arEl.textContent = (phase && phase.arabic) ? phase.arabic : '';
  var trEl = document.getElementById('dhikr-translit');
  if (trEl) trEl.textContent = (phase && phase.translit) ? phase.translit : '';
  var frEl = document.getElementById('dhikr-trad');
  if (frEl) frEl.textContent = (phase && phase.fr) ? phase.fr : '';
  var label = document.getElementById('dhikr-phase-label');
  if (label) {
    if (done) { var doneLabel = phase && phase.fr ? phase.fr : 'Tasbih accompli'; label.textContent = '\u2713 ' + doneLabel; label.style.color = phase && phase.color ? phase.color : '#C8A84A'; }
    else { label.textContent = (phase ? phase.fr || '' : '') + ' \u2014 ' + localCount + '/' + localTarget; label.style.color = ''; }
  }
}
function openTasbihModal(prayer) {
  var _p = prayer || (typeof getCurrentPrayerBlock === 'function' ? getCurrentPrayerBlock().id : 'unknown');
  _dhikrState.prayer = _p;
  openDhikrCounter({
    id: 'tasbih',
    target: 100,
    saveKey: 'tasbih_' + todayKey() + '_' + _p,
    phases: [
      { from: 0, to: 33, arabic: '\u0633\u064F\u0628\u0652\u062D\u064E\u0627\u0646\u064E \u0671\u0644\u0644\u0651\u064E\u0670\u0647', translit: 'Sub\u1E25\u0101na Ll\u0101h', fr: 'Gloire \u00e0 Allah', color: '#6B4F1D' },
      { from: 33, to: 66, arabic: '\u0671\u0644\u0652\u062D\u064E\u0645\u0652\u062F\u064F \u0644\u0650\u0644\u0651\u064E\u0670\u0647', translit: 'Al-\u1E25amdu li-Ll\u0101h', fr: 'Louange \u00e0 Allah', color: '#C8A84A' },
      { from: 66, to: 99, arabic: '\u0671\u0644\u0644\u0651\u064E\u0670\u0647\u064F \u0623\u064E\u0643\u0652\u0628\u064E\u0631', translit: 'All\u0101hu Akbar', fr: 'Allah est le plus Grand', color: '#73834A' },
      { from: 99, to: 100, arabic: '\u0644\u0627 \u0625\u0650\u0644\u064E\u0670\u0647\u064E \u0625\u0650\u0644\u0651\u064E\u0627 \u0671\u0644\u0644\u0651\u064E\u0647\u064F \u0648\u064E\u062D\u0652\u062F\u064E\u0647\u064F \u0644\u0627 \u0634\u064E\u0631\u0650\u064A\u0643\u064E \u0644\u064E\u0647\u064F', translit: 'L\u0101 il\u0101ha illa Ll\u0101hu wa\u1E25dahu l\u0101 shar\u012Bka lah', fr: 'Pas de divinit\u00e9 en dehors d\u2019Allah, Unique, sans associ\u00e9', color: '#1F5F4A' }
    ],
    onComplete: function() {
      showToast('\u2713 Tasbih accompli \u2014 Alhamdulillah');
    }
  });
}
function openIstighfarModal() {
  _dhikrState.prayer = typeof getCurrentPrayerBlock === 'function' ? getCurrentPrayerBlock().id : null;
  openDhikrCounter({
    id: 'istighfar',
    target: 100,
    saveKey: 'istighfar_' + todayKey(),
    phases: [
      { from: 0, to: 100, arabic: '\u0623\u064E\u0633\u0652\u062A\u064E\u063A\u0652\u0641\u0650\u0631\u064F \u0671\u0644\u0644\u0651\u064E\u0670\u0647', translit: 'Astaghfirull\u0101h', fr: 'Je demande pardon \u00e0 Allah', color: '#C8A84A' }
    ],
    onComplete: function() {
      showToast('\u2713 Istighfar accompli \u2014 Alhamdulillah');
    }
  });
}
window.openIstighfarModal = openIstighfarModal;
window.openTasbihModal = openTasbihModal;
function _dhikrReset() {
  if (!confirm('R\u00e9initialiser le compteur ?')) return;
  var c = _dhikrState.config;
  _dhikrState.count = 0;
  if (c) safeSetItem(c.saveKey, JSON.stringify({ date: todayKey(), count: 0 }));
  _dhikrUpdate();
}
window._dhikrReset = _dhikrReset;
window.openDhikrCounter = openDhikrCounter;
window.closeDhikrCounter = closeDhikrCounter;

init();

